(* ========================================================================= *)
(* SHA-256 block compression, scalar (no SHA-NI and SIMD) x86 version.       *)
(*                                                                           *)
(* It computes the FIPS 180-4 SHA-256 compression function over num_blocks   *)
(* 64-byte big-endian message blocks, updating the 8-word state in place:    *)
(*                                                                           *)
(* extern void sha256_compress                                               *)
(*   (uint32_t state[static 8], const uint8_t *data, size_t num_blocks);     *)
(*                                                                           *)
(* SysV: RDI = state, RSI = data, RDX = num_blocks (must be nonzero).        *)
(*                                                                           *)
(* The K256 round-constant table lives in .rodata and is addressed           *)
(* RIP-relatively (leaq K256(%rip),%rbp), so the code is frozen with         *)
(* define_assert_relocs_from_elf. K256 holds the 64 round constants with     *)
(* each 16-byte row doubled (512 bytes), followed by three further doubled   *)
(* 16-byte rows; the top byte of the word at +512 is 0x00, which is the      *)
(* sentinel that terminates the 16-round inner loop (cmpb $0,3(%rbp)) after  *)
(* exactly 3 iterations (the bytes at +259 and +387 are 0x27 and 0x19).      *)
(* ========================================================================= *)

needs "x86/proofs/base.ml";;
needs "x86/proofs/consttime.ml";;
needs "x86/proofs/utils/sha256_spec.ml";;
needs "x86/proofs/utils/sha256_bridge.ml";;

(* ------------------------------------------------------------------------- *)
(* The machine code, with the K256 table relocation abstracted.              *)
(*                                                                           *)
(* (K256 is a local symbol, so the relocation in .rela.text is against the   *)
(* .rodata section symbol; since K256 is the whole .rodata section, we name  *)
(* the WHOLE_READONLY blob "K256" and the redundant per-symbol copy          *)
(* "unused_K256", mirroring the x86/tutorial/rodata_local.S example.)        *)
(* ------------------------------------------------------------------------- *)

let sha256_compress_mc,rodata_constants_data =
  define_assert_relocs_from_elf
    ~map_symbol_name:(function "WHOLE_READONLY" -> "K256"
                             | s -> "unused_" ^ s)
    "sha256_compress_mc"
    "x86/sha256/sha256_compress.o"
(fun b ADDR -> [b[
  0xf3; 0x0f; 0x1e; 0xfa;  (* ENDBR64 *)
