(* The byte-list definition of the K256 table: |- K256 = [...] (608 bytes). *)

let K256_DATA =
  List.find (fun th -> name_of(lhs(concl th)) = "K256") rodata_constants_data;;

let sha256_compress_tmc =
  define_trimmed "sha256_compress_tmc"
                 sha256_compress_mc;;

(* X86_MK_EXEC_RULE rather than X86_MK_CORE_EXEC_RULE: the CORE variant's
   BUTLAST step (X86_TRIM_EXEC_RULE) fails (AP_TERM) on an mc theorem that is
   quantified over pc and rodata symbols, and the in-repo reloc precedent
   (curve25519_x25519base.ml) likewise uses X86_MK_EXEC_RULE on the tmc. *)

let SHA256_COMPRESS_EXEC =
  X86_MK_EXEC_RULE sha256_compress_tmc;;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 2 - sentinel-byte concretization.                            *)
(*                                                                           *)
(* The inner 16-round loop is terminated by "cmpb $0,3(%rbp); jne", which    *)
(* tests one rodata byte per iteration.  RBP marches MONOTONICALLY up the    *)
(* doubled K256 table (+128 bytes/iteration), so iteration i (i=0,1,2) tests *)
(* the byte at K256 + 259 + 128*i, i.e. K256+259, K256+387, K256+515.  These *)
(* are 0x27, 0x19, 0x00 in the frozen blob (binary-verified): nonzero for    *)
(* i=0,1 (jne taken -> continue) and zero for i=2 (jne not taken -> exit),   *)
(* which is exactly the "3 iterations" trip count.                           *)
(*                                                                           *)
(* To resolve the jne in the loop proof we must read these three concrete    *)
(* bytes out of the K256 rodata.  The two helper tactics below are lifted    *)
(* verbatim from x86/tutorial/rodata.ml (they are defined there, not in      *)
(* base.ml; the conversions they call - READ_MEMORY_BYTESIZED_SPLIT,         *)
(* WORD_ADD_ASSOC_CONSTS, BYTELIST_EXPAND_CONV - do live in base.ml's        *)
(* closure).  EXPLODE_BYTELIST_ASSUM_TAC turns the whole-rodata bytelist     *)
(* assumption  read (memory :> bytelist (word base, LENGTH K256)) s = K256   *)
(* into 608 per-byte  read (memory :> bytes8 ...) s = <byte>  assumptions,   *)
(* from which the three sentinel bytes follow by ASM_REWRITE_TAC.            *)
(* ------------------------------------------------------------------------- *)

let INTRO_READ_MEMORY_FROM_BYTES8_TAC (t:term) =
  let r = REWRITE_CONV [READ_MEMORY_BYTESIZED_SPLIT] t in
  let r = REWRITE_RULE[WORD_ADD_ASSOC_CONSTS;WORD_ADD_0;ARITH] r in
  MP_TAC r THEN
  ASM (GEN_REWRITE_TAC (LAND_CONV o ONCE_DEPTH_CONV)) [] THEN
  CONV_TAC (LAND_CONV WORD_REDUCE_CONV) THEN
  DISCH_TAC;;

let EXPLODE_BYTELIST_ASSUM_TAC const_data =
  FIRST_X_ASSUM (fun th ->
    let _ = find_term (fun t -> name_of t = "bytelist") (concl th) in
    let unfolded_bytes_loaded = REWRITE_RULE const_data th in
    MP_TAC (CONV_RULE (ONCE_DEPTH_CONV LENGTH_CONV THENC
                      LAND_CONV BYTELIST_EXPAND_CONV)
            unfolded_bytes_loaded)) THEN
  REWRITE_TAC [CONS_11] THEN
  STRIP_TAC;;

(* The three loop-sentinel bytes, read from the whole-rodata bytelist fact.
   0x27 and 0x19 are nonzero (iterations 0,1 continue); 0x00 (iteration 2)
   terminates the loop.  This drives the inner-loop "jne" both ways. *)

let SHA256_SENTINEL_BYTES = prove
 (`!base:num s.
     read (memory :> bytelist (word base, LENGTH K256)) s = K256
     ==> read (memory :> bytes8 (word_add (word base) (word 259))) s = word 0x27 /\
         read (memory :> bytes8 (word_add (word base) (word 387))) s = word 0x19 /\
         read (memory :> bytes8 (word_add (word base) (word 515))) s = word 0x00`,
  REPEAT GEN_TAC THEN DISCH_TAC THEN
  EXPLODE_BYTELIST_ASSUM_TAC [K256_DATA] THEN
  REPEAT CONJ_TAC THEN ASM_REWRITE_TAC[]);;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - the per-round K-constant reads.                          *)
(*                                                                           *)
(* From the whole-rodata bytelist precondition, read each of the 64 SHA-256  *)
(* round constants out of the DOUBLED K256 table as a 4-byte little-endian   *)
(* bytes32, and equate it to  EL t sha256_constants.  The doubled-row layout *)
(* places constant t at byte offset                                          *)
(*    kofs t = 128*(t DIV 16) + 32*((t MOD 16) DIV 4) + 4*(t MOD 4)          *)
(* (binary-verified for all 64; the same formula whose +3 byte gives the     *)
(* three loop sentinels 259/387/515 = kofs 32/.. + 3).  This is the K-read   *)
(* obligation that every inner-loop sub-round needs (each rounds_16_xx pass   *)
(* reads k16..k30 at kbase_i + {0,4,8,12,32,36,40,44,64,68,72,76,96,100,104}, *)
(* i.e. kofs(16+j) - kofs 16 for the relevant j), and that the abstract-m     *)
(* inner-loop restatement (Phase 8 / Phase 9) folds the round constants with. *)
(* Same machinery as SHA256_SENTINEL_BYTES: explode the bytelist to per-byte  *)
(* reads, reduce EL t sha256_constants to its literal, then assemble each     *)
(* bytes32 from the 4 component bytes (INTRO_READ_MEMORY_FROM_BYTES8_TAC).    *)
(* Built PROGRAMMATICALLY (the 64-conjunct statement is generated, not typed).*)
(* ------------------------------------------------------------------------- *)

let SHA256_K256_READS =
  let kofs t = 128*(t/16) + 32*((t mod 16)/4) + 4*(t mod 4) in
  let one t =
    Printf.sprintf
      "read (memory :> bytes32 (word_add (word base) (word %d))) s = EL %d sha256_constants"
      (kofs t) t in
  let body = String.concat " /\\ " (map one (0--63)) in
  let goal = parse_term (Printf.sprintf
    "!base:num s:x86state. \
       read (memory :> bytelist (word base, LENGTH K256)) s = K256 \
       ==> %s" body) in
  prove
   (goal,
    REPEAT GEN_TAC THEN DISCH_TAC THEN
    EXPLODE_BYTELIST_ASSUM_TAC [K256_DATA] THEN
    REWRITE_TAC[sha256_constants] THEN
    CONV_TAC(ONCE_DEPTH_CONV EL_CONV) THEN
    REWRITE_TAC[WORD_ADD_0] THEN
    REPEAT CONJ_TAC THEN
    (fun (asl,w) -> INTRO_READ_MEMORY_FROM_BYTES8_TAC (lhs w) (asl,w)) THEN
    ASM_REWRITE_TAC[]);;

(* ------------------------------------------------------------------------- *)
(* Phases 4-5 - one compression round with the W[i] memory path.             *)
(*                                                                           *)
(* We prove that ONE round-0-style head round of the frozen code computes    *)
(* sha256_round on the working-variable registers (Phase 4, register-only)   *)
(* AND establishes the W-ring memory path (Phase 5): the big-endian load     *)
(* "mov (%rsi),%r12d ; bswap %r12d" (pc+89/+102, producing                   *)
(* word_bytereverse wraw from the raw little-endian dword wraw at (%rsi))     *)
(* and its store "mov %r12d,(%rsp)" (pc+122) into the W-ring slot at          *)
(* stackptr+0.  These three instructions already sit inside the stepped      *)
(* pc+87..pc+194 range, so Phase 5 only had to STRENGTHEN the postcondition   *)
(* with the store fact  read (memory :> bytes32 stackptr) s =                 *)
(* word_bytereverse wraw  (the h-fold "add %r11d,%r12d" at pc+136 is AFTER    *)
(* the store, so the stored value is the clean message word); the existing    *)
(* closer discharges it unchanged.  The K256 base walk and the b^c Maj-carry  *)
(* init remain Phase-6 concerns.                                             *)
(*                                                                           *)
(* Entry/exit (verified against objdump + the EXEC decode array):            *)
(*  - The round-0 body runs from orig 0x52 (tmc-relative pc+78), the loop    *)
(*    top "mov %ebx,%edi", to orig 0xc6 (pc+194), the round-1 W-load.        *)
(*  - We ENTER at pc+87 (orig 0x5b, "xor %ecx,%edi"), i.e. just AFTER the    *)
(*    "mov %ebx,%edi" (edi := b) and the RIP-relative "lea K256(%rip),%rbp"  *)
(*    (whose post-state RBP carries messy reloc arithmetic                   *)
(*    word(val(word(pc+87)) + val(word_sx(iword(&K256 - (&pc+87))))) that is *)
(*    a Phase-6 concern).  So the precondition supplies RBP = kbase (the     *)
(*    abstract K-table cursor) and RDI = word_zx b directly; the round       *)
(*    constant k is read symbolically from (memory :> bytes32 kbase),        *)
(*    matching sha256_round's k parameter.                                   *)
(*  - 33 instructions, pc+87 .. pc+194.                                      *)
(*                                                                           *)
(* IMPORTANT (corrects the planner's Phase-4 hint): this Ragamuffin code     *)
(* does NOT defer the Sigma0/T2 add.  The instruction "add %r14d,%r11d"      *)
(* (Sigma0 fold completing new-a) at orig 0xc3 = pc+191 is the LAST          *)
(* instruction of round 0, before round 1's W-load at pc+194.  Each round    *)
(* fully computes its 8 outputs in place; the idiom here is                  *)
(* register-ROLE ROTATION, not deferred adds.  So the round lemma maps to    *)
(* sha256_round with NO one-round offset and Phase-6 seams are clean.        *)
(*                                                                           *)
(* Output register -> sha256_round element map (all int32, via word_zx):     *)
(*   R11=EL 0 (new a),  RAX=EL 1 (=a),   RBX=EL 2 (=b),   RCX=EL 3 (=c),     *)
(*   RDX=EL 4 (new e),  R8 =EL 5 (=e),   R9 =EL 6 (=f),   R10=EL 7 (=g).     *)
(* The round's message word is word_bytereverse wraw (the big-endian         *)
(* assembly of the little-endian dword wraw at (%rsi); note word_bswap does  *)
(* NOT exist in the library - the stepper emits word_bytereverse).           *)
(*                                                                           *)
(* Postcondition closer (session 003).  X86_STEPS_TAC wraps every 32-bit      *)
(* operation in a width-changing word_zx (int32<->int64, the x86 zerotop_32   *)
(* operand model), so the raw final-state register terms are deep nests of    *)
(* word_zx around word_add/word_ror/word_xor/word_and.  Two facts make the    *)
(* match tractable and fast:                                                  *)
(*   1. Collapse the word_zx round-trips FIRST, with width-specialized        *)
(*      UNCONDITIONAL rewrites (WORD_ZX_ZX instantiated to int32/int64, plus  *)
(*      the same-width WORD_ZX_TRIVIAL).  Doing this as a plain one-pass       *)
(*      REWRITE_TAC is instant; leaving WORD_ZX_ZX conditional (SIMP_TAC) or  *)
(*      reaching for WORD_BLAST/bare WORD_RULE on the uncollapsed term does   *)
(*      NOT terminate in reasonable time (the word_add ripple-carry blows up).*)
(*   2. After collapse, the four big-Sigma/Choose/Maj bridges from            *)
(*      sha256_bridge.ml match the hardware chains exactly, reducing each     *)
(*      register to  word_zx (small word_add tree over the spec atoms         *)
(*      sha_hash_sigma_0/1, sha_choose, sha_maj, k, word_bytereverse wraw).   *)
(*      The spec side (sha256_round unfolded) is the SAME atoms in a          *)
(*      different word_add association, so AP_TERM_TAC (strip the common      *)
(*      outer word_zx) THEN WORD_RULE (AC over word_add) closes each in a     *)
(*      few ms.  Whole lemma: ~4 s.                                           *)
(* ------------------------------------------------------------------------- *)

(* Width-specialised, unconditional word_zx round-trip collapses. *)
let SHA256_WORD_ZX_3264 = prove
 (`!x:int32. (word_zx:int64->int32)((word_zx:int32->int64) x) = x`,
  SIMP_TAC[WORD_ZX_ZX; DIMINDEX_32; DIMINDEX_64; ARITH]);;

let SHA256_WORD_ZX_3232 = prove
 (`!x:int32. (word_zx:int32->int32) x = x`,
  REWRITE_TAC[WORD_ZX_TRIVIAL]);;

let SHA256_WORD_ZX_6464 = prove
 (`!x:int64. (word_zx:int64->int64) x = x`,
  REWRITE_TAC[WORD_ZX_TRIVIAL]);;

let SHA256_BLOCK_NOHW_ROUND0 = prove
 (`!pc K256 kbase stackptr dataptr a b c d e f g h wraw k.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kbase:int64,4)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc K256) /\
            read RIP s = word (pc + 87) /\
            read RBP s = kbase /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RDI s = word_zx (b:int32) /\
            read (memory :> bytes32 dataptr) s = wraw /\
            read (memory :> bytes32 kbase) s = (k:int32) /\
            read RAX s = word_zx (a:int32) /\
            read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\
            read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\
            read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\
            read R11 s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 194) /\
            read R11 s = word_zx (EL 0 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RAX s = word_zx (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RBX s = word_zx (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RCX s = word_zx (EL 3 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RDX s = word_zx (EL 4 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read R8 s  = word_zx (EL 5 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read R9 s  = word_zx (EL 6 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read R10 s = word_zx (EL 7 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read (memory :> bytes32 stackptr) s = word_bytereverse wraw)
       (MAYCHANGE [RIP;RDI;RBP;RDX;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 stackptr] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--33) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  (* collapse the int32<->int64 word_zx round-trips (fast one-pass) *)
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  (* refold the hardware rotate/xor/and chains to the spec primitives *)
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE] THEN
  (* unfold one spec round and match each working variable up to word_add AC *)
  REWRITE_TAC[sha256_round] THEN
  CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 6 - the second head round (odd parity), standalone.                 *)
(*                                                                           *)
(* This validates the two cross-round threads that ROUND0 could not exhibit  *)
(* (it is the FIRST round, so it seeds the carries fresh):                   *)
(*                                                                           *)
(*  - REGISTER ROLE ROTATION (period 8).  With the canonical register file   *)
(*    C = [RAX;RBX;RCX;RDX;R8;R9;R10;R11] = (a,b,c,d,e,f,g,h) at round 0,    *)
(*    working-variable role j at round t lives in C[(j - t) MOD 8].  So at    *)
(*    round 1 the inputs are a->R11, b->RAX, c->RBX, d->RCX, e->RDX, f->R8,   *)
(*    g->R9, h->R10, and the outputs rotate one place further (EL 0 -> R10).  *)
(*                                                                           *)
(*  - MAJ CARRIED-XOR (period 2).  The scalar code carries the value         *)
(*    b^c into each round's Maj (since b_{t+1}=a_t, c_{t+1}=b_t, we have      *)
(*    b_{t+1}^c_{t+1} = a_t^b_t, computed at the END of round t).  The carry  *)
(*    register alternates: round 0 leaves a0^b0 in R15, which round 1        *)
(*    consumes; round 1 leaves a1^b1 in EDI, which round 2 consumes.  Hence   *)
(*    round 1's precondition supplies R15 = word_zx(word_xor b c) (its own    *)
(*    b^c, = the previous round's a^b) and its postcondition exposes          *)
(*    RDI = word_zx(word_xor a b).                                           *)
(*                                                                           *)
(* Entry pc+194 (orig 0xc6, round-1 W-load), exit pc+299 (orig 0x12f,         *)
(* round-2 W-load); 32 instructions.  W read from (dataptr+4), stored to      *)
(* (stackptr+4), round constant k from kbase.  The Phase-4 closer discharges  *)
(* it unchanged, confirming the closer is parity-independent.  Together with  *)
(* ROUND0 this shows every head round is uniform up to the register          *)
(* permutation and the carry-register swap, so the 16-round head section can  *)
(* be composed by cut-points (one spec-atom refold per round boundary).      *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_ROUND1 = prove
 (`!pc K256 kbase stackptr dataptr a b c d e f g h wraw k.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kbase:int64,4)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc K256) /\
            read RIP s = word (pc + 194) /\
            read RBP s = kbase /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read R15 s = word_zx (word_xor (b:int32) (c:int32)) /\
            read (memory :> bytes32 (word_add dataptr (word 4))) s = wraw /\
            read (memory :> bytes32 kbase) s = (k:int32) /\
            read R11 s = word_zx (a:int32) /\
            read RAX s = word_zx (b:int32) /\
            read RBX s = word_zx (c:int32) /\
            read RCX s = word_zx (d:int32) /\
            read RDX s = word_zx (e:int32) /\
            read R8 s  = word_zx (f:int32) /\
            read R9 s  = word_zx (g:int32) /\
            read R10 s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 299) /\
            read R10 s = word_zx (EL 0 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read R11 s = word_zx (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RAX s = word_zx (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RBX s = word_zx (EL 3 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RCX s = word_zx (EL 4 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RDX s = word_zx (EL 5 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read R8 s  = word_zx (EL 6 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read R9 s  = word_zx (EL 7 (sha256_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw))) /\
            read RDI s = word_zx (word_xor (a:int32) (b:int32)) /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = word_bytereverse wraw)
       (MAYCHANGE [RIP;RDI;RBP;R10;R11;RAX;RBX;RCX;RDX;R8;R9;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 4))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--32) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE] THEN
  REWRITE_TAC[sha256_round] THEN
  CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 6 - composing head rounds by cut-points: the 2-round prototype.     *)
(*                                                                           *)
(* This establishes the composition MECHANISM that scales to all 16 head     *)
(* rounds.  The naive alternative - step both rounds (65 instrs) and close    *)
(* the whole thing with one WORD_RULE - FAILS: round 0's output word_add tree *)
(* feeds round 1's sha_maj / sha_choose as NON-ATOMIC arguments, and since    *)
(* those primitives are opaque, WORD_RULE cannot reconcile the two            *)
(* associations of the argument trees.  Cut-points are therefore mandatory.   *)
(*                                                                           *)
(* The mechanism (one cut per round boundary):                               *)
(*   1. ENSURES_SEQUENCE_TAC at the boundary pc with a cut predicate Q that   *)
(*      states the post-round-k working state in SPEC TERMS - each register   *)
(*      holds word_zx(EL j (sha256_round^k ...)) in its rotated position, and *)
(*      the Maj-carry register holds word_zx(word_xor (EL 1 ..) (EL 2 ..)).   *)
(*   2. Segment 1 (round k) closes with the standard round closer.            *)
(*   3. In segment 2, ABBREV_TAC the inner round result (rr0 here) BEFORE      *)
(*      stepping.  This keeps the inner round OPAQUE, so REWRITE_TAC           *)
(*      [sha256_round] in segment 2 unfolds only the OUTER (round k+1)         *)
(*      application - the inner EL j rr0 atoms match the precondition          *)
(*      registers directly and the closer's final WORD_RULE sees only one      *)
(*      round's word_add tree (no nested-opaque blow-up).                     *)
(*                                                                           *)
(* The cut predicate's carry register is written generically as               *)
(* word_xor (EL 1 rr0) (EL 2 rr0) (= new-a ^ new-b of round 0, since          *)
(* b_1 = a_0 = EL 1 rr0 and c_1 = b_0 = EL 2 rr0), the form that round 1's    *)
(* Maj precondition consumes.                                                *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_HEAD2 = prove
 (`!pc K256 kbase stackptr dataptr a b c d e f g h wraw0 wraw1 k0 k1.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kbase:int64,8) /\
     nonoverlapping (stackptr:int64,64) (dataptr:int64,8)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc K256) /\
            read RIP s = word (pc + 87) /\
            read RBP s = kbase /\ read RSP s = stackptr /\ read RSI s = dataptr /\
            read RDI s = word_zx (b:int32) /\
            read (memory :> bytes32 dataptr) s = wraw0 /\
            read (memory :> bytes32 (word_add dataptr (word 4))) s = wraw1 /\
            read (memory :> bytes32 kbase) s = (k0:int32) /\
            read (memory :> bytes32 (word_add kbase (word 4))) s = (k1:int32) /\
            read RAX s = word_zx (a:int32) /\ read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\ read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\ read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\ read R11 s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 299) /\
            read R10 s = word_zx (EL 0 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1))) /\
            read R11 s = word_zx (EL 1 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1))) /\
            read RAX s = word_zx (EL 2 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1))) /\
            read RBX s = word_zx (EL 3 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1))) /\
            read RCX s = word_zx (EL 4 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1))) /\
            read RDX s = word_zx (EL 5 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1))) /\
            read R8 s  = word_zx (EL 6 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1))) /\
            read R9 s  = word_zx (EL 7 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1))) /\
            read (memory :> bytes32 stackptr) s = word_bytereverse wraw0 /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = word_bytereverse wraw1)
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 stackptr] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 4))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_SEQUENCE_TAC `pc + 194`
   `\s. read RSI s = dataptr /\ read RSP s = stackptr /\
        read RBP s = word_add kbase (word 4) /\
        read (memory :> bytes32 (word_add dataptr (word 4))) s = wraw1 /\
        read (memory :> bytes32 (word_add kbase (word 4))) s = k1 /\
        read R11 s = word_zx (EL 0 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read RAX s = word_zx (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read RBX s = word_zx (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read RCX s = word_zx (EL 3 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read RDX s = word_zx (EL 4 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read R8 s  = word_zx (EL 5 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read R9 s  = word_zx (EL 6 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read R10 s = word_zx (EL 7 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read R15 s = word_zx (word_xor (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)))) /\
        read (memory :> bytes32 stackptr) s = word_bytereverse wraw0` THEN
  CONJ_TAC THENL
   [(* segment 1: round 0, pc+87 .. pc+194 *)
    ENSURES_INIT_TAC "s0" THEN
    X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--33) THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
    REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
                SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE] THEN
    REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    (* segment 2: round 1, pc+194 .. pc+299, inner round kept opaque as rr0 *)
    ABBREV_TAC `rr0:int32 list = sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)` THEN
    ENSURES_INIT_TAC "s0" THEN
    X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--32) THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
    REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
                SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE] THEN
    REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE]);;

(* ------------------------------------------------------------------------- *)
(* Phase 6 - composing head rounds by cut-points: the 4-round lemma.         *)
(*                                                                           *)
(* Exactly HEAD2 with two MORE cut-points (pc+299 after round 1, pc+406      *)
(* after round 2); final segment is round 3, exit pc+509.  Framing A         *)
(* (explicit nested sha256_round, one free k_i / wraw_i per round).  This    *)
(* is the first lemma past HEAD2 to cross the round-3 LEA +20 K-stride        *)
(* (rbp advances kbase+12 -> kbase+32 after round 3, the +20 step that ends   *)
(* each group of four), confirming the cut mechanism is K-walk agnostic.     *)
(*                                                                           *)
(* Register rotation (role j after t rounds in C[(j-t) MOD 8], canonical     *)
(* C = [RAX;RBX;RCX;RDX;R8;R9;R10;R11]) and the period-2 Maj carry, both     *)
(* re-verified against the binary (session 007):                            *)
(*   after r0: a..h in R11,RAX,RBX,RCX,RDX,R8,R9,R10  ; carry-out R15        *)
(*   after r1: a..h in R10,R11,RAX,RBX,RCX,RDX,R8,R9  ; carry-out RDI        *)
(*   after r2: a..h in R9,R10,R11,RAX,RBX,RCX,RDX,R8  ; carry-out R15        *)
(*   after r3: a..h in R8,R9,R10,R11,RAX,RBX,RCX,RDX  ; carry-out RDI        *)
(* W_i read from dataptr+4i, stored to stackptr+4i; k_i from kbase+(0,4,8,12).*)
(*                                                                           *)
(* Each segment uses the standard round closer; later segments ABBREV_TAC    *)
(* the running inner state (rr0/rr1/rr2) BEFORE stepping, so REWRITE_TAC      *)
(* [sha256_round] unfolds only that segment's outer round (no nested-opaque  *)
(* blow-up), per the HEAD2 mechanism.                                        *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_HEAD4 = prove
 (`!pc K256 kbase stackptr dataptr a b c d e f g h
     wraw0 wraw1 wraw2 wraw3 k0 k1 k2 k3.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kbase:int64,16) /\
     nonoverlapping (stackptr:int64,64) (dataptr:int64,16)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc K256) /\
            read RIP s = word (pc + 87) /\
            read RBP s = kbase /\ read RSP s = stackptr /\ read RSI s = dataptr /\
            read RDI s = word_zx (b:int32) /\
            read (memory :> bytes32 dataptr) s = wraw0 /\
            read (memory :> bytes32 (word_add dataptr (word 4))) s = wraw1 /\
            read (memory :> bytes32 (word_add dataptr (word 8))) s = wraw2 /\
            read (memory :> bytes32 (word_add dataptr (word 12))) s = wraw3 /\
            read (memory :> bytes32 kbase) s = (k0:int32) /\
            read (memory :> bytes32 (word_add kbase (word 4))) s = (k1:int32) /\
            read (memory :> bytes32 (word_add kbase (word 8))) s = (k2:int32) /\
            read (memory :> bytes32 (word_add kbase (word 12))) s = (k3:int32) /\
            read RAX s = word_zx (a:int32) /\ read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\ read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\ read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\ read R11 s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 509) /\
            read R8 s  = word_zx (EL 0 (sha256_round (sha256_round (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3))) /\
            read R9 s  = word_zx (EL 1 (sha256_round (sha256_round (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3))) /\
            read R10 s = word_zx (EL 2 (sha256_round (sha256_round (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3))) /\
            read R11 s = word_zx (EL 3 (sha256_round (sha256_round (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3))) /\
            read RAX s = word_zx (EL 4 (sha256_round (sha256_round (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3))) /\
            read RBX s = word_zx (EL 5 (sha256_round (sha256_round (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3))) /\
            read RCX s = word_zx (EL 6 (sha256_round (sha256_round (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3))) /\
            read RDX s = word_zx (EL 7 (sha256_round (sha256_round (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3))) /\
            read (memory :> bytes32 stackptr) s = word_bytereverse wraw0 /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = word_bytereverse wraw1 /\
            read (memory :> bytes32 (word_add stackptr (word 8))) s = word_bytereverse wraw2 /\
            read (memory :> bytes32 (word_add stackptr (word 12))) s = word_bytereverse wraw3)
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 stackptr] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 4))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 8))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 12))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  (* ---- cut after round 0 : pc+194 ---- *)
  ENSURES_SEQUENCE_TAC `pc + 194`
   `\s. read RSI s = dataptr /\ read RSP s = stackptr /\
        read RBP s = word_add kbase (word 4) /\
        read (memory :> bytes32 (word_add dataptr (word 4))) s = wraw1 /\
        read (memory :> bytes32 (word_add dataptr (word 8))) s = wraw2 /\
        read (memory :> bytes32 (word_add dataptr (word 12))) s = wraw3 /\
        read (memory :> bytes32 (word_add kbase (word 4))) s = k1 /\
        read (memory :> bytes32 (word_add kbase (word 8))) s = k2 /\
        read (memory :> bytes32 (word_add kbase (word 12))) s = k3 /\
        read R11 s = word_zx (EL 0 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read RAX s = word_zx (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
