    REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
    REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
                SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE] THEN
    REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    ALL_TAC] THEN
  ABBREV_TAC `rr14:int32 list = sha256_round rr13 k14 (word_bytereverse wraw14)` THEN
  (* final segment: round 15, pc+1663 .. pc+1786 *)
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--37) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE] THEN
  REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ========================================================================= *)
(* Phase 8/9 - abstract-m restatement infrastructure + HEAD16_ABS.           *)
(*                                                                           *)
(* The inner-loop chain (Phase 8 STEP 3) is built over the OPAQUE working    *)
(* state  sha256_compress_rounds m hsh N  rather than the explicit nested    *)
(* sha256_round term, so each per-iteration seam is O(1) in N and the x3     *)
(* chain does not explode (the pure-unroll route was measured non-viable,    *)
(* session-021).  COMPRESS_ROUNDS_CONV unfolds compress_rounds N into the    *)
(* N-deep nest with symbolic EL t sha256_constants / sha256_msg_schedule m t;*)
(* SCHED_LT16_CONV reduces the head schedule words (t<16) to EL t m.         *)
(* ========================================================================= *)
(* --- the fold conversion (from the probe) --- *)
let COMPRESS_ROUNDS_SUC = prove
 (`sha256_compress_rounds m hsh (SUC n) =
     sha256_round (sha256_compress_rounds m hsh n)
                  (EL n sha256_constants)
                  (sha256_msg_schedule m n)`,
  REWRITE_TAC[ADD1; sha256_compress_rounds]);;

let COMPRESS_ROUNDS_CONV : conv =
  let cr0 = CONJUNCT1 sha256_compress_rounds in
  let rec conv tm =
    let n = dest_small_numeral (rand tm) in
    if n = 0 then REWR_CONV cr0 tm
    else
      (RAND_CONV num_CONV THENC
       REWR_CONV COMPRESS_ROUNDS_SUC THENC
       RATOR_CONV(RATOR_CONV(RAND_CONV conv))) tm in
  conv;;

(* sha256_msg_schedule m t  ->  EL t m   for literal t < 16 *)
let SCHED_LT16_CONV : conv =
  ONCE_REWRITE_CONV[sha256_msg_schedule] THENC
  RATOR_CONV(RATOR_CONV(RAND_CONV NUM_LT_CONV)) THENC
  REWRITE_CONV[COND_CLAUSES];;

(* The fold theorem we want to use (GSYM) to collapse the nest into        *)
(* compress_rounds.  Build it as an equation:                              *)
(*   sha256_compress_rounds m hsh 16 = <16-deep nest with EL t m words>    *)
let HEAD16_FOLD = GEN_ALL (prove
 (`sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16 =
   sha256_round (sha256_round (sha256_round (sha256_round (sha256_round
   (sha256_round (sha256_round (sha256_round (sha256_round (sha256_round
   (sha256_round (sha256_round (sha256_round (sha256_round (sha256_round
   (sha256_round [a;b;c;d;e;f;g;h]
     (EL 0 sha256_constants) (EL 0 m))
     (EL 1 sha256_constants) (EL 1 m))
     (EL 2 sha256_constants) (EL 2 m))
     (EL 3 sha256_constants) (EL 3 m))
     (EL 4 sha256_constants) (EL 4 m))
     (EL 5 sha256_constants) (EL 5 m))
     (EL 6 sha256_constants) (EL 6 m))
     (EL 7 sha256_constants) (EL 7 m))
     (EL 8 sha256_constants) (EL 8 m))
     (EL 9 sha256_constants) (EL 9 m))
     (EL 10 sha256_constants) (EL 10 m))
     (EL 11 sha256_constants) (EL 11 m))
     (EL 12 sha256_constants) (EL 12 m))
     (EL 13 sha256_constants) (EL 13 m))
     (EL 14 sha256_constants) (EL 14 m))
     (EL 15 sha256_constants) (EL 15 m)`,
  CONV_TAC(LAND_CONV(COMPRESS_ROUNDS_CONV THENC ONCE_DEPTH_CONV SCHED_LT16_CONV)) THEN
  REFL_TAC));;

(* Partial unfold: unfold compress_rounds m hsh N down to a floor F,        *)
(* leaving compress_rounds m hsh F opaque.  Used to fold the inner-loop     *)
(* body lemmas whose pre/post working state are compress_rounds (16+16i).   *)
let COMPRESS_ROUNDS_DOWNTO (floor:int) : conv =
  let rec conv tm =
    let n = dest_small_numeral (rand tm) in
    if n <= floor then REFL tm
    else (RAND_CONV num_CONV THENC REWR_CONV COMPRESS_ROUNDS_SUC THENC
          RATOR_CONV(RATOR_CONV(RAND_CONV conv))) tm in
  conv;;

(* List reconstruction for an 8-element state: needed to collapse the post   *)
(* nest base [EL 0 l;..;EL 7 l] back to l (l = compress_rounds m sin 16).    *)
let EL8_RECONSTRUCT = prove
 (`!l:int32 list. LENGTH l = 8
       ==> [EL 0 l; EL 1 l; EL 2 l; EL 3 l; EL 4 l; EL 5 l; EL 6 l; EL 7 l] = l`,
  REPEAT STRIP_TAC THEN POP_ASSUM MP_TAC THEN
  CONV_TAC(LAND_CONV(RAND_CONV(TOP_DEPTH_CONV num_CONV))) THEN
  REWRITE_TAC[LENGTH_EQ_CONS; LENGTH_EQ_NIL] THEN
  STRIP_TAC THEN ASM_REWRITE_TAC[] THEN
  CONV_TAC(ONCE_DEPTH_CONV EL_CONV) THEN REWRITE_TAC[]);;

(* HEAD16_ABS: HEAD16 restated with post working state                       *)
(*   sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16,                          *)
(* round constants folded to EL t sha256_constants and head message words to *)
(* EL t m.  DERIVED from HEAD16 by instantiating wraw_t := word_bytereverse  *)
(* (EL t m), k_t := EL t sha256_constants, collapsing the word_bytereverse   *)
(* involution, then folding the nest via GSYM HEAD16_FOLD.                   *)
let SHA256_BLOCK_NOHW_HEAD16_ABS = prove
 (`!pc kdat kbase stackptr dataptr a b c d e f g h (m:int32 list).
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kbase:int64,112) /\
     nonoverlapping (stackptr:int64,64) (dataptr:int64,64)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kdat) /\
            read RIP s = word (pc + 87) /\
            read RBP s = kbase /\ read RSP s = stackptr /\ read RSI s = dataptr /\
            read RDI s = word_zx (b:int32) /\
            read (memory :> bytes32 dataptr) s = word_bytereverse (EL 0 m) /\
            read (memory :> bytes32 (word_add dataptr (word 4))) s = word_bytereverse (EL 1 m) /\
            read (memory :> bytes32 (word_add dataptr (word 8))) s = word_bytereverse (EL 2 m) /\
            read (memory :> bytes32 (word_add dataptr (word 12))) s = word_bytereverse (EL 3 m) /\
            read (memory :> bytes32 (word_add dataptr (word 16))) s = word_bytereverse (EL 4 m) /\
            read (memory :> bytes32 (word_add dataptr (word 20))) s = word_bytereverse (EL 5 m) /\
            read (memory :> bytes32 (word_add dataptr (word 24))) s = word_bytereverse (EL 6 m) /\
            read (memory :> bytes32 (word_add dataptr (word 28))) s = word_bytereverse (EL 7 m) /\
            read (memory :> bytes32 (word_add dataptr (word 32))) s = word_bytereverse (EL 8 m) /\
            read (memory :> bytes32 (word_add dataptr (word 36))) s = word_bytereverse (EL 9 m) /\
            read (memory :> bytes32 (word_add dataptr (word 40))) s = word_bytereverse (EL 10 m) /\
            read (memory :> bytes32 (word_add dataptr (word 44))) s = word_bytereverse (EL 11 m) /\
            read (memory :> bytes32 (word_add dataptr (word 48))) s = word_bytereverse (EL 12 m) /\
            read (memory :> bytes32 (word_add dataptr (word 52))) s = word_bytereverse (EL 13 m) /\
            read (memory :> bytes32 (word_add dataptr (word 56))) s = word_bytereverse (EL 14 m) /\
            read (memory :> bytes32 (word_add dataptr (word 60))) s = word_bytereverse (EL 15 m) /\
            read (memory :> bytes32 kbase) s = EL 0 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 4))) s = EL 1 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 8))) s = EL 2 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 12))) s = EL 3 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 32))) s = EL 4 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 36))) s = EL 5 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 40))) s = EL 6 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 44))) s = EL 7 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 64))) s = EL 8 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 68))) s = EL 9 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 72))) s = EL 10 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 76))) s = EL 11 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 96))) s = EL 12 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 100))) s = EL 13 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 104))) s = EL 14 sha256_constants /\
            read (memory :> bytes32 (word_add kbase (word 108))) s = EL 15 sha256_constants /\
            read RAX s = word_zx (a:int32) /\ read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\ read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\ read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\ read R11 s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 1786) /\
            read RBP s = word_add kbase (word 128) /\
            read RAX s = word_zx (EL 0 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read RBX s = word_zx (EL 1 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read RCX s = word_zx (EL 2 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read RDX s = word_zx (EL 3 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read R8 s = word_zx (EL 4 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read R9 s = word_zx (EL 5 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read R10 s = word_zx (EL 6 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read R11 s = word_zx (EL 7 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read R12 s = word_zx (EL 1 m) /\
            read R13 s = word_zx (word_ror (EL 1 m) 11) /\
            read R15 s = word_zx (EL 14 m) /\
            read RDI s = word_zx (word_xor (EL 1 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16)) (EL 2 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 16))) /\
            read (memory :> bytes32 stackptr) s = EL 0 m /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = EL 1 m /\
            read (memory :> bytes32 (word_add stackptr (word 8))) s = EL 2 m /\
            read (memory :> bytes32 (word_add stackptr (word 12))) s = EL 3 m /\
            read (memory :> bytes32 (word_add stackptr (word 16))) s = EL 4 m /\
            read (memory :> bytes32 (word_add stackptr (word 20))) s = EL 5 m /\
            read (memory :> bytes32 (word_add stackptr (word 24))) s = EL 6 m /\
            read (memory :> bytes32 (word_add stackptr (word 28))) s = EL 7 m /\
            read (memory :> bytes32 (word_add stackptr (word 32))) s = EL 8 m /\
            read (memory :> bytes32 (word_add stackptr (word 36))) s = EL 9 m /\
            read (memory :> bytes32 (word_add stackptr (word 40))) s = EL 10 m /\
            read (memory :> bytes32 (word_add stackptr (word 44))) s = EL 11 m /\
            read (memory :> bytes32 (word_add stackptr (word 48))) s = EL 12 m /\
            read (memory :> bytes32 (word_add stackptr (word 52))) s = EL 13 m /\
            read (memory :> bytes32 (word_add stackptr (word 56))) s = EL 14 m /\
            read (memory :> bytes32 (word_add stackptr (word 60))) s = EL 15 m)
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 stackptr] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 4))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 8))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 12))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 16))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 20))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 24))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 28))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 32))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 36))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 40))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 44))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 48))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 52))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 56))] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 60))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REPEAT GEN_TAC THEN STRIP_TAC THEN
  MP_TAC(SPECL
   [`pc:num`; `kdat:num`; `kbase:int64`; `stackptr:int64`; `dataptr:int64`;
    `a:int32`; `b:int32`; `c:int32`; `d:int32`;
    `e:int32`; `f:int32`; `g:int32`; `h:int32`;
    `word_bytereverse (EL 0 m):int32`; `word_bytereverse (EL 1 m):int32`;
    `word_bytereverse (EL 2 m):int32`; `word_bytereverse (EL 3 m):int32`;
    `word_bytereverse (EL 4 m):int32`; `word_bytereverse (EL 5 m):int32`;
    `word_bytereverse (EL 6 m):int32`; `word_bytereverse (EL 7 m):int32`;
    `word_bytereverse (EL 8 m):int32`; `word_bytereverse (EL 9 m):int32`;
    `word_bytereverse (EL 10 m):int32`; `word_bytereverse (EL 11 m):int32`;
    `word_bytereverse (EL 12 m):int32`; `word_bytereverse (EL 13 m):int32`;
    `word_bytereverse (EL 14 m):int32`; `word_bytereverse (EL 15 m):int32`;
    `EL 0 sha256_constants:int32`; `EL 1 sha256_constants:int32`;
    `EL 2 sha256_constants:int32`; `EL 3 sha256_constants:int32`;
    `EL 4 sha256_constants:int32`; `EL 5 sha256_constants:int32`;
    `EL 6 sha256_constants:int32`; `EL 7 sha256_constants:int32`;
    `EL 8 sha256_constants:int32`; `EL 9 sha256_constants:int32`;
    `EL 10 sha256_constants:int32`; `EL 11 sha256_constants:int32`;
    `EL 12 sha256_constants:int32`; `EL 13 sha256_constants:int32`;
    `EL 14 sha256_constants:int32`; `EL 15 sha256_constants:int32`]
   SHA256_BLOCK_NOHW_HEAD16) THEN
  ASM_REWRITE_TAC[] THEN
  (* collapse word_bytereverse(word_bytereverse x) = x then fold nest *)
  REWRITE_TAC[WORD_BYTEREVERSE_BYTEREVERSE; GSYM HEAD16_FOLD]);;

(* ========================================================================= *)
(* Phase 7 - the rounds_16_xx body (16 fused message-schedule-expand +       *)
(* compress sub-rounds, run 3 times under the rodata sentinel).              *)
(*                                                                           *)
(* Each sub-round i (0<=i<16, absolute round t=16+i within this pass)        *)
(* first expands the message schedule IN PLACE over the 16-word stack ring:  *)
(*                                                                           *)
(*   W[t] = sigma1(ring[(i+14) mod 16]) + ring[(i+9) mod 16]                 *)
(*               + sigma0(ring[(i+1) mod 16]) + ring[i mod 16]              *)
(*                                                                           *)
(* storing W[t] back into ring slot (i mod 16) (rsp + 4*(i mod 16)); then    *)
(* runs one compression round with W[t] as the message word and K[t] from    *)
(* (%rbp).  The register file, Maj carried-XOR and K-walk all CONTINUE from   *)
(* the head section unchanged (round 16 = 16 mod 8 = 0 is canonical;         *)
(* a->RAX..h->R11; round-t role j in C[(j-t) mod 8]).                        *)
(*                                                                           *)
(* DEFERRED Sigma0 FOLD (same pipeline as the head, verified vs the binary). *)
(* Sub-round i's  add %r14d,<new-a>  is pipelined ~16 bytes INTO sub-round   *)
(* (i+1)'s prologue (fold PCs pc+1945,2105,...,4202, and sub-round 15's at   *)
(* pc+4360 is PAST the back-edge, like head round 15 past the head JMP).  So *)
(* a CLEAN (folded) working-var state occurs at fold_pc+3, where the NEXT    *)
(* sub-round's sigma0 scratch (r12 = ring[(i+2) mod 16],                     *)
(* r13 = word_ror that 11) and sigma1 scratch are already live.  BODY1       *)
(* below cuts there: pc+1786 (= HEAD16's exit) .. pc+1948 (= round-16 fold   *)
(* pc+1945 + 3), 47 instructions.                                            *)
(*                                                                           *)
(* PARITY (period 2).  Round 16 is EVEN: sigma1 scratch in R15, Maj carry-in *)
(* in EDI.  (Odd rounds swap: sigma1 in EDI, carry-in in R15.)  sigma0       *)
(* scratch is always r12/r13.                                                *)
(*                                                                           *)
(* Framing A (as for the head): free round constant k16 and opaque ring      *)
(* words v0..v15 (each = word_bytereverse wraw_j after the head).  The exit  *)
(* asserts the 8 clean working vars (sha256_round of the input state with    *)
(* the freshly-expanded message word) and the rewritten ring slot 0.  The    *)
(* live exit sigma-scratch for round 17 is left in MAYCHANGE here (BODY1 is   *)
(* the single-sub-round analogue of ROUND0/ROUND1); the cut-point            *)
(* composition lemma carries it forward across sub-round seams.              *)
(*                                                                           *)
(* The closer is the head closer plus the two message-schedule sigma bridges *)
(* SHA256_MSG_SIGMA0_BRIDGE / SHA256_MSG_SIGMA1_BRIDGE (the asm sigma0/sigma1 *)
(* rotate-shift chains match their LHS exactly).                             *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_BODY1 = prove
 (`!pc K256 kbase stackptr a b c d e f g h
     v0 v1 v2 v3 v4 v5 v6 v7 v8 v9 v10 v11 v12 v13 v14 v15 k16.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kbase:int64,4)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc K256) /\
            read RIP s = word (pc + 1786) /\
            read RBP s = kbase /\
            read RSP s = stackptr /\
            read R12 s = word_zx (v1:int32) /\
            read R13 s = word_zx (word_ror (v1:int32) 11) /\
            read R15 s = word_zx (v14:int32) /\
            read RDI s = word_zx (word_xor (b:int32) (c:int32)) /\
            read (memory :> bytes32 kbase) s = (k16:int32) /\
            read (memory :> bytes32 stackptr) s = v0 /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = v1 /\
            read (memory :> bytes32 (word_add stackptr (word 8))) s = v2 /\
            read (memory :> bytes32 (word_add stackptr (word 12))) s = v3 /\
            read (memory :> bytes32 (word_add stackptr (word 16))) s = v4 /\
            read (memory :> bytes32 (word_add stackptr (word 20))) s = v5 /\
            read (memory :> bytes32 (word_add stackptr (word 24))) s = v6 /\
            read (memory :> bytes32 (word_add stackptr (word 28))) s = v7 /\
            read (memory :> bytes32 (word_add stackptr (word 32))) s = v8 /\
            read (memory :> bytes32 (word_add stackptr (word 36))) s = v9 /\
            read (memory :> bytes32 (word_add stackptr (word 40))) s = v10 /\
            read (memory :> bytes32 (word_add stackptr (word 44))) s = v11 /\
            read (memory :> bytes32 (word_add stackptr (word 48))) s = v12 /\
            read (memory :> bytes32 (word_add stackptr (word 52))) s = v13 /\
            read (memory :> bytes32 (word_add stackptr (word 56))) s = v14 /\
            read (memory :> bytes32 (word_add stackptr (word 60))) s = v15 /\
            read RAX s = word_zx (a:int32) /\
            read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\
            read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\
            read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\
            read R11 s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 1948) /\
            read R11 s = word_zx (EL 0 (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0)))) /\
            read RAX s = word_zx (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0)))) /\
            read RBX s = word_zx (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0)))) /\
            read RCX s = word_zx (EL 3 (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0)))) /\
            read RDX s = word_zx (EL 4 (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0)))) /\
            read R8 s  = word_zx (EL 5 (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0)))) /\
            read R9 s  = word_zx (EL 6 (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0)))) /\
            read R10 s = word_zx (EL 7 (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0)))) /\
            read (memory :> bytes32 stackptr) s =
              word_add (word_add (sha_msg_sigma_1 v14) v9)
                       (word_add (sha_msg_sigma_0 v1) v0))
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 stackptr] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--47) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
              SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha256_round] THEN
  CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 7 - BODY2: TWO rounds_16_xx sub-rounds (rounds 16,17) composed by a  *)
(* cut-point at pc+1948 (round 16's clean exit, = BODY1's exit).  This is the *)
(* head HEAD2 mechanism applied to the 16xx body, and it validates the whole  *)
(* sub-round-composition recipe the BODY{N} generator scales up:             *)
(*                                                                           *)
(*  - FULL-RING cut predicate.  Unlike the head (where slot t is freshly      *)
(*    STORED at round t), every 16xx sub-round REWRITES one ring slot, so the *)
(*    cut predicate must carry all 16 ring words: slot 0 already holds the    *)
(*    round-16 expansion w16, slots 1..15 still hold v1..v15.  (Only the      *)
(*    slots actually read by round 17 - 1,2,10,15 - plus the rewritten slot 0 *)
(*    and slot 1 in the postcondition need to appear; the rest ride in        *)
(*    MAYCHANGE / are reintroduced by the next sub-round as needed.)         *)
(*  - PARITY SWAP across the seam.  Round 16 is even (sigma1 scratch R15,     *)
(*    Maj carry-in EDI); round 17 is odd (sigma1 scratch EDI, carry-in R15).  *)
(*    The cut predicate therefore exposes RDI = v15 (round-17 sigma1 src) and *)
(*    R15 = word_xor(EL1)(EL2) of the round-16 output (round-17 Maj carry-in).*)
(*  - DEFERRED sigma0 SCRATCH carried across.  At pc+1948 r12 = v2,           *)
(*    r13 = word_ror v2 11 (round-17 sigma0 src = ring slot 2), pre-loaded by *)
(*    round 16's tail; the cut predicate exposes them so segment 2 can step.  *)
(*  - ABBREV_TAC rr16 before stepping segment 2 keeps sha256_round nested one *)
(*    round at a time (same trick as the head HEAD2/HEAD4).                  *)
(*                                                                           *)
(* Each segment is 47 instructions (round 16: pc+1786..1948; round 17:        *)
(* pc+1948..2108).  Closer identical to BODY1.                               *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_BODY2 = prove
 (`!pc K256 kbase stackptr a b c d e f g h
     v0 v1 v2 v3 v4 v5 v6 v7 v8 v9 v10 v11 v12 v13 v14 v15 k16 k17.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kbase:int64,8)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc K256) /\
            read RIP s = word (pc + 1786) /\
            read RBP s = kbase /\
            read RSP s = stackptr /\
            read R12 s = word_zx (v1:int32) /\
            read R13 s = word_zx (word_ror (v1:int32) 11) /\
            read R15 s = word_zx (v14:int32) /\
            read RDI s = word_zx (word_xor (b:int32) (c:int32)) /\
            read (memory :> bytes32 kbase) s = (k16:int32) /\
            read (memory :> bytes32 (word_add kbase (word 4))) s = (k17:int32) /\
            read (memory :> bytes32 stackptr) s = v0 /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = v1 /\
            read (memory :> bytes32 (word_add stackptr (word 8))) s = v2 /\
            read (memory :> bytes32 (word_add stackptr (word 12))) s = v3 /\
            read (memory :> bytes32 (word_add stackptr (word 16))) s = v4 /\
            read (memory :> bytes32 (word_add stackptr (word 20))) s = v5 /\
            read (memory :> bytes32 (word_add stackptr (word 24))) s = v6 /\
            read (memory :> bytes32 (word_add stackptr (word 28))) s = v7 /\
            read (memory :> bytes32 (word_add stackptr (word 32))) s = v8 /\
            read (memory :> bytes32 (word_add stackptr (word 36))) s = v9 /\
            read (memory :> bytes32 (word_add stackptr (word 40))) s = v10 /\
            read (memory :> bytes32 (word_add stackptr (word 44))) s = v11 /\
            read (memory :> bytes32 (word_add stackptr (word 48))) s = v12 /\
            read (memory :> bytes32 (word_add stackptr (word 52))) s = v13 /\
            read (memory :> bytes32 (word_add stackptr (word 56))) s = v14 /\
            read (memory :> bytes32 (word_add stackptr (word 60))) s = v15 /\
            read RAX s = word_zx (a:int32) /\
            read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\
            read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\
            read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\
            read R11 s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 2108) /\
            read R10 s = word_zx (EL 0 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))) k17
              (word_add (word_add (sha_msg_sigma_1 v15) v10)
                        (word_add (sha_msg_sigma_0 v2) v1)))) /\
            read R11 s = word_zx (EL 1 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))) k17
              (word_add (word_add (sha_msg_sigma_1 v15) v10)
                        (word_add (sha_msg_sigma_0 v2) v1)))) /\
            read RAX s = word_zx (EL 2 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))) k17
              (word_add (word_add (sha_msg_sigma_1 v15) v10)
                        (word_add (sha_msg_sigma_0 v2) v1)))) /\
            read RBX s = word_zx (EL 3 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))) k17
              (word_add (word_add (sha_msg_sigma_1 v15) v10)
                        (word_add (sha_msg_sigma_0 v2) v1)))) /\
            read RCX s = word_zx (EL 4 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))) k17
              (word_add (word_add (sha_msg_sigma_1 v15) v10)
                        (word_add (sha_msg_sigma_0 v2) v1)))) /\
            read RDX s = word_zx (EL 5 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))) k17
              (word_add (word_add (sha_msg_sigma_1 v15) v10)
                        (word_add (sha_msg_sigma_0 v2) v1)))) /\
            read R8 s  = word_zx (EL 6 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))) k17
              (word_add (word_add (sha_msg_sigma_1 v15) v10)
                        (word_add (sha_msg_sigma_0 v2) v1)))) /\
            read R9 s  = word_zx (EL 7 (sha256_round (sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))) k17
              (word_add (word_add (sha_msg_sigma_1 v15) v10)
                        (word_add (sha_msg_sigma_0 v2) v1)))) /\
            read (memory :> bytes32 stackptr) s =
              word_add (word_add (sha_msg_sigma_1 v14) v9)
                       (word_add (sha_msg_sigma_0 v1) v0) /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s =
              word_add (word_add (sha_msg_sigma_1 v15) v10)
                       (word_add (sha_msg_sigma_0 v2) v1))
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 stackptr] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 4))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_SEQUENCE_TAC `pc + 1948`
   `\s. read RSP s = stackptr /\
        read RBP s = word_add kbase (word 4) /\
        read R12 s = word_zx (v2:int32) /\
        read R13 s = word_zx (word_ror (v2:int32) 11) /\
        read RDI s = word_zx (v15:int32) /\
        read R15 s = word_zx (word_xor
              (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k16
                (word_add (word_add (sha_msg_sigma_1 v14) v9)
                          (word_add (sha_msg_sigma_0 v1) v0))))
              (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k16
                (word_add (word_add (sha_msg_sigma_1 v14) v9)
                          (word_add (sha_msg_sigma_0 v1) v0))))) /\
        read (memory :> bytes32 (word_add kbase (word 4))) s = k17 /\
        read (memory :> bytes32 (word_add stackptr (word 4))) s = v1 /\
        read (memory :> bytes32 (word_add stackptr (word 8))) s = v2 /\
        read (memory :> bytes32 (word_add stackptr (word 12))) s = v3 /\
        read (memory :> bytes32 (word_add stackptr (word 16))) s = v4 /\
        read (memory :> bytes32 (word_add stackptr (word 20))) s = v5 /\
        read (memory :> bytes32 (word_add stackptr (word 24))) s = v6 /\
        read (memory :> bytes32 (word_add stackptr (word 28))) s = v7 /\
        read (memory :> bytes32 (word_add stackptr (word 32))) s = v8 /\
        read (memory :> bytes32 (word_add stackptr (word 36))) s = v9 /\
        read (memory :> bytes32 (word_add stackptr (word 40))) s = v10 /\
        read (memory :> bytes32 (word_add stackptr (word 56))) s = v14 /\
        read (memory :> bytes32 (word_add stackptr (word 60))) s = v15 /\
        read R11 s = word_zx (EL 0 (sha256_round [a;b;c;d;e;f;g;h] k16
          (word_add (word_add (sha_msg_sigma_1 v14) v9)
                    (word_add (sha_msg_sigma_0 v1) v0)))) /\
        read RAX s = word_zx (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k16
          (word_add (word_add (sha_msg_sigma_1 v14) v9)
                    (word_add (sha_msg_sigma_0 v1) v0)))) /\
        read RBX s = word_zx (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k16
          (word_add (word_add (sha_msg_sigma_1 v14) v9)
                    (word_add (sha_msg_sigma_0 v1) v0)))) /\
        read RCX s = word_zx (EL 3 (sha256_round [a;b;c;d;e;f;g;h] k16
          (word_add (word_add (sha_msg_sigma_1 v14) v9)
                    (word_add (sha_msg_sigma_0 v1) v0)))) /\
        read RDX s = word_zx (EL 4 (sha256_round [a;b;c;d;e;f;g;h] k16
          (word_add (word_add (sha_msg_sigma_1 v14) v9)
                    (word_add (sha_msg_sigma_0 v1) v0)))) /\
        read R8 s  = word_zx (EL 5 (sha256_round [a;b;c;d;e;f;g;h] k16
          (word_add (word_add (sha_msg_sigma_1 v14) v9)
                    (word_add (sha_msg_sigma_0 v1) v0)))) /\
        read R9 s  = word_zx (EL 6 (sha256_round [a;b;c;d;e;f;g;h] k16
          (word_add (word_add (sha_msg_sigma_1 v14) v9)
                    (word_add (sha_msg_sigma_0 v1) v0)))) /\
        read R10 s = word_zx (EL 7 (sha256_round [a;b;c;d;e;f;g;h] k16
          (word_add (word_add (sha_msg_sigma_1 v14) v9)
                    (word_add (sha_msg_sigma_0 v1) v0)))) /\
        read (memory :> bytes32 stackptr) s =
          word_add (word_add (sha_msg_sigma_1 v14) v9)
                   (word_add (sha_msg_sigma_0 v1) v0)` THEN
  CONJ_TAC THENL
   [(* segment 1: round 16, pc+1786 .. pc+1948 *)
    ENSURES_INIT_TAC "s0" THEN
    X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--47) THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
    REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
                SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
                SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
    REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    ALL_TAC] THEN
  ABBREV_TAC `rr16:int32 list = sha256_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha_msg_sigma_1 v14) v9)
                        (word_add (sha_msg_sigma_0 v1) v0))` THEN
  (* segment 2: round 17, pc+1948 .. pc+2108 *)
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--47) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
              SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 7 - BODY15: the first FIFTEEN rounds_16_xx sub-rounds (rounds 16..30) *)
(* of one 16xx pass, composed by 14 cut-points (one per sub-round boundary,    *)
(* clean fold-to-fold states at fold_pc+3).  Pure scale-up of the BODY2        *)
(* mechanism via the auditable generator (orchestrator/logs/                   *)
(* session-008-body-gen.py); regression-validated token-faithfully at N=2      *)
(* against the committed BODY2 and proven at N=4 before scaling.               *)
(*                                                                           *)
(* Entry pc+1786 (= HEAD16 exit, round-16 clean entry); exit pc+4205           *)
(* (round-30 deferred-Sigma0 fold + 3 = sub-round 14's clean exit).  Each      *)
(* segment is 47 instructions.  The cut predicate carries all 16 ring slots    *)
(* (each rounds_16_xx sub-round REWRITES one ring slot in place; un-rewritten  *)
(* slots still hold v_j), the period-2 sigma scratch/Maj-carry parity, and the *)
(* RBP K-walk (kbase = rbp at round-16 entry; sub-round i reads K at offset     *)
(* 32*(i DIV 4)+4*(i MOD 4); kspan 108 for 15 sub-rounds).  Un-abbreviated     *)
(* ring occupants (nested message-schedule sigma expansions) scale fine to 15  *)
(* segments under WORD_RULE - no per-slot ABBREV needed.                       *)
(*                                                                           *)
(* WHY NOT 16: sub-round 15 (round 31) defers its Sigma0-fold to pc+4360,      *)
(* which is PAST the conditional back-edge `jne` at pc+4349 (sentinel `cmpb    *)
(* $0,3(%rbp)` at pc+4345).  So round 31 has NO clean folded state reachable    *)
(* without crossing the (symbolic-kbase) conditional branch; pc+4345 is a      *)
(* SPLIT state (new-a in EAX missing its +r14d Sigma0 term).  That split-state *)
(* tail and the back-edge are the Phase-8 loop-seam's job (analogous to        *)
(* HEAD16 stopping at the round-15 pre-fold boundary).  BODY15 is the clean,    *)
(* composable body lemma; it ends exactly where the 15th fold completes.       *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_BODY15 = prove
 (`!pc K256 kbase stackptr a b c d e f g h
     v0 v1 v2 v3 v4 v5 v6 v7 v8 v9 v10 v11 v12 v13 v14 v15 k16 k17 k18 k19 k20 k21 k22 k23 k24 k25 k26 k27 k28 k29 k30.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kbase:int64,108)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc K256) /\
            read RIP s = word (pc + 1786) /\
            read RBP s = kbase /\ read RSP s = stackptr /\
            read R12 s = word_zx (v1:int32) /\
            read R13 s = word_zx (word_ror (v1:int32) 11) /\
            read R15 s = word_zx (v14:int32) /\
            read RDI s = word_zx (word_xor (b:int32) (c:int32)) /\
            read (memory :> bytes32 kbase) s = (k16:int32) /\
            read (memory :> bytes32 (word_add kbase (word 4))) s = (k17:int32) /\
            read (memory :> bytes32 (word_add kbase (word 8))) s = (k18:int32) /\
            read (memory :> bytes32 (word_add kbase (word 12))) s = (k19:int32) /\
            read (memory :> bytes32 (word_add kbase (word 32))) s = (k20:int32) /\
            read (memory :> bytes32 (word_add kbase (word 36))) s = (k21:int32) /\
            read (memory :> bytes32 (word_add kbase (word 40))) s = (k22:int32) /\
            read (memory :> bytes32 (word_add kbase (word 44))) s = (k23:int32) /\
            read (memory :> bytes32 (word_add kbase (word 64))) s = (k24:int32) /\
            read (memory :> bytes32 (word_add kbase (word 68))) s = (k25:int32) /\
            read (memory :> bytes32 (word_add kbase (word 72))) s = (k26:int32) /\
            read (memory :> bytes32 (word_add kbase (word 76))) s = (k27:int32) /\
            read (memory :> bytes32 (word_add kbase (word 96))) s = (k28:int32) /\
            read (memory :> bytes32 (word_add kbase (word 100))) s = (k29:int32) /\
            read (memory :> bytes32 (word_add kbase (word 104))) s = (k30:int32) /\
            read (memory :> bytes32 stackptr) s = v0 /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = v1 /\
            read (memory :> bytes32 (word_add stackptr (word 8))) s = v2 /\
            read (memory :> bytes32 (word_add stackptr (word 12))) s = v3 /\
            read (memory :> bytes32 (word_add stackptr (word 16))) s = v4 /\
            read (memory :> bytes32 (word_add stackptr (word 20))) s = v5 /\
            read (memory :> bytes32 (word_add stackptr (word 24))) s = v6 /\
            read (memory :> bytes32 (word_add stackptr (word 28))) s = v7 /\
            read (memory :> bytes32 (word_add stackptr (word 32))) s = v8 /\
            read (memory :> bytes32 (word_add stackptr (word 36))) s = v9 /\
            read (memory :> bytes32 (word_add stackptr (word 40))) s = v10 /\
            read (memory :> bytes32 (word_add stackptr (word 44))) s = v11 /\
            read (memory :> bytes32 (word_add stackptr (word 48))) s = v12 /\
            read (memory :> bytes32 (word_add stackptr (word 52))) s = v13 /\
            read (memory :> bytes32 (word_add stackptr (word 56))) s = v14 /\
            read (memory :> bytes32 (word_add stackptr (word 60))) s = v15 /\
            read RAX s = word_zx (a:int32) /\ read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\ read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\ read R9 s  = word_zx (f:int32) /\
