    REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
    REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
                SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
                SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
    REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    ALL_TAC] THEN
  ABBREV_TAC `rr29:int32 list = (sha256_round rr28 k29 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 v15) v10) (word_add (sha_msg_sigma_0 v2) v1))) v12) (word_add (sha_msg_sigma_0 v4) v3))) v14) (word_add (sha_msg_sigma_0 v6) v5))) (word_add (word_add (sha_msg_sigma_1 v14) v9) (word_add (sha_msg_sigma_0 v1) v0))) (word_add (sha_msg_sigma_0 v8) v7))) (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 v14) v9) (word_add (sha_msg_sigma_0 v1) v0))) v11) (word_add (sha_msg_sigma_0 v3) v2))) (word_add (sha_msg_sigma_0 v10) v9))) (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 v14) v9) (word_add (sha_msg_sigma_0 v1) v0))) v11) (word_add (sha_msg_sigma_0 v3) v2))) v13) (word_add (sha_msg_sigma_0 v5) v4))) (word_add (sha_msg_sigma_0 v12) v11))) (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 v14) v9) (word_add (sha_msg_sigma_0 v1) v0))) v11) (word_add (sha_msg_sigma_0 v3) v2))) v13) (word_add (sha_msg_sigma_0 v5) v4))) v15) (word_add (sha_msg_sigma_0 v7) v6))) (word_add (sha_msg_sigma_0 v14) v13)))` THEN
  (* final segment: round 30, pc+4044 .. pc+4205 *)
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--47) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
              SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* BODY15_ABS: BODY15 (rounds 16..30) restated over the OPAQUE working state  *)
(* sha256_compress_rounds m sin (16 -> 31).  Built programmatically by         *)
(* instantiating BODY15 with                                                  *)
(*   a..h    := EL j (sha256_compress_rounds m sin 16),                       *)
(*   vj      := EL j m,                                                        *)
(*   k(16+j) := EL (16+j) sha256_constants,                                    *)
(* then folding the post nest to sha256_compress_rounds m sin 31 (via GSYM of  *)
(* a partial unfold from 31 down to 16, with the message-schedule words memoed  *)
(* over the abstract block m) and collapsing the base [EL 0 sin16;..] = sin16   *)
(* (EL8_RECONSTRUCT, needing LENGTH sin = 8).  The seam is O(1) in the round    *)
(* count, so the inner-loop iteration composes x3 with no term explosion.       *)
(* All helpers are locally scoped; only SHA256_BLOCK_NOHW_BODY15_ABS escapes.   *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_BODY15_ABS =
  (* schedule memo over abstract m (EL t m at the base, no length hyp). *)
  let tt_tm = `t:num` in
  let msched_pat = `sha256_msg_schedule m t` in
  let instM t = vsubst [mk_small_numeral t,tt_tm] msched_pat in
  let schedM = Array.make 64 TRUTH in
  (for t = 0 to 15 do
     schedM.(t) <-
       CONV_RULE(RAND_CONV(RATOR_CONV(RATOR_CONV(RAND_CONV NUM_LT_CONV)) THENC
                           REWRITE_CONV[COND_CLAUSES] THENC
                           TRY_CONV(LAND_CONV NUM_RED_CONV)))
         (REWR_CONV sha256_msg_schedule (instM t))
   done;
   for t = 16 to 31 do
     schedM.(t) <-
       CONV_RULE(RAND_CONV(DEPTH_CONV NUM_RED_CONV THENC
           REWRITE_CONV[schedM.(t-2); schedM.(t-7); schedM.(t-15); schedM.(t-16)]))
         (REWR_CONV sha256_msg_schedule (instM t))
   done);
  (* post-state fold: compress_rounds m sin 31 = sha256_round^15            *)
  (*   (compress_rounds m sin 16) (EL 16 c)(sched 16) .. (EL 30 c)(sched 30) *)
  let body15_fold_m = prove
   (mk_eq(`sha256_compress_rounds m sin 31`,
          rhs(concl(
            (COMPRESS_ROUNDS_DOWNTO 16 THENC
             REWRITE_CONV(map (fun t -> schedM.(t)) (16--30)))
            `sha256_compress_rounds m sin 31`))),
    CONV_TAC(LAND_CONV(COMPRESS_ROUNDS_DOWNTO 16 THENC
                       REWRITE_CONV(map (fun t -> schedM.(t)) (16--30)))) THEN
    REFL_TAC) in
  (* [EL 0 sin16;..;EL 7 sin16] = sin16, under LENGTH sin = 8. *)
  let sin16_len = prove
   (`LENGTH (sin:int32 list) = 8
       ==> [EL 0 (sha256_compress_rounds m sin 16);
            EL 1 (sha256_compress_rounds m sin 16);
            EL 2 (sha256_compress_rounds m sin 16);
            EL 3 (sha256_compress_rounds m sin 16);
            EL 4 (sha256_compress_rounds m sin 16);
            EL 5 (sha256_compress_rounds m sin 16);
            EL 6 (sha256_compress_rounds m sin 16);
            EL 7 (sha256_compress_rounds m sin 16)]
           = sha256_compress_rounds m sin 16`,
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA256_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  (* instantiate BODY15 (43 binders: pc K256 kbase stackptr a..h v0..v15 k16..k30). *)
  let inst_args =
    [`pc:num`; `kdat:num`; `kbase:int64`; `stackptr:int64`] @
    (map (fun j -> vsubst [mk_small_numeral j,`j:num`]
                    `EL j (sha256_compress_rounds m sin 16):int32`) (0--7)) @
    (map (fun j -> vsubst [mk_small_numeral j,`j:num`] `EL j (m:int32 list):int32`) (0--15)) @
    (map (fun t -> vsubst [mk_small_numeral t,`t:num`]
                    `EL t sha256_constants:int32`) (16--30)) in
  let body15_inst = SPECL inst_args SHA256_BLOCK_NOHW_BODY15 in
  let th0 = DISCH `LENGTH (sin:int32 list) = 8` body15_inst in
  GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sin16_len; GSYM body15_fold_m]
    (UNDISCH th0)));;

(* ------------------------------------------------------------------------- *)
(* Phase 8 - ROUND31: the 16th (last) rounds_16_xx sub-round, the one BODY15  *)
(* deliberately omits because its deferred Sigma0 fold sits PAST the back-edge *)
(* jne.  This is the per-iteration "tail" after BODY15: pc+4205 (BODY15 exit)  *)
(* -> pc+4345 (just before the sentinel cmpb $0,3(%rbp)), 42 instructions.     *)
(*                                                                            *)
(* Round 31 is ODD (sigma1 scratch in RDI, Maj carry-in in R15) and its       *)
(* register roles are C[(j+1) mod 8]: a in RBX, b in RCX, c in RDX, d in R8,   *)
(* e in R9, f in R10, g in R11, h in RAX.  It reads ring slot 8 (= W24) and    *)
(* slot 15 (= v15, not yet rewritten), sigma0 src W16 from R12/R13, sigma1 src *)
(* W29 from RDI, and K31 from (%rbp).  W31 = sigma1(W29)+W24+sigma0(W16)+v15    *)
(* is stored back to ring slot 15 (rsp+60).                                    *)
(*                                                                            *)
(* The exit (pc+4345) is a SPLIT state: the round-32-canonical registers hold  *)
(* EL 1..7 of (sha256_round st31 ...) directly, R8 = EL 4 (clean new-e), but   *)
(* RAX = EL 0 (...) - Sigma0(a) (the deferred-fold: the asm has added        *)
(* T1+Maj but not yet the +Sigma0), with R14 = Sigma0(a) waiting to be folded  *)
(* by the next iteration's prologue (or the add-back region on loop exit).     *)
(* We stop before the sentinel cmpb so this is a clean ARITHMETIC seam; the    *)
(* sentinel/jne control flow is handled at composition time (Phase 8 STEP 3),  *)
(* where kbase relates to K256 and the tested bytes are concrete.              *)
(* Closer identical to BODY1/BODY15 (42 steps instead of 47).                  *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_ROUND31 = prove
 (`!pc kk kb stackptr a b c d e f g h w16 w24 w29 w15 k31.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kb:int64,4)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 4205) /\
            read RBP s = kb /\ read RSP s = stackptr /\
            read R12 s = word_zx (w16:int32) /\
            read R13 s = word_zx (word_ror (w16:int32) 11) /\
            read RDI s = word_zx (w29:int32) /\
            read R15 s = word_zx (word_xor (b:int32) (c:int32)) /\
            read (memory :> bytes32 kb) s = (k31:int32) /\
            read (memory :> bytes32 (word_add stackptr (word 32))) s = w24 /\
            read (memory :> bytes32 (word_add stackptr (word 60))) s = w15 /\
            read RBX s = word_zx (a:int32) /\ read RCX s = word_zx (b:int32) /\
            read RDX s = word_zx (c:int32) /\ read R8  s = word_zx (d:int32) /\
            read R9  s = word_zx (e:int32) /\ read R10 s = word_zx (f:int32) /\
            read R11 s = word_zx (g:int32) /\ read RAX s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 4345) /\
            read RBP s = word_add kb (word 20) /\
            read RSP s = stackptr /\
            read RBX s = word_zx (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read RCX s = word_zx (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read RDX s = word_zx (EL 3 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R8  s = word_zx (EL 4 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R9  s = word_zx (EL 5 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R10 s = word_zx (EL 6 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R11 s = word_zx (EL 7 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read RAX s = word_zx (word_sub (EL 0 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) (sha_hash_sigma_0 a)) /\
            read R14 s = word_zx (sha_hash_sigma_0 a) /\
            read (memory :> bytes32 (word_add stackptr (word 60))) s =
              word_add (word_add (sha_msg_sigma_1 w29) w24)
                       (word_add (sha_msg_sigma_0 w16) w15))
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 60))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--42) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
              SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - ROUND31 with the carried scratch the loop chain needs.    *)
(*                                                                           *)
(* Same ensures as SHA256_BLOCK_NOHW_ROUND31 (pc+4205 -> pc+4345) but with    *)
(* the post strengthened (purely additively) to expose the state the next     *)
(* loop iteration's pc+1786 PRE consumes and ROUND31 leaves untouched:        *)
(*   - RDI = word_xor a b : the Maj a^b carry threaded into the next round    *)
(*     (ROUND31 recomputes RDI, so this is its EXIT value, not w29 carried).  *)
(*   - the W-ring slots at stackptr+4 (v1) and stackptr+56 (v14): ROUND31's    *)
(*     memory MAYCHANGE is only slot 60, so 4 and 56 ride through unchanged.   *)
(* These feed the continue-edge SHA256_BLOCK_NOHW_LOOPEDGE_CONT (which reads   *)
(* slots 4/56 for the next round's R12/R13/R15 scratch) and the next BODY15.   *)
(* NB the loop sentinel byte is NOT carried here: at kb+23 it lies outside     *)
(* the `nonoverlapping (stackptr,64)(kb,4)` hyp, so the stepper discards it    *)
(* across the slot-60 write.  The chain supplies it independently from the     *)
(* whole-rodata bytelist precondition via SHA256_SENTINEL_BYTES.              *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_ROUND31_S = prove
 (`!pc kk kb stackptr a b c d e f g h w16 w24 w29 w15 k31 v1 v14.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (kb:int64,4)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 4205) /\
            read RBP s = kb /\ read RSP s = stackptr /\
            read R12 s = word_zx (w16:int32) /\
            read R13 s = word_zx (word_ror (w16:int32) 11) /\
            read RDI s = word_zx (w29:int32) /\
            read R15 s = word_zx (word_xor (b:int32) (c:int32)) /\
            read (memory :> bytes32 kb) s = (k31:int32) /\
            read (memory :> bytes32 (word_add stackptr (word 32))) s = w24 /\
            read (memory :> bytes32 (word_add stackptr (word 60))) s = w15 /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = (v1:int32) /\
            read (memory :> bytes32 (word_add stackptr (word 56))) s = (v14:int32) /\
            read RBX s = word_zx (a:int32) /\ read RCX s = word_zx (b:int32) /\
            read RDX s = word_zx (c:int32) /\ read R8  s = word_zx (d:int32) /\
            read R9  s = word_zx (e:int32) /\ read R10 s = word_zx (f:int32) /\
            read R11 s = word_zx (g:int32) /\ read RAX s = word_zx (h:int32))
       (\s. read RIP s = word (pc + 4345) /\
            read RBP s = word_add kb (word 20) /\
            read RSP s = stackptr /\
            read RDI s = word_zx (word_xor (a:int32) (b:int32)) /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = v1 /\
            read (memory :> bytes32 (word_add stackptr (word 56))) s = v14 /\
            read RBX s = word_zx (EL 1 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read RCX s = word_zx (EL 2 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read RDX s = word_zx (EL 3 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R8  s = word_zx (EL 4 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R9  s = word_zx (EL 5 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R10 s = word_zx (EL 6 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R11 s = word_zx (EL 7 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) /\
            read R14 s = word_zx (sha_hash_sigma_0 a) /\
            read RAX s = word_zx (word_sub (EL 0 (sha256_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha_msg_sigma_1 w29) w24)
                        (word_add (sha_msg_sigma_0 w16) w15)))) (sha_hash_sigma_0 a)) /\
            read (memory :> bytes32 (word_add stackptr (word 60))) s =
              word_add (word_add (sha_msg_sigma_1 w29) w24)
                       (word_add (sha_msg_sigma_0 w16) w15))
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 (word_add stackptr (word 60))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--42) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
              SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - ROUND31_S restated over the OPAQUE compress_rounds state. *)
(*                                                                           *)
(* The abstract-m form of SHA256_BLOCK_NOHW_ROUND31_S: the 16th sub-round    *)
(* (round 31) of one rounds_16_xx iteration, restated so its pre/post working *)
(* state is sha256_compress_rounds m sin {31,32} rather than the explicit     *)
(* nested sha256_round term, and its message words are sha256_msg_schedule m  *)
(* {16,24,29,15} for the ITERATION-0 ring (EL j m at the schedule base).      *)
(* Same programmatic derivation as BODY15_ABS, but folds a SINGLE round       *)
(* (31->32).  The deliberate SPLIT exit is preserved verbatim:                *)
(*   RAX = EL 0 (cr m sin 32) - Sigma0 (EL 0 (cr m sin 31)),                  *)
(*   R14 = Sigma0 (EL 0 (cr m sin 31))                                        *)
(* (the next iteration's prologue folds R14 into RAX to recover EL 0 cr 32).  *)
(* The v1/v14 ring slots and RDI = a^b carry ride through unchanged, exactly  *)
(* as in ROUND31_S, feeding LOOPEDGE_CONT and the next BODY15.                *)
(* DERIVED from ROUND31_S by instantiating a..h := EL j (cr m sin 31),        *)
(* w16/w24/w29/w15 := the reduced sigma-trees sched {16,24,29,15}, k31 :=     *)
(* EL 31 sha256_constants, then folding (GSYM sched 31 + GSYM the 31->32      *)
(* unfold).  All helpers are locally scoped.                                  *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_ROUND31_S_ABS =
  (* schedule memo over abstract m (EL t m at the base, no length hyp). *)
  let tt_tm = `t:num` in
  let msched_pat = `sha256_msg_schedule m t` in
  let instM t = vsubst [mk_small_numeral t,tt_tm] msched_pat in
  let schedM = Array.make 64 TRUTH in
  (for t = 0 to 15 do
     schedM.(t) <-
       CONV_RULE(RAND_CONV(RATOR_CONV(RATOR_CONV(RAND_CONV NUM_LT_CONV)) THENC
                           REWRITE_CONV[COND_CLAUSES] THENC
                           TRY_CONV(LAND_CONV NUM_RED_CONV)))
         (REWR_CONV sha256_msg_schedule (instM t))
   done;
   for t = 16 to 31 do
     schedM.(t) <-
       CONV_RULE(RAND_CONV(DEPTH_CONV NUM_RED_CONV THENC
           REWRITE_CONV[schedM.(t-2); schedM.(t-7); schedM.(t-15); schedM.(t-16)]))
         (REWR_CONV sha256_msg_schedule (instM t))
   done);
  (* single-round fold: cr m sin 32 = sha256_round (cr m sin 31)(EL 31 c)(sched 31). *)
  let round31_fold_m = (COMPRESS_ROUNDS_DOWNTO 31) `sha256_compress_rounds m sin 32` in
  (* [EL 0 sin31;..;EL 7 sin31] = sin31, under LENGTH sin = 8. *)
  let sin31_len = prove
   (`LENGTH (sin:int32 list) = 8
       ==> [EL 0 (sha256_compress_rounds m sin 31);
            EL 1 (sha256_compress_rounds m sin 31);
            EL 2 (sha256_compress_rounds m sin 31);
            EL 3 (sha256_compress_rounds m sin 31);
            EL 4 (sha256_compress_rounds m sin 31);
            EL 5 (sha256_compress_rounds m sin 31);
            EL 6 (sha256_compress_rounds m sin 31);
            EL 7 (sha256_compress_rounds m sin 31)]
           = sha256_compress_rounds m sin 31`,
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA256_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  (* instantiate ROUND31_S (19 binders: pc kk kb stackptr a..h                *)
  (*   w16 w24 w29 w15 k31 v1 v14).                                           *)
  let inst_args =
    [`pc:num`; `kdat:num`; `kb:int64`; `stackptr:int64`] @
    (map (fun j -> vsubst [mk_small_numeral j,`j:num`]
                    `EL j (sha256_compress_rounds m sin 31):int32`) (0--7)) @
    [ rhs(concl schedM.(16)); rhs(concl schedM.(24));
      rhs(concl schedM.(29)); rhs(concl schedM.(15));
      `EL 31 sha256_constants:int32`; `v1:int32`; `v14:int32` ] in
  let r31s_inst = SPECL inst_args SHA256_BLOCK_NOHW_ROUND31_S in
  let th0 = DISCH `LENGTH (sin:int32 list) = 8` r31s_inst in
  GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sin31_len; GSYM schedM.(31); GSYM round31_fold_m]
    (UNDISCH th0)));;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - per-iteration ABS generators for the x3 inner-loop chain. *)
(*                                                                           *)
(* The inner loop runs exactly 3 times (i = 0,1,2).  Each iteration is        *)
(* BODY15 (15 clean sub-rounds) then ROUND31_S (the 16th, SPLIT exit).  The   *)
(* iterations are NOT identical: iteration i consumes the W-ring holding      *)
(* sched m (16i+j) (j=0..15) and produces sched m (16i+16+j), while the       *)
(* working state advances cr m sin (16+16i) -> cr m sin (32+16i).  Because    *)
(* the implementation's message-schedule sigma-expansion is SHIFT-INVARIANT,  *)
(* the committed BODY15 / ROUND31_S (stated over free ring vars vj and free   *)
(* working a..h) restate to iteration i by instantiating vj := sched m        *)
(* (16i+j) and a..h := EL j (cr m sin (16+16i)), then folding.                *)
(*                                                                           *)
(* These generators produce, for a literal iteration index i, the abstract    *)
(* iteration-i body / round-31 lemmas with O(1)-sized opaque-schedule seams   *)
(* (validated session-023: clean bodies ~8.7K chars, round31s ~9.8K chars,    *)
(* FLAT across i -- the pure-unroll route was 940K growing 16x/iter).  The    *)
(* i=0 instances coincide (up to the EL j m <-> sched m j leaf naming) with   *)
(* SHA256_BLOCK_NOHW_BODY15_ABS / ROUND31_S_ABS above; the clean form keeps    *)
(* every ring leaf as the opaque atom sched m (16i+j) so consecutive          *)
(* iterations seam by construction (body i POST ring = sched m (16i+16..30+16i)*)
(* = body (i+1) PRE ring = sched m (16(i+1)..14+16(i+1))).                     *)
(*                                                                           *)
(* Shared term builders (literal-index instantiation, avoiding hand-typed     *)
(* (int32)list annotations which the term parser rejects):                    *)
let abs_cr_tm n =       (* sha256_compress_rounds m sin <n> *)
  vsubst [mk_small_numeral n,`n:num`] `sha256_compress_rounds m sin n`;;
let abs_el_cr j n =     (* EL <j> (sha256_compress_rounds m sin <n>) : int32 *)
  vsubst [mk_small_numeral j,`j:num`; mk_small_numeral n,`n:num`]
    `EL j (sha256_compress_rounds m sin n):int32`;;
let abs_el_k t =        (* EL <t> sha256_constants : int32 *)
  vsubst [mk_small_numeral t,`t:num`] `EL t sha256_constants:int32`;;
let abs_instM t =       (* sha256_msg_schedule m <t> *)
  vsubst [mk_small_numeral t,`t:num`] `sha256_msg_schedule m t`;;

(* shifted-window schedule memo: leaves [rb,rb+15] opaque (REFL), expand      *)
(* [rb+16,hi] via the recurrence (literal indices -> NUM_RED_CONV).           *)
let abs_build_schedM rb hi =
  let memo = Array.make (hi+1) TRUTH in
  for t = rb to min hi (rb+15) do memo.(t) <- REFL (abs_instM t) done;
  for t = rb+16 to hi do
    memo.(t) <-
      CONV_RULE(RAND_CONV(DEPTH_CONV NUM_RED_CONV THENC
          REWRITE_CONV[memo.(t-2); memo.(t-7); memo.(t-15); memo.(t-16)]))
        (REWR_CONV sha256_msg_schedule (abs_instM t));
  done;
  memo;;

(* MK_BODY15_ABS i : BODY15 for inner-loop iteration i, W-ring stores folded   *)
(* to opaque sched m (16i+16+j) (clean form, ~8.7K chars).                     *)
let MK_BODY15_ABS i =
  let rb = 16*i and wb = 16+16*i in
  let schedM = abs_build_schedM rb (wb+14) in
  let foldeq = prove
   (mk_eq(abs_cr_tm (wb+15),
          rhs(concl((COMPRESS_ROUNDS_DOWNTO wb THENC
                     REWRITE_CONV(map (fun t -> schedM.(t)) (wb--(wb+14))))
                    (abs_cr_tm (wb+15))))),
    CONV_TAC(LAND_CONV(COMPRESS_ROUNDS_DOWNTO wb THENC
                       REWRITE_CONV(map (fun t -> schedM.(t)) (wb--(wb+14))))) THEN
    REFL_TAC) in
  let sinwb = abs_cr_tm wb in
  let sinwb_len = prove
   (mk_imp(`LENGTH (sin:int32 list) = 8`,
           mk_eq(mk_list(map (fun j -> abs_el_cr j wb) (0--7),`:int32`), sinwb)),
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA256_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  let inst_args =
    [`pc:num`; `kdat:num`; `kbase:int64`; `stackptr:int64`] @
    (map (fun j -> abs_el_cr j wb) (0--7)) @
    (map (fun j -> abs_instM (rb+j)) (0--15)) @
    (map (fun t -> abs_el_k (wb+t)) (0--14)) in
  let body15_inst = SPECL inst_args SHA256_BLOCK_NOHW_BODY15 in
  let th0 = DISCH `LENGTH (sin:int32 list) = 8` body15_inst in
  let raw = GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sinwb_len; GSYM foldeq] (UNDISCH th0))) in
  REWRITE_RULE (map (fun t -> GSYM schedM.(t)) ((rb+16)--(wb+14))) raw;;

(* ONE-LEVEL expansion of sched m t : leaves the four sub-scheds m {t-2,t-7,    *)
(* t-15,t-16} OPAQUE (REWR the recurrence, reduce only the index arithmetic +    *)
(* kill the t<16 COND).  Used by MK_ROUND31S_ABS so its PRE references the same  *)
(* opaque sched atoms that MK_BODY15_ABS's POST exposes (atom-for-atom seam).    *)
let abs_one_level t =
  CONV_RULE(RAND_CONV(
      RATOR_CONV(RATOR_CONV(RAND_CONV NUM_RED_CONV)) THENC
      REWRITE_CONV[COND_CLAUSES] THENC
      DEPTH_CONV NUM_RED_CONV))
    (REWR_CONV sha256_msg_schedule (abs_instM t));;

(* MK_ROUND31S_ABS i : ROUND31_S for iteration i (single round 31+16i ->       *)
(* 32+16i, SPLIT exit), ~9.8K chars.  Stores opaque sched m (16i+31).          *)
(*                                                                             *)
(* CRITICAL (session-024): ROUND31_S's message-word binders w16/w24/w29/w15    *)
(* are instantiated with the OPAQUE sched atoms sched m (16i+{16,24,29,15}),   *)
(* NOT the fully-expanded sigma-trees rhs(schedM.(...)).  The expanded form was *)
(* the actual reason the per-iteration BODY15->ROUND31 seam did NOT match by    *)
(* construction (MK_BODY15_ABS POST exposes R12/R13/RDI/slot32 as opaque sched  *)
(* atoms; the expanded PRE would not unify).  The stored W31 (= the four-way    *)
(* sigma sum) then folds to opaque sched m (16i+31) via GSYM the ONE-LEVEL      *)
(* expansion, and the round folds to cr m sin (32+16i) via GSYM the unfold.     *)
let MK_ROUND31S_ABS i =
  let rb = 16*i and wb = 16+16*i in
  let ol = abs_one_level (rb+31) in
  let foldeq = (COMPRESS_ROUNDS_DOWNTO (wb+15)) (abs_cr_tm (wb+16)) in
  let sinwbp15 = abs_cr_tm (wb+15) in
  let sinwbp15_len = prove
   (mk_imp(`LENGTH (sin:int32 list) = 8`,
           mk_eq(mk_list(map (fun j -> abs_el_cr j (wb+15)) (0--7),`:int32`), sinwbp15)),
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA256_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  let inst_args =
    [`pc:num`; `kdat:num`; `kb:int64`; `stackptr:int64`] @
    (map (fun j -> abs_el_cr j (wb+15)) (0--7)) @
    [ abs_instM (rb+16); abs_instM (rb+24); abs_instM (rb+29); abs_instM (rb+15);
      abs_el_k (wb+15); `v1:int32`; `v14:int32` ] in
  let r31s_inst = SPECL inst_args SHA256_BLOCK_NOHW_ROUND31_S in
  let th0 = DISCH `LENGTH (sin:int32 list) = 8` r31s_inst in
  GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sinwbp15_len; GSYM ol; GSYM foldeq]
    (UNDISCH th0)));;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - the loop PROLOGUE-FOLD segment pc+1766 -> pc+1786.        *)
(*                                                                           *)
(* This is the 5-instruction transition the inner-loop back-edge `jne` lands  *)
(* on (orig 0x6ea..0x6fe): it reconciles ROUND31's deferred-Sigma0 SPLIT      *)
(* state and reloads the next sub-round's sigma scratch.  No branch, no       *)
(* memory compare, so it steps directly.                                      *)
(*   pc+1766 mov 0x4(%rsp),%r13d   R13 := ring slot 1  (next sub-round v1)    *)
(*   pc+1771 mov 0x38(%rsp),%r15d  R15 := ring slot 14 (next sub-round v14)   *)
(*   pc+1776 mov %r13d,%r12d       R12 := slot 1                              *)
(*   pc+1779 ror $0xb,%r13d        R13 := ror(slot1,11)                       *)
(*   pc+1783 add %r14d,%eax        RAX := rax_in + r14_in  (THE Sigma0 fold:  *)
(*                                  ROUND31 exits RAX = EL0 - Sigma0(a) and    *)
(*                                  R14 = Sigma0(a); this add restores EL0.)   *)
(* -> pc+1786 (next round's `mov %r15d,%r14d`, NOT executed here).            *)
(*                                                                           *)
(* The post pins exactly the round-entry scratch convention at the clean      *)
(* pc+1786 point (R12=slot1, R13=ror(slot1,11), R15=slot14, RAX=folded).      *)
(* RBP/RSP ride through unchanged.  Verified cheat-free (PROLOGUE_016_PASS).  *)
(* It composes AFTER the sentinel cmpb+jne to form one loop continue edge     *)
(* (the cmpb/jne stepping is the open STEP-3 blocker - see the BODY15_ROUND31 *)
(* comment below and the session-016 summary).                               *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_PROLOGUE = prove
 (`!pc kk stackptr rbp_val r1 r14v rax_in r14_in.
     nonoverlapping (word pc,4465) (stackptr:int64,64)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 1766) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read RAX s = word_zx (rax_in:int32) /\
            read R14 s = word_zx (r14_in:int32) /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = (r1:int32) /\
            read (memory :> bytes32 (word_add stackptr (word 56))) s = (r14v:int32))
       (\s. read RIP s = word (pc + 1786) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read R12 s = word_zx (r1:int32) /\
            read R13 s = word_zx (word_ror (r1:int32) 11) /\
            read R15 s = word_zx (r14v:int32) /\
            read RAX s = word_zx (word_add (rax_in:int32) r14_in))
       (MAYCHANGE [RIP;RAX;R12;R13;R15] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--5) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ========================================================================= *)
(* cmpb (:8 memory-operand CMP) stepper augmentation -- route (a), in-file.  *)
(* X86_OPERATION_CLAUSES (x86.ml:4718) carries x86_CMP only at :64 (CMP_ALT)  *)
(* and :32 (INST_TYPE); the loop sentinel `cmpb $0,3(%rbp)` runs x86_CMP at   *)
(* :8, which never unfolds, so the flag writes stay non-ground and            *)
(* EXISTS_NONTRIVIAL_CONV fails.  Build the :8 clause the way x86.ml builds    *)
(* the others, append it to a local clause list, and re-evaluate the stepper  *)
(* chain VERBATIM from x86.ml under _C8 names so they close over the           *)
(* augmented list.  The :8 clause matches ONLY byte cmps, so X86_STEPS_C8_TAC  *)
(* is identical to X86_STEPS_TAC on every other instruction; it is used only  *)
(* by the loop-edge lemmas below.                                             *)
(*                                                                           *)
(* IMPORTANT: build WITHOUT the REWRITE_RULE[WORD_ZX_TRIVIAL] step that the    *)
(* generic x86.ml pipeline uses.  At :8 the parity flag's `word_zx (z:byte)`   *)
(* is a TRIVIAL :8->:8 zero-extension, so WORD_ZX_TRIVIAL would strip it to    *)
(* `word_evenparity (word_sub ...)`; that bare form makes X86_CONV's downstream *)
(* conversions diverge (stack overflow).  Keeping the `word_zx` wrapper makes  *)
(* the clause structurally identical to the proven-good :32 clause (where      *)
(* :32->:8 is non-trivial, so the wrapper survives there too).                *)
(* ------------------------------------------------------------------------- *)

let X86_CMP_8_CLAUSE =
  (CONV_RULE (TOP_DEPTH_CONV WORD_SIMPLE_SUBWORD_CONV) o
   CONV_RULE(TOP_DEPTH_CONV let_CONV) o SPEC_ALL)
  (INST_TYPE[`:8`,`:N`] x86_CMP);;

let X86_OPERATION_CLAUSES_C8 = X86_OPERATION_CLAUSES @ [X86_CMP_8_CLAUSE];;

let X86_CONV_C8 (decode_ths:thm option array) ths tm =
  (* Find `read RIP .. = ..` from ths (assumptions). *)
  let pc_th = try find
    (fun th ->
      let c = concl th in
      is_eq c && is_read_rip (fst (dest_eq c)))
    ths with _ ->
      failwith "X86_CONV_C8: can't find `read RIP .. = ..` from ths" in

  (* Find `bytes_loaded ..`. *)
  let bytes_loaded_mc_ths:thm list =
    (* Pick the _mc const from decode_ths, if decode_ths[0] != None, which is
       likely to be true. *)
    let the_mc:term option = Option.bind decode_ths.(0)
      (fun th ->
        (* th is `forall .., bytes_loaded ... _mc ==> x86_decode ..`. *)
        let t = concl th in
        let bytes_loaded_term = fst (dest_imp (snd (strip_forall t))) in
        let the_mc = last (snd (strip_comb bytes_loaded_term)) in
        (* if _mc contains relocations, the_mc is `.._mc args`. In this
           case, return None. *)
        if is_const the_mc then Some the_mc else None) in
    let bytes_loaded_tm = `bytes_loaded` in
    let res = filter (fun th ->
        let cc = concl th in is_comb cc && (
        let c,args = strip_comb (concl th) in
        c = bytes_loaded_tm &&
          (the_mc = None || last args = Option.get the_mc)))
      ths in
    if res = [] then failwith
        ("X86_CONV_C8: can't find `bytes_loaded .. .. " ^
          (if the_mc <> None then string_of_term (Option.get the_mc) else "..")
          ^ "` from ths")
    else res in

  let eth = tryfind (fun loaded_mc_th ->
      GEN_REWRITE_CONV I [X86_THM decode_ths loaded_mc_th pc_th] tm)
    bytes_loaded_mc_ths in
  (* Pick the right rules. It will be a singleton in most cases... *)
  let x86_execute_case_rules:thm list =
    let ts = find_terms is_const (concl eth) in
    List.filter_map (fun t ->
      try Some ((assoc (name_of t) X86_EXECUTE_CASES)) with _ -> None) ts in
  (K eth THENC
   PURE_ONCE_REWRITE_CONV(x86_execute_case_rules) THENC
   REWRITE_CONV[add_store_event;add_load_event;SEQ_ID] THENC
   ONCE_DEPTH_CONV OPERAND_SIZE_CONV THENC
   REWRITE_CONV[condition_semantics; aligned_OPERAND128; aligned_OPERAND256] THENC
   REWRITE_CONV[OPERAND_SIZE_CASES] THENC
   REWRITE_CONV[OPERAND_CLAUSES] THENC
   ONCE_DEPTH_CONV BSID_SEMANTICS_CONV THENC
   REWRITE_CONV X86_OPERATION_CLAUSES_C8 THENC
   REWRITE_CONV[READ_RVALUE;
                ASSIGN_ZEROTOP_32; READ_ZEROTOP_32; WRITE_ZEROTOP_32;
                ASSIGN_ZEROTOP_128; READ_ZEROTOP_128; WRITE_ZEROTOP_128;
                READ_BOTTOM_128] THENC
   DEPTH_CONV WORD_NUM_RED_CONV THENC
   REWRITE_CONV[SEQ; condition_semantics] THENC
   REWRITE_CONV[bytesize] THENC (* bytesize in add_{load,store}_event *)
   GEN_REWRITE_CONV TOP_DEPTH_CONV
    [UNDEFINED_VALUE; UNDEFINED_VALUES; SEQ_ID] THENC
   GEN_REWRITE_CONV TOP_DEPTH_CONV
    [ASSIGNS_PULL_ZEROTOP_THM; ASSIGNS_PULL_THM] THENC
   REWRITE_CONV[ASSIGNS_THM] THENC
   GEN_REWRITE_CONV TOP_DEPTH_CONV [SEQ_PULL_THM; BETA_THM] THENC
   GEN_REWRITE_CONV TOP_DEPTH_CONV[assign; seq; UNWIND_THM1; BETA_THM] THENC
   TRY_CONV(REWRITE_CONV[WRITE_BOTTOM_128]) THENC
   TRY_CONV(REWRITE_CONV READ_YMM_SSE_EQUIV) THENC
   REWRITE_CONV[] THENC REWRITE_CONV[WRITE_SHORT; READ_SHORT] THENC
   TOP_DEPTH_CONV COMPONENT_READ_OVER_WRITE_CONV THENC
   X86_FORCE_CONDITIONAL_CONV ths THENC
   ONCE_DEPTH_CONV
    (GEN_REWRITE_CONV I [GSYM WORD_ADD] THENC
     GEN_REWRITE_CONV (RAND_CONV o TOP_DEPTH_CONV) [GSYM ADD_ASSOC] THENC
     RAND_CONV NUM_REDUCE_CONV) THENC
   TOP_DEPTH_CONV COMPONENT_WRITE_OVER_WRITE_CONV THENC
   GEN_REWRITE_CONV (SUB_COMPONENTS_CONV o TOP_DEPTH_CONV) ths THENC
   GEN_REWRITE_CONV TOP_DEPTH_CONV [WORD_VAL] THENC
   ONCE_DEPTH_CONV WORD_PC_PLUS_CONV THENC
   DEPTH_CONV WORD_NUM_RED_CONV THENC
   ONCE_DEPTH_CONV NORMALIZE_RELATIVE_ADDRESS_CONV
 ) tm;;
let X86_BASIC_STEP_C8_TAC =
  let x86_tm = `x86` and x86_ty = `:x86state` and one = `1:num` in
  fun (decode_ths: thm option array) sname store_inst_term_to (asl,w) ->
    let sv = rand w and sv' = mk_var(sname,x86_ty) in
    let atm = mk_comb(mk_comb(x86_tm,sv),sv') in
    let eth = X86_CONV_C8 decode_ths (map snd asl) atm in

    (* store the decoded instruction at store_inst_term_to *)
    (match store_inst_term_to with
     | Some r -> r := rhs (concl eth)
     | None -> ());

    (* prepare a tactic for progressing to a next step. *)
    let progress_tac =
      let c,_ = strip_comb w in
      if name_of c = "eventually" then
        GEN_REWRITE_TAC I [eventually_CASES] THEN DISJ2_TAC
      else if name_of c = "eventually_n" then
        let stepn = dest_numeral(rand(rator(rator w))) in
        let stepn_decr = stepn -/ num 1 in
        (* stepn = 1+{stepn-1}*)
        let stepn_thm = GSYM (NUM_ADD_CONV
          (mk_binary "+" (one,mk_numeral(stepn_decr)))) in
        GEN_REWRITE_TAC (RATOR_CONV o RATOR_CONV o RAND_CONV) [stepn_thm] THEN
        GEN_REWRITE_TAC I [EVENTUALLY_N_STEP]
      else failwith "X86_BASIC_STEP_C8_TAC: neither eventually nor eventually_n"
      in

    (progress_tac THEN CONJ_TAC THENL
     [GEN_REWRITE_TAC BINDER_CONV [eth] THEN
      (CONV_TAC EXISTS_NONTRIVIAL_CONV ORELSE
        (PRINT_GOAL_TAC THEN
        FAIL_TAC ("X86_BASIC_STEP_C8_TAC: Equality between two states is " ^
                  "ill-formed. Did you forget to assume an extra condition" ^
                  " like pointer alignment?")));
      X_GEN_TAC sv' THEN GEN_REWRITE_TAC LAND_CONV [eth] THEN
      REPEAT X86_UNDEFINED_CHOOSE_TAC]) (asl,w);;
let X86_STEP_C8_TAC (mc_length_th,decode_ths) subths sname
      (store_inst_term_to: term ref option)
      (strip_component_tac: thm_tactic) =
  (*** This does the basic decoding setup ***)

  X86_BASIC_STEP_C8_TAC decode_ths sname store_inst_term_to THEN

  (*** This part shows the code isn't self-modifying ***)

  NONSELFMODIFYING_STATE_UPDATE_TAC
    (MATCH_MP bytes_loaded_update mc_length_th) THEN

  (*** Attempt also to show subroutines aren't modified, if applicable ***)

  MAP_EVERY (TRY o NONSELFMODIFYING_STATE_UPDATE_TAC o
    MATCH_MP bytes_loaded_update o CONJUNCT1) subths THEN

  (*** This part produces any updated versions of existing asms ***)

  ASSUMPTION_STATE_UPDATE_TAC THEN

  (*** Produce updated "MAYCHANGE" assumption ***)

  MAYCHANGE_STATE_UPDATE_TAC THEN

  (*** This adds state component theorems for the updates ***)
  (*** Could also assume th itself but I throw it away   ***)

  DISCH_THEN(fun th ->
    let thl = STATE_UPDATE_NEW_RULE th in
    if thl = [] then ALL_TAC else
    MP_TAC(end_itlist CONJ thl) THEN
    ASSEMBLER_SIMPLIFY_TAC THEN
    strip_component_tac th);;
let X86_VERBOSE_STEP_C8_TAC (exth1,exth2) sname g =
  Format.print_string("Stepping to state "^sname); Format.print_newline();
  X86_STEP_C8_TAC (exth1,exth2) [] sname None (K STRIP_TAC) g;;
let X86_SINGLE_STEP_C8_TAC th s =
  time (X86_VERBOSE_STEP_C8_TAC th s) THEN
  DISCARD_OLDSTATE_TAC s THEN
  CLARIFY_TAC;;
let X86_STEPS_C8_TAC th snums =
  MAP_EVERY (X86_SINGLE_STEP_C8_TAC th) (statenames "s" snums);;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - the two inner-loop edges at the sentinel cmpb (pc+4345).  *)
(*                                                                           *)
(* ROUND31 exits at pc+4345, the loop sentinel:                              *)
(*   pc+4345  cmpb $0,3(%rbp)   compare the rodata sentinel byte K256+3 ahead *)
(*   pc+4349  jne  <pc+1766>    continue the inner loop iff that byte != 0    *)
(* The byte is read from the doubled-K table walked by RBP; SHA256_SENTINEL_  *)
(* BYTES proves it is 0x27 (iter 0), 0x19 (iter 1) -> continue, then 0x00     *)
(* (iter 2) -> exit.  We model the sentinel byte abstractly here (sb, or      *)
(* word 0 for the exit edge); the chain instantiates it from SENTINEL_BYTES.  *)
(*                                                                           *)
(* CONTINUE edge (sb<>0): cmpb+jne lands at pc+1766; we then reuse the proven *)
(* 5-instruction PROLOGUE fold to reach the clean pc+1786 round-entry state.  *)
(* So this edge is pc+4345 -> pc+1786 in 7 steps (cmpb, jne, then prologue).  *)
(* EXIT edge (sb=word 0): jne not taken, falls through to pc+4355 (the start  *)
(* of the loop-exit deferred-Sigma0 fold + add-back, a Phase-9 concern).      *)
(*                                                                           *)
(* Both step the byte compare with X86_STEPS_C8_TAC (the cmpb needs the :8    *)
(* CMP clause above).  After cmpb+jne the PC is a conditional                 *)
(*   if ~(val(word_sub sb (word 0)) = 0) then word(pc+1766) else word(pc+4355)*)
(* which we collapse with WORD_SUB_0 + VAL_EQ_0 and the sb hypothesis before  *)
(* the stepper resolves the next instruction.                                 *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_LOOPEDGE_CONT = prove
 (`!pc kk stackptr rbp_val r1 r14v rax_in r14_in sb.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (word pc,4465) (rbp_val:int64,4) /\
     ~(sb = word 0)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 4345) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read RAX s = word_zx (rax_in:int32) /\
            read R14 s = word_zx (r14_in:int32) /\
            read (memory :> bytes8 (word_add rbp_val (word 3))) s = (sb:byte) /\
            read (memory :> bytes32 (word_add stackptr (word 4))) s = (r1:int32) /\
            read (memory :> bytes32 (word_add stackptr (word 56))) s = (r14v:int32))
       (\s. read RIP s = word (pc + 1786) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read R12 s = word_zx (r1:int32) /\
            read R13 s = word_zx (word_ror (r1:int32) 11) /\
            read R15 s = word_zx (r14v:int32) /\
            read RAX s = word_zx (word_add (rax_in:int32) r14_in))
       (MAYCHANGE [RIP;RAX;R12;R13;R15] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_C8_TAC SHA256_COMPRESS_EXEC (1--2) THEN
  RULE_ASSUM_TAC(REWRITE_RULE[WORD_SUB_0; VAL_EQ_0]) THEN
  FIRST_X_ASSUM(fun th ->
    if can (term_match [] `read RIP s2 = X`) (concl th)
    then ASSUME_TAC(REWRITE_RULE[ASSUME `~(sb:byte = word 0)`] th)
    else NO_TAC) THEN
  X86_STEPS_C8_TAC SHA256_COMPRESS_EXEC (3--7) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

let SHA256_BLOCK_NOHW_LOOPEDGE_EXIT = prove
 (`!pc kk stackptr rbp_val rax_in r14_in.
     nonoverlapping (word pc,4465) (stackptr:int64,64) /\
     nonoverlapping (word pc,4465) (rbp_val:int64,4)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 4345) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read RAX s = word_zx (rax_in:int32) /\
            read R14 s = word_zx (r14_in:int32) /\
            read (memory :> bytes8 (word_add rbp_val (word 3))) s = (word 0:byte))
       (\s. read RIP s = word (pc + 4355) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read RAX s = word_zx (rax_in:int32) /\
            read R14 s = word_zx (r14_in:int32))
       (MAYCHANGE [RIP] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_C8_TAC SHA256_COMPRESS_EXEC (1--2) THEN
  RULE_ASSUM_TAC(REWRITE_RULE[WORD_SUB_0; VAL_EQ_0]) THEN
  FIRST_X_ASSUM(fun th ->
    if can (term_match [] `read RIP s2 = X`) (concl th)
    then ASSUME_TAC(REWRITE_RULE[] th)
    else NO_TAC) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[]);;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - glue BODY15 ; ROUND31 into ONE rounds_16_xx iteration.    *)
(*                                                                           *)
(* The composed ensures runs pc+1786 -> pc+4345 (BODY15's 15 clean sub-rounds *)
(* then ROUND31, the 16th, ending in the intended SPLIT state just before the *)
(* loop sentinel cmpb).  Its statement is ~1.26M chars (BODY15's nested        *)
(* sha256_round terms x ROUND31's), so we build it PROGRAMMATICALLY by term    *)
(* surgery on `concl SHA256_BLOCK_NOHW_BODY15` / `..._ROUND31` rather than     *)
(* hand-typing it.  PRE = BODY15 pre + the carried K read at kbase+108 (= k31, *)
(* which BODY15's post does not expose); POST = ROUND31 post instantiated at   *)
(* the seam (a..h := EL 0..7 of BODY15's 30-round state, ring occupants, etc.) *)
(* FRAME = BODY15 frame ,, ROUND31 frame.                                     *)
(*                                                                           *)
(* The proof is ENSURES_SEQUENCE_TAC at pc+4205 (the BODY15->ROUND31 seam)     *)
(* then a per-leg ENSURES_SUBLEMMA lift of each committed lemma.  TWO subtle   *)
(* points (both diagnosed in session 015):                                    *)
(*  (1) Rodata-prime fix.  ENSURES_SEQUENCE_TAC injects program_decodes as     *)
(*      `\s. bytes_loaded s (word pc) (_tmc pc K256')` - a PRIMED rodata var    *)
(*      (the goal already has K256 free, so the higher-order match renames).   *)
(*      The committed lemmas carry the unprimed K256, so their bytes_loaded    *)
(*      atoms will not unify on the leg.  Fix: INST each committed lemma's      *)
(*      rodata var to the goal's OWN var, read from the goal at tactic time.   *)
(*  (2) Leg-B SUBLEM shape.  After the INST, leg B's leg-1 conjunct            *)
(*      (!s. P s ==> P' s) is alpha-trivial and REWRITE_TAC[] inside the canned *)
(*      ENSURES_SUBLEMMA_TAC auto-closes it; the canned CONJ_TAC THENL then     *)
(*      misaligns (X_GEN_TAC hits the `subsumed` conjunct -> dest_binder).  So  *)
(*      leg B uses a local sublem_b = the canned body MINUS that branch.  Leg A *)
(*      keeps the canned tactic (its PRE has the extra carried-K conjunct, so   *)
(*      leg-1 does NOT auto-close and the 3-conjunct canned path is correct).  *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_BODY15_ROUND31 =
  (* ---- term plumbing on the two committed concls ---- *)
  let strip_ensures th =
    let bod = snd(strip_forall(concl th)) in
    let _,ens = dest_imp bod in
    let l,c = dest_comb ens in
    let l2,q = dest_comb l in
    let _,p = dest_comb l2 in (p,q,c) in
  let conjs_of_lam q = let s,body = dest_abs q in s, conjuncts body in
  let comp_of c = let l,_ = dest_eq c in snd(dest_comb(fst(dest_comb l))) in
  let rhs_of  c = snd(dest_eq c) in
  let comp_str c = try string_of_term (comp_of c) with _ -> "?" in
  let by_comp target lst = find (fun c -> comp_str c = target) lst in
  let (_pB,_qB,cB)  = strip_ensures SHA256_BLOCK_NOHW_BODY15 in
  let (pR,qR,cR)    = strip_ensures SHA256_BLOCK_NOHW_ROUND31 in
  let sB, _qBc      = conjs_of_lam _qB in
  let _,  pBc       = conjs_of_lam _pB in
  let _,  qBc       = conjs_of_lam _qB in
  let bvars = fst(strip_forall(concl SHA256_BLOCK_NOHW_BODY15)) in
  let rvars = fst(strip_forall(concl SHA256_BLOCK_NOHW_ROUND31)) in
  let vbyname vs n = find (fun v -> name_of v = n) vs in
  let rv = vbyname rvars and bv = vbyname bvars in
  (* seam values out of BODY15 post (30-round state, ring occupants) *)
  let st30  = rand(rand(rhs_of(by_comp "RBX" qBc))) in
  let occ0  = rand(rhs_of(by_comp "R12" qBc)) in
  let occ13 = rand(rhs_of(by_comp "RDI" qBc)) in
  let slot32val =
    rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 32))" qBc) in
  let el i = mk_comb(mk_comb(`EL:num->int32 list->int32`,
                             mk_small_numeral i), st30) in
  let kbase108 = `word_add (kbase:int64) (word 108)` in
  let k31fresh = `k31:int32` in
  let inst =
   [ el 0,rv"a"; el 1,rv"b"; el 2,rv"c"; el 3,rv"d";
     el 4,rv"e"; el 5,rv"f"; el 6,rv"g"; el 7,rv"h";
     occ0,rv"w16"; slot32val,rv"w24"; occ13,rv"w29"; `v15:int32`,rv"w15";
     kbase108,rv"kb"; (bv "K256"),rv"kk"; k31fresh,rv"k31" ] in
  let pR_i = vsubst inst pR in
  let qR_i = vsubst inst qR in
  let cR_i = vsubst inst cR in
  let _, pR_i_c = conjs_of_lam pR_i in
  (* composed PRE = BODY15 pre + carried K read at kbase+108 = k31 *)
  let kread108 = mk_eq(
     mk_comb(mk_comb(`read:(x86state,int32)component->x86state->int32`,
                     `memory :> bytes32 (word_add (kbase:int64) (word 108))`),
             sB), k31fresh) in
  let pre_lam  = mk_abs(sB, list_mk_conj (pBc @ [kread108])) in
  (* FRAME = BODY15 frame ,, ROUND31 frame *)
  let seqop = `(,,):(x86state->x86state->bool)->(x86state->x86state->bool)->
                    (x86state->x86state->bool)` in
  let frame = mk_comb(mk_comb(seqop,cB),cR_i) in
  (* HYPS = BODY15's two nonoverlapping + (stackptr,64)(kbase+108,4) *)
  let hyps_B = fst(dest_imp(snd(strip_forall(concl SHA256_BLOCK_NOHW_BODY15)))) in
  let no_extra =
    `nonoverlapping (stackptr:int64,64) (word_add (kbase:int64) (word 108),4)` in
  let hyps = mk_conj(hyps_B, no_extra) in
  let ens_body = snd(dest_imp(snd(strip_forall(concl SHA256_BLOCK_NOHW_BODY15)))) in
  let ens_head = rator(rator(rator ens_body)) in
  let mk_ensures p q c = mk_comb(mk_comb(mk_comb(ens_head,p),q),c) in
  let comp_concl =
    list_mk_forall(bvars @ [k31fresh],
      mk_imp(hyps, mk_ensures pre_lam qR_i frame)) in
  (* seamQ = ROUND31 instantiated pre minus bytes_loaded + RIP *)
  let is_bytes_loaded c =
    try let _ = find_term
          (fun t->is_const t && fst(dest_const t)="bytes_loaded") c in true
    with _->false in
  let seamQ_conjs =
    filter (fun c -> not(is_bytes_loaded c) && comp_str c <> "RIP") pR_i_c in
  let seamQ = mk_abs(sB, list_mk_conj seamQ_conjs) in
  let pc_seam = `pc + 4205` in
  (* committed lemmas specialized to the goal's bound vars / seam terms *)
  let body15_self = SPECL bvars SHA256_BLOCK_NOHW_BODY15 in
  let round31_seam =
    SPECL [ `pc:num`; (bv "K256"); kbase108; `stackptr:int64`;
            el 0; el 1; el 2; el 3; el 4; el 5; el 6; el 7;
            occ0; slot32val; occ13; `v15:int32`; k31fresh ]
          SHA256_BLOCK_NOHW_ROUND31 in
  (* rodata-prime fix: re-point a committed lemma's rodata var to the goal's *)
  let goal_rodata_var w =
    let blob = find_term (fun t ->
        (try fst(dest_const(fst(strip_comb t)))=
                "sha256_compress_tmc"
         with _ -> false)) w in
    last (snd (strip_comb blob)) in
  let match_leg lemma =
    W(fun (asl,w) ->
        ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, (bv"K256")] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let execup =
    MATCH_MP bytes_loaded_update (fst SHA256_COMPRESS_EXEC) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  let sublem_b =
    MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
     [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC;
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
      REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
      REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
      REWRITE_TAC[GSYM SEQ_ASSOC] THEN
      PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
      CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
      REWRITE_TAC[ASSIGNS_THM] THEN
      REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
      NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
      ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC)] in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg body15_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg round31_seam THEN sublem_b THEN ASM_REWRITE_TAC[] ]);;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - BODY15 ; ROUND31_S into ONE rounds_16_xx iteration, with  *)
(* a FAT post that carries everything the NEXT iteration's pc+1786 PRE needs.  *)
(*                                                                           *)
(* This is BODY15_ROUND31 rebuilt on ROUND31_S (the union-post variant).  Two  *)
(* differences from BODY15_ROUND31:                                           *)
(*   (1) ROUND31_S's pre reads the W-ring slots 4 (v1) and 56 (v14), so the    *)
(*       seam instantiation binds v1 := BODY15-post slot4, v14 := slot56.      *)
(*   (2) ROUND31_S's MAYCHANGE touches only slot60, so all OTHER ring slots    *)
(*       (0,8,12,16,20,24,28,32,36,40,44,48,52) and the carried working state  *)
(*       ride through it unchanged.  We add those slot conjuncts to BOTH the    *)
(*       seam predicate (leg A = BODY15 proves them) AND the composed post (so  *)
(*       they are exposed for the next iteration); they thread through          *)
(*       ROUND31_S's frame as out-of-frame preserved facts.                    *)
(* Result post = ROUND31_S inst-post (RBX..R11 = 32-round state, RAX split,    *)
(* R14=Sigma0 a, RDI=a^b, slot4/slot56/slot60) + the 13 surviving ring slots.  *)
(* Built PROGRAMMATICALLY by term surgery, same idiom as BODY15_ROUND31.       *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_BODY15_ROUND31_S =
  let strip_ensures th =
    let bod = snd(strip_forall(concl th)) in
    let _,ens = dest_imp bod in
    let l,c = dest_comb ens in
    let l2,q = dest_comb l in
    let _,p = dest_comb l2 in (p,q,c) in
  let conjs_of_lam q = let s,body = dest_abs q in s, conjuncts body in
  let comp_of c = let l,_ = dest_eq c in snd(dest_comb(fst(dest_comb l))) in
  let rhs_of  c = snd(dest_eq c) in
  let comp_str c = try string_of_term (comp_of c) with _ -> "?" in
  let by_comp target lst = find (fun c -> comp_str c = target) lst in
  let (_pB,_qB,cB)  = strip_ensures SHA256_BLOCK_NOHW_BODY15 in
  let (pR,qR,cR)    = strip_ensures SHA256_BLOCK_NOHW_ROUND31_S in
  let sB, _qBc      = conjs_of_lam _qB in
  let _,  pBc       = conjs_of_lam _pB in
  let _,  qBc       = conjs_of_lam _qB in
  let bvars = fst(strip_forall(concl SHA256_BLOCK_NOHW_BODY15)) in
  let rvars = fst(strip_forall(concl SHA256_BLOCK_NOHW_ROUND31_S)) in
  let vbyname vs n = find (fun v -> name_of v = n) vs in
  let rv = vbyname rvars and bv = vbyname bvars in
  (* seam values out of BODY15 post (30-round state, ring occupants) *)
  let st30  = rand(rand(rhs_of(by_comp "RBX" qBc))) in
  let occ0  = rand(rhs_of(by_comp "R12" qBc)) in
  let occ13 = rand(rhs_of(by_comp "RDI" qBc)) in
  let slotval n =
    rhs_of(by_comp
      ("memory :> bytes32 (word_add stackptr (word "^string_of_int n^"))") qBc) in
  let slot4val  = slotval 4 in
  let slot32val = slotval 32 in
  let slot56val = slotval 56 in
  let el i = mk_comb(mk_comb(`EL:num->int32 list->int32`,
                             mk_small_numeral i), st30) in
  let kbase108 = `word_add (kbase:int64) (word 108)` in
  let k31fresh = `k31:int32` in
  let inst =
   [ el 0,rv"a"; el 1,rv"b"; el 2,rv"c"; el 3,rv"d";
     el 4,rv"e"; el 5,rv"f"; el 6,rv"g"; el 7,rv"h";
     occ0,rv"w16"; slot32val,rv"w24"; occ13,rv"w29"; `v15:int32`,rv"w15";
     slot4val,rv"v1"; slot56val,rv"v14";
     kbase108,rv"kb"; (bv "K256"),rv"kk"; k31fresh,rv"k31" ] in
  let pR_i = vsubst inst pR in
  let qR_i = vsubst inst qR in
  let cR_i = vsubst inst cR in
  let _, pR_i_c = conjs_of_lam pR_i in
  let _, qR_i_c = conjs_of_lam qR_i in
  (* the BODY15-post ring-slot conjuncts that ROUND31_S does NOT touch in its    *)
  (* MAYCHANGE (everything except slot60): they survive ROUND31_S unchanged.     *)
  let is_slot_read off c =
    comp_str c =
      (if off = 0 then "memory :> bytes32 stackptr"
       else "memory :> bytes32 (word_add stackptr (word "^string_of_int off^"))") in
  let surviving_slots =
    filter (fun off -> off <> 60)
           [0;4;8;12;16;20;24;28;32;36;40;44;48;52;56] in
  let body_slot_conj off = by_comp
      (if off = 0 then "memory :> bytes32 stackptr"
       else "memory :> bytes32 (word_add stackptr (word "^string_of_int off^"))")
      qBc in
  let carried_slot_conjs = map body_slot_conj surviving_slots in
  (* composed PRE = BODY15 pre + carried K read at kbase+108 = k31 *)
  let kread108 = mk_eq(
     mk_comb(mk_comb(`read:(x86state,int32)component->x86state->int32`,
                     `memory :> bytes32 (word_add (kbase:int64) (word 108))`),
             sB), k31fresh) in
  let pre_lam  = mk_abs(sB, list_mk_conj (pBc @ [kread108])) in
  (* FRAME = BODY15 frame ,, ROUND31_S frame *)
  let seqop = `(,,):(x86state->x86state->bool)->(x86state->x86state->bool)->
                    (x86state->x86state->bool)` in
  let frame = mk_comb(mk_comb(seqop,cB),cR_i) in
  (* HYPS = BODY15's two nonoverlapping + (stackptr,64)(kbase+108,4) *)
  let hyps_B = fst(dest_imp(snd(strip_forall(concl SHA256_BLOCK_NOHW_BODY15)))) in
  let no_extra =
    `nonoverlapping (stackptr:int64,64) (word_add (kbase:int64) (word 108),4)` in
  let hyps = mk_conj(hyps_B, no_extra) in
  let ens_body = snd(dest_imp(snd(strip_forall(concl SHA256_BLOCK_NOHW_BODY15)))) in
  let ens_head = rator(rator(rator ens_body)) in
  let mk_ensures p q c = mk_comb(mk_comb(mk_comb(ens_head,p),q),c) in
  (* composed POST = ROUND31_S inst-post + the surviving ring slots *)
  let post_lam = mk_abs(sB, list_mk_conj (qR_i_c @ carried_slot_conjs)) in
  let comp_concl =
    list_mk_forall(bvars @ [k31fresh],
      mk_imp(hyps, mk_ensures pre_lam post_lam frame)) in
  (* seamQ = ROUND31_S instantiated pre (minus bytes_loaded + RIP) + the         *)
  (* surviving ring slots (leg A = BODY15 proves them, leg B threads them).      *)
  let is_bytes_loaded c =
    try let _ = find_term
          (fun t->is_const t && fst(dest_const t)="bytes_loaded") c in true
    with _->false in
  let seamQ_conjs =
    filter (fun c -> not(is_bytes_loaded c) && comp_str c <> "RIP") pR_i_c in
  (* avoid duplicating slot4/slot56 (already in ROUND31_S pre) *)
  let extra_seam_slots =
    filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs)))
           carried_slot_conjs in
  let seamQ = mk_abs(sB, list_mk_conj (seamQ_conjs @ extra_seam_slots)) in
  let pc_seam = `pc + 4205` in
  let body15_self = SPECL bvars SHA256_BLOCK_NOHW_BODY15 in
  let round31_seam =
    SPECL [ `pc:num`; (bv "K256"); kbase108; `stackptr:int64`;
            el 0; el 1; el 2; el 3; el 4; el 5; el 6; el 7;
            occ0; slot32val; occ13; `v15:int32`; k31fresh; slot4val; slot56val ]
          SHA256_BLOCK_NOHW_ROUND31_S in
  let goal_rodata_var w =
    let blob = find_term (fun t ->
        (try fst(dest_const(fst(strip_comb t)))=
                "sha256_compress_tmc"
         with _ -> false)) w in
    last (snd (strip_comb blob)) in
  let match_leg lemma =
    W(fun (asl,w) ->
        ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, (bv"K256")] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let execup =
    MATCH_MP bytes_loaded_update (fst SHA256_COMPRESS_EXEC) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  (* Unlike the thin-post BODY15_ROUND31 (whose leg B used a TRIMMED sublemma     *)
  (* because its leg-1 !s.P=>P' auto-closed), here BOTH legs use the canned        *)
  (* ENSURES_SUBLEMMA_TAC: the composed PRE carries extra conjuncts (the carried  *)
  (* K@kbase+108 and the 12 surviving ring slots), so leg B's leg-1 does NOT       *)
  (* auto-close and the 3-conjunct canned path is the correct one for it too.      *)
  ignore is_slot_read;
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg body15_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg round31_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - ONE loop CONTINUE iteration: BODY15_ROUND31_S ; LOOPEDGE  *)
(* _CONT, pc+1786 -> pc+1786.  This is the inner-loop iteration that loops     *)
(* back (the sentinel byte is nonzero, so the jne is taken).                   *)
(*                                                                           *)
(* BODY15_ROUND31_S exits at pc+4345 in the SPLIT state; LOOPEDGE_CONT then    *)
(* steps the sentinel cmpb + the taken jne + the 5-instr prologue-fold back to *)
(* pc+1786, reconciling the deferred Sigma0 (RAX := EL0(st31)) and reloading   *)
(* the next sub-round's R12/R13/R15 scratch from ring slots 1/14.  The         *)
(* composed post is exactly the shape BODY15_ROUND31_S's OWN pre needs (next   *)
(* iteration), so this lemma is self-composable for the x3 chain.              *)
(*                                                                           *)
(* Seam at pc+4345.  The CONT instantiation pulls its pre-vars from BR_S's     *)
(* post (rbp_val = (kbase+108)+20, rax_in = the split EL0-Sigma0, r14_in =     *)
(* Sigma0 a, r1/r14v = ring slots 4/56).  The sentinel-byte read at rbp_val+3  *)
(* and ~(sb=word 0) are HYPS (BR_S does not source the sentinel; the x3 chain  *)
(* discharges them from SHA256_SENTINEL_BYTES).  The sentinel read threads     *)
(* through BR_S's frame as a preserved bytes8 fact (needs the added            *)
(* nonoverlapping (stackptr,64)(rbp_val+3,1) hyp); the canned sublem_a carries *)
(* it.  Built PROGRAMMATICALLY (term surgery on the two committed concls).     *)
(* ------------------------------------------------------------------------- *)

let SHA256_BLOCK_NOHW_ITER_CONT =
  let strip_ensures th =
    let bod = snd(strip_forall(concl th)) in
    let _,ens = dest_imp bod in
    let l,c = dest_comb ens in let l2,q = dest_comb l in
    let _,p = dest_comb l2 in (p,q,c) in
  let conjs_of_lam q = let s,body = dest_abs q in s, conjuncts body in
  let comp_of c = let l,_ = dest_eq c in snd(dest_comb(fst(dest_comb l))) in
  let rhs_of c = snd(dest_eq c) in
  let comp_str c = try string_of_term (comp_of c) with _ -> "?" in
  let by_comp t lst = find (fun c -> comp_str c = t) lst in
  let (_pBR,_qBR,cBR) = strip_ensures SHA256_BLOCK_NOHW_BODY15_ROUND31_S in
  let (pC,qC,cC)      = strip_ensures SHA256_BLOCK_NOHW_LOOPEDGE_CONT in
  let sBR, pBRc = conjs_of_lam _pBR in
  let _,   qBRc = conjs_of_lam _qBR in
  let brvars = fst(strip_forall(concl SHA256_BLOCK_NOHW_BODY15_ROUND31_S)) in
  let cvars  = fst(strip_forall(concl SHA256_BLOCK_NOHW_LOOPEDGE_CONT)) in
  let vbyname vs n = find (fun v -> name_of v = n) vs in
  let cv = vbyname cvars and brv = vbyname brvars in
  (* values from BR_S post to instantiate CONT's pre vars *)
  let rbp_val_v = rhs_of(by_comp "RBP" qBRc) in            (* (kbase+108)+20 *)
  let rax_in_v  = rand(rhs_of(by_comp "RAX" qBRc)) in       (* strip word_zx *)
  let r14_in_v  = rand(rhs_of(by_comp "R14" qBRc)) in
  let r1_v      = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 4))" qBRc) in
  let r14v_v    = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 56))" qBRc) in
  let sb_v = `sb:byte` in
  (* CONT instantiated at the seam *)
  let cinst =
   [ (brv "K256"), cv"kk"; rbp_val_v, cv"rbp_val"; r1_v, cv"r1"; r14v_v, cv"r14v";
     rax_in_v, cv"rax_in"; r14_in_v, cv"r14_in"; sb_v, cv"sb" ] in
  let pC_i = vsubst cinst pC in
  let qC_i = vsubst cinst qC in
  let cC_i = vsubst cinst cC in
  let _, pC_i_c = conjs_of_lam pC_i in
  let _, qC_i_c = conjs_of_lam qC_i in
  (* sentinel-byte read: extract CONT's instantiated bytes8 conjunct, retarget    *)
  (* its state var to BR_S's sBR so it sits in the composed PRE as a preserved     *)
  (* fact threading through BR_S's frame (BR_S touches no bytes8).                 *)
  let is_bytes8 c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes8") c in true
    with _->false in
  let sent_read_C = find is_bytes8 pC_i_c in
  let sent_state = rand(fst(dest_eq sent_read_C)) in
  let sent_read = subst [sBR, sent_state] sent_read_C in
  (* composed PRE = BR_S pre + carried-K(kbase+108) [already in BR_S pre] + sentinel *)
  let pre_lam = mk_abs(sBR, list_mk_conj (pBRc @ [sent_read])) in
  (* surviving BR_S post facts NOT overwritten by CONT (frame [RIP;RAX;R12;R13;R15]) *)
  (* and not already in CONT post: keep RDI,RBX..R11,R14,slot4,slot56,slot60,ring   *)
  let cont_post_comps = map comp_str qC_i_c in
  let overwritten = ["RIP";"RAX";"R12";"R13";"R15"] in
  let surviving = filter (fun c ->
       not(mem (comp_str c) cont_post_comps) &&
       not(mem (comp_str c) overwritten)) qBRc in
  let post_lam = mk_abs(sBR, list_mk_conj (qC_i_c @ surviving)) in
  (* FRAME = BR_S frame ,, CONT frame *)
  let seqop = `(,,):(x86state->x86state->bool)->(x86state->x86state->bool)->(x86state->x86state->bool)` in
  let frame = mk_comb(mk_comb(seqop,cBR),cC_i) in
  (* HYPS = BR_S hyps + CONT hyps (nonoverlap rbp_val,4 + ~(sb=0)) + sentinel slot *)
  let hyps_BR = fst(dest_imp(snd(strip_forall(concl SHA256_BLOCK_NOHW_BODY15_ROUND31_S)))) in
  let no_rbp = `nonoverlapping (word pc,4465) (word_add (word_add (kbase:int64) (word 108)) (word 20),4)` in
  let sb_ne = mk_neg(mk_eq(sb_v,`word 0:byte`)) in
  let no_sent = `nonoverlapping (stackptr:int64,64) (word_add (word_add (word_add (kbase:int64) (word 108)) (word 20)) (word 3),1)` in
  let hyps = list_mk_conj [hyps_BR; no_rbp; sb_ne; no_sent] in
  let ens_body = snd(dest_imp(snd(strip_forall(concl SHA256_BLOCK_NOHW_BODY15_ROUND31_S)))) in
  let ens_head = rator(rator(rator ens_body)) in
  let mk_ensures p q c = mk_comb(mk_comb(mk_comb(ens_head,p),q),c) in
  let comp_concl = list_mk_forall(brvars, mk_imp(hyps, mk_ensures pre_lam post_lam frame)) in
  (* seamQ at pc+4345 = CONT inst-pre (minus bytes_loaded+RIP) + surviving BR_S facts *)
  let is_bytes_loaded c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes_loaded") c in true with _->false in
  let seamQ_conjs = filter (fun c -> not(is_bytes_loaded c) && comp_str c <> "RIP") pC_i_c in
  let extra_seam = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) surviving in
  let seamQ = mk_abs(sBR, list_mk_conj (seamQ_conjs @ extra_seam)) in
  let pc_seam = `pc + 4345` in
  let brs_self = SPECL brvars SHA256_BLOCK_NOHW_BODY15_ROUND31_S in
  let cont_seam =
    SPECL [ `pc:num`; (brv "K256"); `stackptr:int64`; rbp_val_v; r1_v; r14v_v;
            rax_in_v; r14_in_v; sb_v ] SHA256_BLOCK_NOHW_LOOPEDGE_CONT in
  let goal_rodata_var w =
    let blob = find_term (fun t ->
        (try fst(dest_const(fst(strip_comb t)))="sha256_compress_tmc"
         with _ -> false)) w in
    last (snd (strip_comb blob)) in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, (brv"K256")] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let execup = MATCH_MP bytes_loaded_update (fst SHA256_COMPRESS_EXEC) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg brs_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg cont_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

(* ------------------------------------------------------------------------- *)
(* Phase 8 STEP 3 - per-iteration ABS composition: BODY15_ABS ; ROUND31_S_ABS *)
(* ; LOOPEDGE_{CONT,EXIT}, one full inner-loop iteration over the OPAQUE       *)
(* compress_rounds / sched abstraction.  Built PROGRAMMATICALLY (term surgery  *)
(* on the generator outputs MK_BODY15_ABS / MK_ROUND31S_ABS), mirroring the    *)
(* concrete BODY15_ROUND31_S / ITER_CONT but i-INDEPENDENT (seams O(1), each    *)
(* iteration lemma ~10K chars FLAT vs the 940K-growing-16x pure unroll).       *)
(*                                                                            *)
(* MK_BR_S_ABS i      : body i ; round31s i, pc+1786 -> pc+4345 (SPLIT exit).  *)
(* MK_ITER_ABS i br    : br ; LOOPEDGE_CONT, pc+1786 -> pc+1786 (continue).     *)
(* MK_ITER_ABS_EXIT i br: br ; LOOPEDGE_EXIT, pc+1786 -> pc+4355 (loop exit).   *)
(*                                                                            *)
(* The per-iteration seam (BODY15 POST -> ROUND31_S PRE) matches atom-for-atom *)
(* BECAUSE MK_ROUND31S_ABS instantiates w16/w24/w29/w15 with the OPAQUE sched   *)
(* atoms (session-024 fix); 17 PRE conjuncts match, the rest are the carried K  *)
(* read + frame-ridden RSP/slot60.  The composed lemmas carry LENGTH sin = 8    *)
(* (fronted) and the rodata binder kdat.                                       *)
(* ------------------------------------------------------------------------- *)

(* ---- shared plumbing ---- *)
let rec strip_all_imp tm = if is_imp tm then strip_all_imp (snd(dest_imp tm)) else tm;;
(* split a theorem  !vs. h1 ==> ... ==> ensures pre post frame  into          *)
(* (vs, [h1;..], pre, post, frame).  ABS lemmas have 2 imps (LENGTH, nonov).  *)
let parts th =
  let vs = fst(strip_forall(concl th)) in
  let bod = snd(strip_forall(concl th)) in
  let rec hyps tm = if is_imp tm then let h,r = dest_imp tm in
                      let hs,e = hyps r in (h::hs,e) else ([],tm) in
  let hs,ens = hyps bod in
  let l,c = dest_comb ens in let l2,q = dest_comb l in
  let _,p = dest_comb l2 in (vs,hs,p,q,c);;
let conjs_of_lam q = let s,body = dest_abs q in s, conjuncts body;;
let comp_of c = let l,_ = dest_eq c in snd(dest_comb(fst(dest_comb l)));;
let comp_str c = try string_of_term (comp_of c) with _ -> "?";;
let rhs_of c = snd(dest_eq c);;
let by_comp t lst = find (fun c -> comp_str c = t) lst;;
let is_named nm c =
  try let cn = fst(dest_const(fst(strip_comb c))) in cn = nm with _ -> false;;
let seqop = `(,,):(x86state->x86state->bool)->(x86state->x86state->bool)->
                  (x86state->x86state->bool)`;;
let ens_head_of th =
  let ens = strip_all_imp (snd(strip_forall(concl th))) in
  rator(rator(rator ens));;
let mk_ensures eh p q c = mk_comb(mk_comb(mk_comb(eh,p),q),c);;
let goal_rodata_var w =
  let blob = find_term (fun t ->
      (try fst(dest_const(fst(strip_comb t)))="sha256_compress_tmc"
       with _ -> false)) w in
  last (snd (strip_comb blob));;
let execup = MATCH_MP bytes_loaded_update (fst SHA256_COMPRESS_EXEC);;

(* ===================================================================== *)
(* MK_BR_S_ABS i : compose body i ; round31s i at pc+4205.                *)
(* ===================================================================== *)
let MK_BR_S_ABS i =
  let bI = MK_BODY15_ABS i and rI = MK_ROUND31S_ABS i in
  let (bvars,bhyps,pBlam,qBlam,cB) = parts bI in
  let (rvars,rhypsB,pR,qR,cR)  = parts rI in
  ignore rhypsB;
  let sB, pBc = conjs_of_lam pBlam in
  let _, qBc  = conjs_of_lam qBlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let rv = vbn rvars in
  (* seam instantiation: ABS lemmas pre-align a..h; only kb/v1/v14 are free. *)
  let rbp_b  = rhs_of(by_comp "RBP" qBc) in                 (* kbase+108 *)
  let slot4  = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 4))" qBc) in
  let slot56 = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 56))" qBc) in
  let inst = [ rbp_b, rv"kb"; slot4, rv"v1"; slot56, rv"v14" ] in
  let pR_i = vsubst inst pR and qR_i = vsubst inst qR and cR_i = vsubst inst cR in
  let _, pR_i_c = conjs_of_lam pR_i in
  let _, qR_i_c = conjs_of_lam qR_i in
  (* B15-post ring slots NOT in ROUND31_S frame (everything but slot60): survive *)
  let surviving_slots = filter (fun off -> off <> 60)
                          [0;4;8;12;16;20;24;28;32;36;40;44;48;52;56] in
  let body_slot_conj off = by_comp
      (if off = 0 then "memory :> bytes32 stackptr"
       else "memory :> bytes32 (word_add stackptr (word "^string_of_int off^"))") qBc in
  let carried_slot_conjs = map body_slot_conj surviving_slots in
  (* carried K read at kbase+108 = EL (31+16i) consts (k31), which B15 post lacks. *)
  let k31val = abs_el_k (16+16*i+15) in   (* EL (31+16i) sha256_constants *)
  let kread108 = mk_eq(
     mk_comb(mk_comb(`read:(x86state,int32)component->x86state->int32`,
                     `memory :> bytes32 (word_add (kbase:int64) (word 108))`),
             sB), k31val) in
  let pre_lam  = mk_abs(sB, list_mk_conj (pBc @ [kread108])) in
  let frame = mk_comb(mk_comb(seqop,cB),cR_i) in
  let hyps_B = list_mk_conj bhyps in
  let no_extra = `nonoverlapping (stackptr:int64,64) (word_add (kbase:int64) (word 108),4)` in
  let hyps = mk_conj(hyps_B, no_extra) in
  let eh = ens_head_of bI in
  let post_lam = mk_abs(sB, list_mk_conj (qR_i_c @ carried_slot_conjs)) in
  (* LENGTH sin = 8 must front the composed concl (both legs need it).           *)
  let lensin = `LENGTH (sin:int32 list) = 8` in
  let comp_concl =
    list_mk_forall(bvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  (* seamQ = ROUND31_S inst-pre (minus bytes_loaded+RIP) + surviving ring slots.  *)
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pR_i_c in
  let extra_seam_slots = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) carried_slot_conjs in
  let seamQ = mk_abs(sB, list_mk_conj (seamQ_conjs @ extra_seam_slots)) in
  let pc_seam = `pc + 4205` in
  (* committed lemmas, specialised at the seam (keep BOTH antecedents            *)
  (* LENGTH sin=8 ==> nonoverlap ==> ensures; ASM_REWRITE_TAC discharges both     *)
  (* from the outer assumptions, as in the concrete case for the single hyp).     *)
  let body_self = SPECL bvars bI in
  let round31_seam =
    SPECL [ `kdat:num`; `pc:num`; rbp_b; slot4; slot56; `sin:int32 list`;
            `m:int32 list`; `stackptr:int64` ] rI in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg body_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg round31_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

let MK_ITER_ABS i brI =
  let (brvars,brhyps,pBRlam,qBRlam,cBR) = parts brI in
  let (cvars,chypsC,pC,qC,cC) = parts SHA256_BLOCK_NOHW_LOOPEDGE_CONT in
  ignore chypsC;
  let sBR, pBRc = conjs_of_lam pBRlam in
  let _, qBRc = conjs_of_lam qBRlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let cv = vbn cvars in
  let rbp_val_v = rhs_of(by_comp "RBP" qBRc) in
  let rax_in_v  = rand(rhs_of(by_comp "RAX" qBRc)) in
  let r14_in_v  = rand(rhs_of(by_comp "R14" qBRc)) in
  let r1_v      = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 4))" qBRc) in
  let r14v_v    = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 56))" qBRc) in
  let sb_v = `sb:byte` in
  let cinst =
   [ `kdat:num`, cv"kk"; rbp_val_v, cv"rbp_val"; r1_v, cv"r1"; r14v_v, cv"r14v";
     rax_in_v, cv"rax_in"; r14_in_v, cv"r14_in"; sb_v, cv"sb" ] in
  let pC_i = vsubst cinst pC and qC_i = vsubst cinst qC and cC_i = vsubst cinst cC in
  let _, pC_i_c = conjs_of_lam pC_i in
  let _, qC_i_c = conjs_of_lam qC_i in
  let is_bytes8 c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes8") c in true with _->false in
  let sent_read_C = find is_bytes8 pC_i_c in
  let sent_state = rand(fst(dest_eq sent_read_C)) in
  let sent_read = subst [sBR, sent_state] sent_read_C in
  let pre_lam = mk_abs(sBR, list_mk_conj (pBRc @ [sent_read])) in
  let cont_post_comps = map comp_str qC_i_c in
  let overwritten = ["RIP";"RAX";"R12";"R13";"R15"] in
  let surviving = filter (fun c ->
       not(mem (comp_str c) cont_post_comps) && not(mem (comp_str c) overwritten)) qBRc in
  let post_lam = mk_abs(sBR, list_mk_conj (qC_i_c @ surviving)) in
  let frame = mk_comb(mk_comb(seqop,cBR),cC_i) in
  let hyps_BR = list_mk_conj brhyps in
  let no_rbp = vsubst [rbp_val_v,`RBPV:int64`] `nonoverlapping (word pc,4465) (RBPV:int64,4)` in
  let sb_ne = mk_neg(mk_eq(sb_v,`word 0:byte`)) in
  (* sentinel nonoverlap: (stackptr,64) vs (rbp_val+3, 1) *)
  let no_sent = vsubst [rbp_val_v,`RBPV:int64`]
      `nonoverlapping (stackptr:int64,64) (word_add (RBPV:int64) (word 3),1)` in
  let hyps = list_mk_conj [hyps_BR; no_rbp; sb_ne; no_sent] in
  let eh = ens_head_of brI in
  let lensin = `LENGTH (sin:int32 list) = 8` in
  let comp_concl =
    list_mk_forall(brvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pC_i_c in
  let extra_seam = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) surviving in
  let seamQ = mk_abs(sBR, list_mk_conj (seamQ_conjs @ extra_seam)) in
  let pc_seam = `pc + 4345` in
  let brs_self = SPECL brvars brI in
  let cont_seam =
    SPECL [ `pc:num`; `kdat:num`; `stackptr:int64`; rbp_val_v; r1_v; r14v_v;
            rax_in_v; r14_in_v; sb_v ] SHA256_BLOCK_NOHW_LOOPEDGE_CONT in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg brs_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg cont_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

(* ===================================================================== *)
(* MK_ITER_ABS_EXIT i (brI) : compose BR_S_ABS i ; LOOPEDGE_EXIT at        *)
(* pc+4345 (exit iteration: pc+1786 -> pc+4355).  Sentinel byte = word 0.  *)
(* ===================================================================== *)
let MK_ITER_ABS_EXIT i brI =
  let (brvars,brhyps,pBRlam,qBRlam,cBR) = parts brI in
  let (cvars,chypsE,pE,qE,cE) = parts SHA256_BLOCK_NOHW_LOOPEDGE_EXIT in
  ignore chypsE;
  let sBR, pBRc = conjs_of_lam pBRlam in
  let _, qBRc = conjs_of_lam qBRlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let cv = vbn cvars in
  let rbp_val_v = rhs_of(by_comp "RBP" qBRc) in
  let rax_in_v  = rand(rhs_of(by_comp "RAX" qBRc)) in
  let r14_in_v  = rand(rhs_of(by_comp "R14" qBRc)) in
  let einst =
   [ `kdat:num`, cv"kk"; rbp_val_v, cv"rbp_val";
     rax_in_v, cv"rax_in"; r14_in_v, cv"r14_in" ] in
  let pE_i = vsubst einst pE and qE_i = vsubst einst qE and cE_i = vsubst einst cE in
  let _, pE_i_c = conjs_of_lam pE_i in
  let _, qE_i_c = conjs_of_lam qE_i in
  (* sentinel-byte read at rbp_val+3 = word 0 (EXIT condition). *)
  let is_bytes8 c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes8") c in true with _->false in
  let sent_read_E = find is_bytes8 pE_i_c in
  let sent_state = rand(fst(dest_eq sent_read_E)) in
  let sent_read = subst [sBR, sent_state] sent_read_E in
  let pre_lam = mk_abs(sBR, list_mk_conj (pBRc @ [sent_read])) in
  (* EXIT frame is only [RIP]+flags+events; everything else of BR_S post survives *)
  let exit_post_comps = map comp_str qE_i_c in
  let overwritten = ["RIP"] in
  let surviving = filter (fun c ->
       not(mem (comp_str c) exit_post_comps) && not(mem (comp_str c) overwritten)) qBRc in
  let post_lam = mk_abs(sBR, list_mk_conj (qE_i_c @ surviving)) in
  let frame = mk_comb(mk_comb(seqop,cBR),cE_i) in
  let hyps_BR = list_mk_conj brhyps in
  let no_rbp = vsubst [rbp_val_v,`RBPV:int64`] `nonoverlapping (word pc,4465) (RBPV:int64,4)` in
  let no_sent = vsubst [rbp_val_v,`RBPV:int64`]
      `nonoverlapping (stackptr:int64,64) (word_add (RBPV:int64) (word 3),1)` in
  let hyps = list_mk_conj [hyps_BR; no_rbp; no_sent] in
  let eh = ens_head_of brI in
  let lensin = `LENGTH (sin:int32 list) = 8` in
  let comp_concl =
    list_mk_forall(brvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pE_i_c in
  let extra_seam = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) surviving in
  let seamQ = mk_abs(sBR, list_mk_conj (seamQ_conjs @ extra_seam)) in
  let pc_seam = `pc + 4345` in
  let brs_self = SPECL brvars brI in
  let exit_seam =
    SPECL [ `pc:num`; `kdat:num`; `stackptr:int64`; rbp_val_v;
            rax_in_v; r14_in_v ] SHA256_BLOCK_NOHW_LOOPEDGE_EXIT in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg brs_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg exit_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;


(* The three concrete inner-loop iteration lemmas (i=0,1 continue; i=2 exit).  *)
let SHA256_BLOCK_NOHW_ITER_ABS_0 = MK_ITER_ABS 0 (MK_BR_S_ABS 0);;
let SHA256_BLOCK_NOHW_ITER_ABS_1 = MK_ITER_ABS 1 (MK_BR_S_ABS 1);;
let SHA256_BLOCK_NOHW_ITER_ABS_EXIT_2 = MK_ITER_ABS_EXIT 2 (MK_BR_S_ABS 2);;

(* ========================================================================= *)
(* Phase 8 FINAL: the single-block inner-loop lemma SHA256_BLOCK_NOHW_INNER.  *)
(*                                                                           *)
(*   HEAD16_ABS (pc+87->pc+1786) ; ITER_ABS_0[K+128] ; ITER_ABS_1[K+256] ;    *)
(*   ITER_ABS_EXIT_2[K+384]  =>  ensures  pc+87 -> pc+4355                     *)
(*   with working state  sha256_compress_rounds m [a;..;h] 64.                *)
(*                                                                           *)
(* The three iterations run the inner do-while loop body exactly 3 times      *)
(* (i=0,1 take the back-edge: sentinel byte 0x27 / 0x19 != 0; i=2 exits:      *)
(* sentinel 0x00).  Composed PROGRAMMATICALLY at each pc+1786 seam by         *)
(* ENSURES_SEQUENCE_TAC with the per-iteration ABS lemmas reused verbatim:    *)
(* leg A = the accumulated chain (its rodata binder kdat is BOUND, so a plain *)
(* MP_TAC, no INST), leg B = the appended ITER lemma (free kdat -> match_leg  *)
(* INST to the goal's own rodata var).  seamQ = the appended lemma's PRE      *)
(* (minus the ENSURES_SEQUENCE-injected bytes_loaded + RIP), so leg B closes  *)
(* with the trimmed sublem_b; leg A reconciles the seam:                      *)
(*  - entry seam (HEAD16->IT0): the W-ring is EL j m in HEAD16 POST vs         *)
(*    sched m j in IT0 PRE for j<16 -> bridge with SCHED_LT16_CONV.            *)
(*  - iter-to-iter seam: RBP (kbase+128+108+20 = kbase+256) and RAX           *)
(*    (word_add (word_sub X sigma0) sigma0 = X) close by WORD_RULE; RDI        *)
(*    rotates EL 1/2 (cr .. (n+1)) = EL 0/1 (cr .. n) -> CR_ROT1/CR_ROT2.      *)
(* Anti-explosion holds: C0/C1/C2 stay ~15K/20K/25K chars (NOT the 940K-      *)
(* growing-16x pure unroll).                                                  *)
(* ========================================================================= *)

(* EL 1/2 of one more compression round = EL 0/1 of the previous state:       *)
(* the next iteration's RDI Maj-carry (word_xor (EL1 crN) (EL2 crN)) equals    *)
(* the prior iteration's exit RDI (word_xor (EL0 cr(N-1)) (EL1 cr(N-1))).      *)
let CR_ROT1 = prove
 (`!m s n. EL 1 (sha256_compress_rounds m s (SUC n)) =
           EL 0 (sha256_compress_rounds m s n)`,
  REWRITE_TAC[COMPRESS_ROUNDS_SUC; sha256_round] THEN
  REPEAT GEN_TAC THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN REFL_TAC);;

let CR_ROT2 = prove
 (`!m s n. EL 2 (sha256_compress_rounds m s (SUC n)) =
           EL 1 (sha256_compress_rounds m s n)`,
  REWRITE_TAC[COMPRESS_ROUNDS_SUC; sha256_round] THEN
  REPEAT GEN_TAC THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN REFL_TAC);;

(* literal-index instances:  EL 1 (cr m [a..h] (n+1)) = EL 0 (cr m [a..h] n)  *)
(* and EL 2 (..)= EL 1 (..) , via  n+1 = SUC n  (num_CONV).                    *)
let cr_rot_rules n =
  let suc = num_CONV (mk_small_numeral (n+1)) in
  let mk th = REWRITE_RULE[GSYM suc]
      (SPECL [`m:int32 list`;`[a;b;c;d;e;f;g;h]:int32 list`;mk_small_numeral n] th) in
  [mk CR_ROT1; mk CR_ROT2];;

let SHA256_BLOCK_NOHW_INNER =
  let len8 = LENGTH_CONV `LENGTH ([a;b;c;d;e;f;g;h]:int32 list)` in
  (* per-iteration ITER lemmas, instantiated for the chain (kbase +128/iter,    *)
  (* sin:=[a;..;h] so the working state threads as cr m [a..h] (16i) directly,   *)
  (* sentinel byte 0x27/0x19 for the two continue iterations; LENGTH collapsed). *)
  let it0i = REWRITE_RULE[len8] (INST [`word 0x27:byte`,`sb:byte`]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 128)`;
              `[a;b;c;d;e;f;g;h]:int32 list`;`m:int32 list`;`stackptr:int64`]
             SHA256_BLOCK_NOHW_ITER_ABS_0)) in
  let it1i = REWRITE_RULE[len8] (INST [`word 0x19:byte`,`sb:byte`]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 256)`;
              `[a;b;c;d;e;f;g;h]:int32 list`;`m:int32 list`;`stackptr:int64`]
             SHA256_BLOCK_NOHW_ITER_ABS_1)) in
  let it2i = REWRITE_RULE[len8]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 384)`;
              `[a;b;c;d;e;f;g;h]:int32 list`;`m:int32 list`;`stackptr:int64`]
             SHA256_BLOCK_NOHW_ITER_ABS_EXIT_2) in
  (* leg-B trimmed SUBLEM (canned ENSURES_SUBLEMMA_TAC body minus the leg-1      *)
  (* branch, which auto-closes when seamQ = the appended lemma's PRE exactly).   *)
  let sublem_b_tac =
    MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
     [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC;
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
      REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
      REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
      REWRITE_TAC[GSYM SEQ_ASSOC] THEN
      PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
      CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
      REWRITE_TAC[ASSIGNS_THM] THEN
      REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
      NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
      ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC)] in
  (* compose prevThm ; itI at the pc+1786 seam (see header).                     *)
  let compose_step prevThm itI legA_reconcile =
    let (pvars,phyps,pPlam,pQlam,pC) = parts prevThm in
    let (_,ihyps,iPlam,iQlam,iC) = parts itI in
    let sP, pPc = conjs_of_lam pPlam in
    let _,  pQc = conjs_of_lam pQlam in
    let sI, iPc0 = conjs_of_lam iPlam in
    let iPc = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") iPc0 in
    let pcomps = map comp_str pQc in
    let carried_I = filter (fun c -> not(mem (comp_str c) pcomps)) iPc in
    let carried_P = map (vsubst [sP, sI]) carried_I in
    let pre_lam = mk_abs(sP, list_mk_conj (pPc @ carried_P)) in
    let post_lam = iQlam in
    let frame = mk_comb(mk_comb(seqop,pC),iC) in
    let hyps = list_mk_conj (phyps @ ihyps) in
    let eh = ens_head_of prevThm in
    let comp_concl = list_mk_forall(pvars, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame)) in
    let seamQ = mk_abs(sI, list_mk_conj iPc) in
    let pc_seam = `pc + 1786` in
    let prev_self = SPECL pvars prevThm in
    let match_leg lemma =
      W(fun (asl,w) -> ignore asl;
          let kv = goal_rodata_var w in
          MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
          ASM_REWRITE_TAC[]) in
    let sublem_a = ENSURES_SUBLEMMA_TAC execup in
    let legA = MP_TAC (REWRITE_RULE[SOME_FLAGS] prev_self) THEN ASM_REWRITE_TAC[] in
    prove
     (comp_concl,
      REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN STRIP_TAC THEN
      ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
      [ legA THEN sublem_a "s" "s'" THEN legA_reconcile;
        match_leg itI THEN sublem_b_tac THEN ASM_REWRITE_TAC[] ]) in
  let SCHED_LT16_RULES = map (fun j -> SCHED_LT16_CONV (abs_instM j)) (0--15) in
  let c0 = compose_step SHA256_BLOCK_NOHW_HEAD16_ABS it0i
             (REWRITE_TAC SCHED_LT16_RULES THEN ASM_REWRITE_TAC[]) in
  let c1 = compose_step c0 it1i
             (ASM_REWRITE_TAC[] THEN REWRITE_TAC (cr_rot_rules 31) THEN
              REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE) in
  let c2 = compose_step c1 it2i
             (ASM_REWRITE_TAC[] THEN REWRITE_TAC (cr_rot_rules 47) THEN
              REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE) in
  c2;;

(* ========================================================================= *)
(* Phase 9 - full single block: ENTRY ; INNER ; TAIL = sha256_block.         *)
(*                                                                           *)
(* INNER (above) runs the 16 head rounds + 3 inner-loop iterations           *)
(* (pc+87 -> pc+4355) leaving the working state in the SPLIT form            *)
(* (RAX = EL0(cr 64) - sigma0(EL0(cr 63)), R14 = sigma0(EL0(cr 63))).        *)
(* Phase 9 wraps it with:                                                    *)
(*   ENTRY (pc+29 -> pc+87): the canonical-state setup feeding INNER's PRE,  *)
(*   TAIL  (pc+4355 -> pc+4426): the loop-exit deferred-sigma0 reconcile     *)
(*     (add %r14d,%eax) + the 8-word feed-forward add-back into (%rdi).      *)
(* These two segment lemmas are proved here; the composition + the spec-     *)
(* algebra (working state + feed-forward = sha256_block) follow.             *)
(* ------------------------------------------------------------------------- *)

(* ENTRY: pc+29 (orig 0x21, just after the `and $-64,%rsp`) -> pc+87.        *)
(* 15 instructions: 4 stack saves (statep/dataptr/end/origsp into 64..88     *)
(* (%rsp)), the 8 state loads `mov N(%rdi),reg`, the `jmp`, `mov %ebx,%edi`  *)
(* (RDI := b for round 0's Maj seed) and `lea K256(%rip),%rbp`.  The rip-    *)
(* relative LEA result folds to `word kk` (the rodata base = HEAD16_ABS's    *)
(* kbase) via RIP_REL_ADDR_FOLD, whose riprel32_within_bounds side-condition *)
(* rides as a precondition (discharged when this meets a concrete caller).   *)
let SHA256_BLOCK_NOHW_ENTRY = prove
 (`!pc kk stackptr statep dataptr endp origsp a b c d e f g h.
     nonoverlapping (word pc,4465) (statep:int64,32) /\
     nonoverlapping (word pc,4465) (stackptr:int64,96) /\
     nonoverlapping (statep:int64,32) (stackptr:int64,96) /\
     riprel32_within_bounds kk (pc + 87)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 29) /\
            read RSP s = stackptr /\
            read RDI s = statep /\
            read RSI s = dataptr /\
            read RDX s = endp /\
            read RAX s = origsp /\
            read (memory :> bytes32 statep) s = (a:int32) /\
            read (memory :> bytes32 (word_add statep (word 4))) s = (b:int32) /\
            read (memory :> bytes32 (word_add statep (word 8))) s = (c:int32) /\
            read (memory :> bytes32 (word_add statep (word 12))) s = (d:int32) /\
            read (memory :> bytes32 (word_add statep (word 16))) s = (e:int32) /\
            read (memory :> bytes32 (word_add statep (word 20))) s = (f:int32) /\
            read (memory :> bytes32 (word_add statep (word 24))) s = (g:int32) /\
            read (memory :> bytes32 (word_add statep (word 28))) s = (h:int32))
       (\s. read RIP s = word (pc + 87) /\
            read RBP s = word kk /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RDI s = word_zx (b:int32) /\
            read RAX s = word_zx (a:int32) /\
            read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\
            read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\
            read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\
            read R11 s = word_zx (h:int32) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 72))) s = dataptr /\
            read (memory :> bytes64 (word_add stackptr (word 80))) s = endp /\
            read (memory :> bytes64 (word_add stackptr (word 88))) s = origsp)
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 64));
                   memory :> bytes64 (word_add stackptr (word 72));
                   memory :> bytes64 (word_add stackptr (word 80));
                   memory :> bytes64 (word_add stackptr (word 88))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--15) THEN
  (* fold the rip-relative lea result so `read RBP s15 = word kk` (curve25519  *)
  (* base recipe): UNDISCH the reloc'd RBP read, IMP_REWRITE the fold, re-DISCH.*)
  UNDISCH_TAC
   `read RBP s15 =
      word (val (word (pc + 87):(64)word) +
            val (word_sx (iword (&kk - (&pc + &87)):int32):(64)word):num)` THEN
  IMP_REWRITE_TAC[RIP_REL_ADDR_FOLD] THEN ASM_REWRITE_TAC[] THEN DISCH_TAC THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REPEAT CONJ_TAC THEN TRY REFL_TAC THEN TRY (AP_TERM_TAC THEN CONV_TAC WORD_RULE));;

(* TAIL: pc+4355 (orig 0x1107, the loop-exit `mov 0x40(%rsp),%rdi`) ->        *)
(* pc+4426 (orig 0x114e, the outer `jb`, NOT executed).  20 instructions:     *)
(*   mov 0x40(%rsp),%rdi  (reload statep)                                     *)
(*   add %r14d,%eax       (reconcile the deferred sigma0: va := va + r14_in)  *)
(*   lea 0x40(%rsi),%rsi  (advance dataptr; outer-loop bookkeeping)           *)
(*   add (%rdi),%eax ... add 0x1c(%rdi),%r11d   (feed-forward add)            *)
(*   cmp 0x50(%rsp),%rsi  (outer-loop test, sets flags only)                  *)
(*   mov %eax,(%rdi) ... mov %r11d,0x1c(%rdi)   (store the 8 words back)       *)
(* Input working vars RAX..R11 = word_zx of va..vh, R14 = word_zx r14_in;     *)
(* input state words at (statep)+4i = s0v..s7v.  POST: statep+4i holds        *)
(* word_add (working var i) s_i, with var 0 = word_add va r14_in.             *)
let SHA256_BLOCK_NOHW_TAIL = prove
 (`!pc kk stackptr statep dataptr va vb vc vd ve vf vg vh r14_in
    s0v s1v s2v s3v s4v s5v s6v s7v.
     nonoverlapping (word pc,4465) (statep:int64,32)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 4355) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = word_zx (va:int32) /\
            read RBX s = word_zx (vb:int32) /\
            read RCX s = word_zx (vc:int32) /\
            read RDX s = word_zx (vd:int32) /\
            read R8 s  = word_zx (ve:int32) /\
            read R9 s  = word_zx (vf:int32) /\
            read R10 s = word_zx (vg:int32) /\
            read R11 s = word_zx (vh:int32) /\
            read R14 s = word_zx (r14_in:int32) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = statep /\
            read (memory :> bytes32 statep) s = (s0v:int32) /\
            read (memory :> bytes32 (word_add statep (word 4))) s = (s1v:int32) /\
            read (memory :> bytes32 (word_add statep (word 8))) s = (s2v:int32) /\
            read (memory :> bytes32 (word_add statep (word 12))) s = (s3v:int32) /\
            read (memory :> bytes32 (word_add statep (word 16))) s = (s4v:int32) /\
            read (memory :> bytes32 (word_add statep (word 20))) s = (s5v:int32) /\
            read (memory :> bytes32 (word_add statep (word 24))) s = (s6v:int32) /\
            read (memory :> bytes32 (word_add statep (word 28))) s = (s7v:int32))
       (\s. read RIP s = word (pc + 4426) /\
            read (memory :> bytes32 statep) s =
                word_add (word_add va r14_in) s0v /\
            read (memory :> bytes32 (word_add statep (word 4))) s =
                word_add vb s1v /\
            read (memory :> bytes32 (word_add statep (word 8))) s =
                word_add vc s2v /\
            read (memory :> bytes32 (word_add statep (word 12))) s =
                word_add vd s3v /\
            read (memory :> bytes32 (word_add statep (word 16))) s =
                word_add ve s4v /\
            read (memory :> bytes32 (word_add statep (word 20))) s =
                word_add vf s5v /\
            read (memory :> bytes32 (word_add statep (word 24))) s =
                word_add vg s6v /\
            read (memory :> bytes32 (word_add statep (word 28))) s =
                word_add vh s7v)
       (MAYCHANGE [RIP;RDI;RSI;RAX;RBX;RCX;RDX;R8;R9;R10;R11] ,,
        MAYCHANGE [memory :> bytes32 statep;
                   memory :> bytes32 (word_add statep (word 4));
                   memory :> bytes32 (word_add statep (word 8));
                   memory :> bytes32 (word_add statep (word 12));
                   memory :> bytes32 (word_add statep (word 16));
                   memory :> bytes32 (word_add statep (word 20));
                   memory :> bytes32 (word_add statep (word 24));
                   memory :> bytes32 (word_add statep (word 28))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--20) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 9 - the single-block lemma (composition + spec-algebra).            *)
(*                                                                           *)
(* Compose ENTRY (pc+29->87) ; INNER (pc+87->4355) ; TAIL (pc+4355->4426)    *)
(* into one ensures whose postcondition writes  sha256_block m [a;..;h]      *)
(* into the 8-word state at statep.  [a;..;h] is the input hash state read    *)
(* at entry from (statep)+4i; m is the message block, EL i m =                *)
(* word_bytereverse(read bytes32 (dataptr+4i)).                              *)
(*                                                                           *)
(* SEAM ENTRY->INNER (pc+87): ENTRY POST gives RBP=word kk (= INNER's kbase   *)
(*   via SPECL kbase:=word kk), the 8 working regs = word_zx a..h, RDI=word_zx*)
(*   b, RSI=dataptr.  INNER PRE additionally needs the 16 dataptr block reads *)
(*   (word_bytereverse(EL i m)) and the 32 K-reads (EL t consts at word kk +  *)
(*   offsets) + the per-iteration sentinel/nonoverlap facts.  These ride the  *)
(*   composed BLOCK PRE: the dataptr reads + the whole-K256 bytelist fact     *)
(*   read(memory:>bytelist(word kk,LENGTH K256)) s = K256, from which the     *)
(*   K-reads follow by SHA256_K256_READS and the sentinels by                 *)
(*   SHA256_SENTINEL_BYTES; all preserved through ENTRY's frame (ENTRY only   *)
(*   writes stack slots 64..88 + regs, disjoint from dataptr/kk-region).      *)
(* SEAM INNER->TAIL (pc+4355): instantiate TAIL with                          *)
(*   va := word_sub (EL0 cr64) (sigma0(EL0 cr63)), r14_in := sigma0(EL0 cr63),*)
(*   vb..vh := EL 1..7 cr64, s0v..s7v := a..h (the input state at statep+4i,  *)
(*   preserved through INNER's frame: INNER touches only regs + stack ring    *)
(*   slots 0..60, disjoint from statep; the 64(%rsp)=statep save also rides). *)
(*   TAIL POST then gives statep+4i = word_add (var i) s_i; var0 =            *)
(*   word_add va r14_in = EL0 cr64 (WORD_RULE: word_add(word_sub X s)s = X).  *)
(* SPEC-ALGEBRA: statep+4i = word_add (EL i cr64) (EL i [a;..;h]), and        *)
(*   sha256_block m hsh = [word_add (EL i (cr m hsh 64)) (EL i hsh)]          *)
(*   (sha256_block def + cr64 = sha256_compress_rounds m [a..h] 64), so the   *)
(*   written words ARE EL i (sha256_block m [a;..;h]).  Pure rewriting with   *)
(*   sha256_block + EL_CONV + LENGTH_SHA256_COMPRESS_ROUNDS.                  *)
(*                                                                           *)
(* SKELETON (session-027): ENTRY + TAIL are proved cheat-free above; INNER is *)
(* SHA256_BLOCK_NOHW_INNER.  The composition statement is below; the proof is *)
(* CHEAT_TAC pending the ENSURES_SEQUENCE glue (two seams) + the discharge of *)
(* the carried K/sentinel facts and the spec-algebra rewrite.  See the        *)
(* session-027 summary + drivers (s027_compose.ml, inner_stmt.txt) for the    *)
(* full plan; next session replaces CHEAT_TAC.                                *)
(* ------------------------------------------------------------------------- *)

(* The composition is built PROGRAMMATICALLY: blockQ87 / blockQ4355 are the two  *)
(* seam predicates (at pc+87 and pc+4355), block_concl the full statement, and    *)
(* the three legs (entry/inner/tail) are discharged via the match_leg/sublem      *)
(* idiom.  Reuses the shared plumbing (parts/conjs_of_lam/comp_str/by_comp/        *)
(* rhs_of/is_named/seqop/ens_head_of/mk_ensures/goal_rodata_var/execup) defined    *)
(* above near the inner-loop chain.  Two facts the seams need:                     *)
(*   RECON : word_add (word_sub x s) s = x   (INNER's SPLIT RAX <-> TAIL's var0)   *)
(*   SB    : EL i (sha256_block m hsh) = word_add (EL i (cr m hsh 64)) (EL i hsh)  *)
(*           (the feed-forward add-back IS sha256_block, straight from the def).   *)
let RECON = prove
 (`!x s:int32. word_add (word_sub x s) s = x`, CONV_TAC WORD_RULE);;
let SB = prove
 (`!m a b c d e f g h.
     EL 0 (sha256_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 0 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 64)) a /\
     EL 1 (sha256_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 1 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 64)) b /\
     EL 2 (sha256_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 2 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 64)) c /\
     EL 3 (sha256_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 3 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 64)) d /\
     EL 4 (sha256_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 4 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 64)) e /\
     EL 5 (sha256_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 5 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 64)) f /\
     EL 6 (sha256_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 6 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 64)) g /\
     EL 7 (sha256_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 7 (sha256_compress_rounds m [a;b;c;d;e;f;g;h] 64)) h`,
  REWRITE_TAC[sha256_block] THEN
  CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN REWRITE_TAC[]);;

let SHA256_BLOCK_NOHW_BLOCK =
  (* ---- classifiers ---- *)
  let is_kread c =
    try is_eq c &&
        (let r = rhs_of c in
         is_comb r && is_comb(rator r) &&
         (try fst(dest_const(rator(rator r)))="EL" with _ -> false) &&
         (try fst(dest_const(rand r))="sha256_constants" with _ -> false))
    with _ -> false in
  let is_sentinel c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes8") c in true
    with _ -> false in
  ignore is_kread; ignore is_sentinel;
  (* ---- specialise the three committed segment lemmas for the chain ---- *)
  let INNER_i = SPECL [`pc:num`;`kk:num`;`word kk:int64`;`stackptr:int64`;
     `dataptr:int64`;`a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;
     `g:int32`;`h:int32`;`m:int32 list`] SHA256_BLOCK_NOHW_INNER in
  let (_,ihyps,iPlam,iQlam,iC) = parts INNER_i in
  let sI,iPc = conjs_of_lam iPlam in
  let _,iQc = conjs_of_lam iQlam in
  let bighyp_i = hd ihyps in
  let zx_arg comp = rand(rhs_of(by_comp comp iQc)) in
  let TAIL_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
     `dataptr:int64`; zx_arg "RAX"; zx_arg "RBX"; zx_arg "RCX"; zx_arg "RDX";
     zx_arg "R8"; zx_arg "R9"; zx_arg "R10"; zx_arg "R11"; zx_arg "R14";
     `a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;`g:int32`;`h:int32`]
     SHA256_BLOCK_NOHW_TAIL in
  let (_,_,tPlam,tQlam,tC) = parts TAIL_i in
  let sT,tPc = conjs_of_lam tPlam in
  let _,tQc = conjs_of_lam tQlam in
  let ENTRY_i2 = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
     `dataptr:int64`;`endp:int64`;`origsp:int64`;`a:int32`;`b:int32`;`c:int32`;
     `d:int32`;`e:int32`;`f:int32`;`g:int32`;`h:int32`] SHA256_BLOCK_NOHW_ENTRY in
  let (_,_,ePlam,eQlam,eC) = parts ENTRY_i2 in
  let _,eQc = conjs_of_lam eQlam in
  let sE = fst(dest_abs eQlam) in
  let _,ePc = conjs_of_lam ePlam in
  let sEp = fst(dest_abs ePlam) in
  (* ---- address-flatten conv (nested word_add of constants -> one word) ---- *)
  let norm_conv = REWRITE_CONV[WORD_ADD_ASSOC_CONSTS;WORD_ADD_0] THENC
                  DEPTH_CONV NUM_ADD_CONV in
  let normt t = try rhs(concl(norm_conv t)) with _ -> t in
  let norm_rule d = CONV_RULE norm_conv d in
  (* ---- Q87 (seam at pc+87) = INNER's full PRE (flattened, minus bytes_loaded/  *)
  (* RIP, which ENSURES_SEQUENCE injects) INCLUDING the 64 K-reads + 3 sentinels  *)
  (* (bytes32/bytes8 — these frame-carry through ENTRY like the dataptr reads;    *)
  (* the whole-K256 bytelist does NOT frame-carry, so it is exploded to K-reads    *)
  (* inside the ENTRY leg), plus the 8 statep reads + slot64 (ride INNER's frame  *)
  (* to feed TAIL). ---- *)
  let drop_q87 c = is_named "bytes_loaded" c || comp_str c = "RIP" in
  let q87_inner = map normt (filter (fun c -> not(drop_q87 c)) iPc) in
  let is_mem c = let cs=comp_str c in String.length cs>=6 && String.sub cs 0 6="memory" in
  let statep_reads = map (vsubst[sI,sEp]) (filter is_mem ePc) in
  let slot64 = vsubst[sI,sE]
     (by_comp "memory :> bytes64 (word_add stackptr (word 64))" eQc) in
  let blockQ87 = mk_abs(sI, list_mk_conj (q87_inner @ statep_reads @ [slot64])) in
  (* ---- Q4355 (seam at pc+4355) = TAIL_i's PRE minus bytes_loaded/RIP ---- *)
  let q4355conjs =
    filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c<>"RIP") tPc in
  let blockQ4355 = mk_abs(sT, list_mk_conj q4355conjs) in
  (* ---- the full BLOCK statement (clean precondition set) ---- *)
  let block_pres =
   [ `nonoverlapping (word pc,4465) (statep:int64,32)`;
     `nonoverlapping (word pc,4465) (stackptr:int64,96)`;
     `nonoverlapping (word pc,4465) (dataptr:int64,64)`;
     `nonoverlapping (word pc,4465) (word kk:int64,608)`;
     `nonoverlapping (statep:int64,32) (stackptr:int64,96)`;
     `nonoverlapping (statep:int64,32) (dataptr:int64,64)`;
     `nonoverlapping (statep:int64,32) (word kk:int64,608)`;
     `nonoverlapping (stackptr:int64,96) (dataptr:int64,64)`;
     `nonoverlapping (stackptr:int64,96) (word kk:int64,608)`;
     `riprel32_within_bounds kk (pc + 87)` ] in
  let sv = `s:x86state` in
  let entry_pre = map (vsubst[sv,sEp]) ePc in
  let dataptr_reads = map (vsubst[sv,sI])
    (filter (fun c -> is_mem c &&
        (try let _=find_term (fun t->is_const t &&
                fst(dest_const t)="word_bytereverse") c in true with _->false)) iPc) in
  let blk_bytelist =
     `read (memory :> bytelist (word kk:int64, LENGTH K256)) (s:x86state) = K256` in
  let blockPRE = mk_abs(sv, list_mk_conj (entry_pre @ dataptr_reads @ [blk_bytelist])) in
  let el_blk i = vsubst[mk_small_numeral i,`i:num`]
     `EL i (sha256_block m [a;b;c;d;e;f;g;h]):int32` in
  let post_read i = vsubst[sv,sT]
     (fst(dest_eq(by_comp (if i=0 then "memory :> bytes32 statep"
          else "memory :> bytes32 (word_add statep (word "^string_of_int(4*i)^"))")
          tQc))) in
  let block_post_conjs =
    `read RIP s = word (pc + 4426)` ::
    (map (fun i -> mk_eq(post_read i, el_blk i)) (0--7)) in
  let blockPOST = mk_abs(sv, list_mk_conj block_post_conjs) in
  let blockFRAME = mk_comb(mk_comb(seqop, mk_comb(mk_comb(seqop,eC),iC)),tC) in
  let eh = ens_head_of INNER_i in
  let block_concl =
    list_mk_forall([`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
                    `dataptr:int64`;`endp:int64`;`origsp:int64`;
                    `a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;
                    `g:int32`;`h:int32`;`m:int32 list`],
      itlist (curry mk_imp) block_pres
        (mk_ensures eh blockPRE blockPOST blockFRAME)) in
  (* ---- leg tactics ---- *)
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kk:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  (* INNER's big nonoverlap+sentinel hyp discharges from BLOCK's nonoverlaps by    *)
  (* NONOVERLAPPING_TAC (sub-range weakening) + byte sentinels by WORD_REDUCE_CONV.*)
  let INNER_HYP_CLOSER =
    REWRITE_TAC[NONOVERLAPPING_CLAUSES] THEN REPEAT CONJ_TAC THEN
    (NONOVERLAPPING_TAC ORELSE CONV_TAC WORD_REDUCE_CONV ORELSE CONV_TAC WORD_RULE) in
  (* Q87's K-reads are flat; INNER's PRE K-reads are nested -> flatten then ASM.   *)
  let INNER_SEAM_RECON =
    REWRITE_TAC[WORD_ADD_ASSOC_CONSTS; WORD_ADD_0] THEN
    CONV_TAC(DEPTH_CONV NUM_ADD_CONV) THEN ASM_REWRITE_TAC[] in
  let inner_leg =
    SUBGOAL_THEN bighyp_i ASSUME_TAC THENL
     [ INNER_HYP_CLOSER;
       match_leg INNER_i THEN sublem_a "s" "s'" THEN INNER_SEAM_RECON ] in
  (* TAIL leg: seamQ = TAIL_i's PRE exactly -> trimmed leg-B; master POST is        *)
  (* sha256_block while TAIL POST is word_add, so close with SB + RECON.            *)
  let tail_leg =
    match_leg TAIL_i THEN
    MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
     [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC;
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
      REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
      REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
      REWRITE_TAC[GSYM SEQ_ASSOC] THEN
      PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
      CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
      REWRITE_TAC[ASSIGNS_THM] THEN
      REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
      NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
      ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC) THEN
      REWRITE_TAC[SB] THEN RULE_ASSUM_TAC(REWRITE_RULE[RECON]) THEN
      ASM_REWRITE_TAC[]] in
  (* ENTRY leg: the whole-K256 bytelist lives in BLOCK PRE (sublem's `P s`), not in *)
  (* the assumptions, so explode it INSIDE the seam branch: after stripping P s +  *)
  (* Q' s' to assumptions, derive the 64 K-reads + 3 sentinels from bytelist-on-s  *)
  (* (KDERIVE_ASSUME); the state-update machinery then frame-carries them to s'.    *)
  let KDERIVE_ASSUME =
    FIRST_ASSUM(fun th ->
          let c = concl th in
          if is_eq c && (try fst(dest_const(rand c))="K256" with _->false)
          then ASSUME_TAC(norm_rule(MATCH_MP SHA256_K256_READS th)) THEN
               ASSUME_TAC(norm_rule(MATCH_MP SHA256_SENTINEL_BYTES th))
          else NO_TAC) in
  let entry_leg =
    match_leg ENTRY_i2 THEN
    MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
     [ W(fun (asl,w) -> ignore asl;
         X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
       STRIP_TAC THEN ASM_REWRITE_TAC[];
       CONJ_TAC THENL [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC; ALL_TAC] THEN
       W(fun (asl,w) -> ignore asl;
         X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
       W(fun (asl,w) -> ignore asl;
         X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
       REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
       KDERIVE_ASSUME THEN
       REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
       REWRITE_TAC[GSYM SEQ_ASSOC] THEN
       PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
       CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
       REWRITE_TAC[ASSIGNS_THM] THEN
       REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
       NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
       ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC) THEN
       ASM_REWRITE_TAC[] ] in
  prove
   (block_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN REPEAT STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC `pc + 87` blockQ87 THEN CONJ_TAC THENL
     [ entry_leg;
       ENSURES_SEQUENCE_TAC `pc + 4355` blockQ4355 THEN CONJ_TAC THENL
        [ inner_leg; tail_leg ] ]);;

(* ========================================================================= *)
(* Phase 10 - outer multi-block loop -> core CORRECT.                        *)
(*                                                                           *)
(* Outer-loop geometry (tmc pc = objdump offset - 4, endbr64 trimmed):        *)
(*   pc+29 (0x21): core entry, after `andq $-64,%rsp`.  Stack saves begin.    *)
(*   pc+49..78 (0x35..0x52): the 8 state loads `mov N(%rdi),reg` (RUNS ONCE). *)
(*   pc+78 (0x52) = Lsha256_compress_loop = OUTER-LOOP LABEL,    *)
(*       i.e. the back-edge target.  Instr: `mov %ebx,%edi`.                  *)
(*   pc+80 (0x54): `lea K256(%rip),%rbp`.   pc+87 (0x5b): INNER entry.        *)
(*   pc+4394 (0x112e): `cmp 0x50(%rsp),%rsi` sets CF (rsi=dataptr+64 vs endp).*)
(*   pc+4426 (0x114e): `jb` back-edge -> targets pc+78 (NOT pc+29).           *)
(*   pc+4430 (0x1154): fall-through = loop exit (epilogue start).             *)
(* So the outer-loop state is carried in REGISTERS eax..r11d across           *)
(* iterations (TAIL also writes it to memory[statep]); the body re-enters at  *)
(* pc+78 with register state.  The loop decomposes as                         *)
(*   PROL_REG (pc+29->78, ONCE) ; loop over BODY (pc+78->4426) where           *)
(*   BODY = MINI (78->87) ; INNER (87->4355) ; TAIL_LP (4355->4426, w/ CF).   *)
(* ------------------------------------------------------------------------- *)

(* PROL_REG: pc+29 -> pc+78, the one-time prologue.  13 instrs: 4 stack saves  *)
(* (statep/dataptr/endp/origsp -> 64+N(%rsp)) + 8 state loads -> eax..r11d.    *)
let SHA256_BLOCK_NOHW_PROL_REG = prove
 (`!pc kk stackptr statep dataptr endp origsp a b c d e f g h.
     nonoverlapping (word pc,4465) (statep:int64,32) /\
     nonoverlapping (word pc,4465) (stackptr:int64,96) /\
     nonoverlapping (statep:int64,32) (stackptr:int64,96)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 29) /\
            read RSP s = stackptr /\
            read RDI s = statep /\
            read RSI s = dataptr /\
            read RDX s = endp /\
            read RAX s = origsp /\
            read (memory :> bytes32 statep) s = (a:int32) /\
            read (memory :> bytes32 (word_add statep (word 4))) s = (b:int32) /\
            read (memory :> bytes32 (word_add statep (word 8))) s = (c:int32) /\
            read (memory :> bytes32 (word_add statep (word 12))) s = (d:int32) /\
            read (memory :> bytes32 (word_add statep (word 16))) s = (e:int32) /\
            read (memory :> bytes32 (word_add statep (word 20))) s = (f:int32) /\
            read (memory :> bytes32 (word_add statep (word 24))) s = (g:int32) /\
            read (memory :> bytes32 (word_add statep (word 28))) s = (h:int32))
       (\s. read RIP s = word (pc + 78) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = word_zx (a:int32) /\
            read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\
            read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\
            read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\
            read R11 s = word_zx (h:int32) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 72))) s = dataptr /\
            read (memory :> bytes64 (word_add stackptr (word 80))) s = endp /\
            read (memory :> bytes64 (word_add stackptr (word 88))) s = origsp)
       (MAYCHANGE [RIP;RAX;RBX;RCX;RDX;R8;R9;R10;R11] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 64));
                   memory :> bytes64 (word_add stackptr (word 72));
                   memory :> bytes64 (word_add stackptr (word 80));
                   memory :> bytes64 (word_add stackptr (word 88))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--13) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REPEAT CONJ_TAC THEN TRY REFL_TAC THEN
  TRY (AP_TERM_TAC THEN CONV_TAC WORD_RULE));;

(* MINI: pc+78 -> pc+87, the 2 loop-top instrs: mov %ebx,%edi ; lea K256,%rbp. *)
(* Strengthened (session-031): the PRE/POST additionally pin RSP/RSI/RAX..R11   *)
(* + slot64(=statep)/slot80(=endp).  These ride the tiny [RIP;RDI;RBP] frame    *)
(* unchanged (no MAYCHANGE touches them), so the closer below is UNALTERED from  *)
(* the original 3-var version.  Needed by the Phase-10 inline loop body, where  *)
(* MINI must deliver the full register/slot state INNER consumes.               *)
let SHA256_BLOCK_NOHW_MINI = prove
 (`!pc kk stackptr dataptr statep endp a b c d e f g h.
     riprel32_within_bounds kk (pc + 87)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 78) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = word_zx (a:int32) /\
            read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\
            read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\
            read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\
            read R11 s = word_zx (h:int32) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 80))) s = endp)
       (\s. read RIP s = word (pc + 87) /\
            read RBP s = word kk /\
            read RDI s = word_zx (b:int32) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = word_zx (a:int32) /\
            read RBX s = word_zx (b:int32) /\
            read RCX s = word_zx (c:int32) /\
            read RDX s = word_zx (d:int32) /\
            read R8 s  = word_zx (e:int32) /\
            read R9 s  = word_zx (f:int32) /\
            read R10 s = word_zx (g:int32) /\
            read R11 s = word_zx (h:int32) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 80))) s = endp)
       (MAYCHANGE [RIP;RDI;RBP] ,, MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--2) THEN
  UNDISCH_TAC
   `read RBP s2 =
      word (val (word (pc + 87):(64)word) +
            val (word_sx (iword (&kk - (&pc + &87)):int32):(64)word):num)` THEN
  IMP_REWRITE_TAC[RIP_REL_ADDR_FOLD] THEN ASM_REWRITE_TAC[] THEN DISCH_TAC THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REPEAT CONJ_TAC THEN TRY REFL_TAC THEN
  TRY (AP_TERM_TAC THEN CONV_TAC WORD_RULE));;

(* TAIL_LP: pc+4355 -> pc+4426, the loop-iteration tail (20 instrs, same as the *)
(* committed TAIL but the POST keeps the register state + RSI advance + CF +    *)
(* RDI=statep that the outer back-edge `jb` needs).  The CF fact is exactly the *)
(* back-edge condition:  read CF s <=> val (dataptr+64) < val endp.  The new     *)
(* working state lands in regs eax..r11d AND memory[statep+4i] (TAIL writes both)*)
(* The nonoverlapping(statep,32)(stackptr,96) hyp is needed so the feed-forward  *)
(* stores at statep don't clobber the carried slot64/slot80 (statep/endp).      *)
let SHA256_BLOCK_NOHW_TAIL_LP = prove
 (`!pc kk stackptr statep dataptr endp va vb vc vd ve vf vg vh r14_in
    s0v s1v s2v s3v s4v s5v s6v s7v.
     nonoverlapping (word pc,4465) (statep:int64,32) /\
     nonoverlapping (statep:int64,32) (stackptr:int64,96)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 4355) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = word_zx (va:int32) /\
            read RBX s = word_zx (vb:int32) /\
            read RCX s = word_zx (vc:int32) /\
            read RDX s = word_zx (vd:int32) /\
            read R8 s  = word_zx (ve:int32) /\
            read R9 s  = word_zx (vf:int32) /\
            read R10 s = word_zx (vg:int32) /\
            read R11 s = word_zx (vh:int32) /\
            read R14 s = word_zx (r14_in:int32) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 80))) s = endp /\
            read (memory :> bytes32 statep) s = (s0v:int32) /\
            read (memory :> bytes32 (word_add statep (word 4))) s = (s1v:int32) /\
            read (memory :> bytes32 (word_add statep (word 8))) s = (s2v:int32) /\
            read (memory :> bytes32 (word_add statep (word 12))) s = (s3v:int32) /\
            read (memory :> bytes32 (word_add statep (word 16))) s = (s4v:int32) /\
            read (memory :> bytes32 (word_add statep (word 20))) s = (s5v:int32) /\
            read (memory :> bytes32 (word_add statep (word 24))) s = (s6v:int32) /\
            read (memory :> bytes32 (word_add statep (word 28))) s = (s7v:int32))
       (\s. read RIP s = word (pc + 4426) /\
            read RSP s = stackptr /\
            read RDI s = statep /\
            read RSI s = word_add dataptr (word 64) /\
            (read CF s <=> val (word_add dataptr (word 64)) < val endp) /\
            read RAX s = word_zx (word_add (word_add va r14_in) s0v) /\
            read RBX s = word_zx (word_add vb s1v) /\
            read RCX s = word_zx (word_add vc s2v) /\
            read RDX s = word_zx (word_add vd s3v) /\
            read R8 s  = word_zx (word_add ve s4v) /\
            read R9 s  = word_zx (word_add vf s5v) /\
            read R10 s = word_zx (word_add vg s6v) /\
            read R11 s = word_zx (word_add vh s7v) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 80))) s = endp /\
            read (memory :> bytes32 statep) s =
                word_add (word_add va r14_in) s0v /\
            read (memory :> bytes32 (word_add statep (word 4))) s =
                word_add vb s1v /\
            read (memory :> bytes32 (word_add statep (word 8))) s =
                word_add vc s2v /\
            read (memory :> bytes32 (word_add statep (word 12))) s =
                word_add vd s3v /\
            read (memory :> bytes32 (word_add statep (word 16))) s =
                word_add ve s4v /\
            read (memory :> bytes32 (word_add statep (word 20))) s =
                word_add vf s5v /\
            read (memory :> bytes32 (word_add statep (word 24))) s =
                word_add vg s6v /\
            read (memory :> bytes32 (word_add statep (word 28))) s =
                word_add vh s7v)
       (MAYCHANGE [RIP;RDI;RSI;RAX;RBX;RCX;RDX;R8;R9;R10;R11] ,,
        MAYCHANGE [memory :> bytes32 statep;
                   memory :> bytes32 (word_add statep (word 4));
                   memory :> bytes32 (word_add statep (word 8));
                   memory :> bytes32 (word_add statep (word 12));
                   memory :> bytes32 (word_add statep (word 16));
                   memory :> bytes32 (word_add statep (word 20));
                   memory :> bytes32 (word_add statep (word 24));
                   memory :> bytes32 (word_add statep (word 28))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--20) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REPEAT CONJ_TAC THEN
  TRY(ASM_REWRITE_TAC[] THEN NO_TAC) THEN
  TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* The single-block lemma (statement, for reference — same shape as block_concl):*)
(*   !pc kk stackptr statep dataptr endp origsp a b c d e f g h m.              *)
(*     <9 nonoverlapping + riprel32_within_bounds kk (pc+87)>                    *)
(*     ==> ensures x86 (pc+29, canonical entry + 16 dataptr reads + K256 bytelist)*)
(*                     (pc+4426, statep+4i = EL i (sha256_block m [a;..;h]))      *)
(*                     (ENTRY ,, INNER ,, TAIL frames).                          *)
(* The verbose explicit form below is retained as documentation of PRE/POST.     *)
let _SHA256_BLOCK_NOHW_BLOCK_STATEMENT_DOC = `T`;;

(*** Original explicit statement (now built programmatically above):
 (`!pc kk stackptr statep dataptr endp origsp a b c d e f g h (m:int32 list).
     nonoverlapping (word pc,4465) (statep:int64,32) /\
     nonoverlapping (word pc,4465) (stackptr:int64,96) /\
     nonoverlapping (statep:int64,32) (stackptr:int64,96) /\
     nonoverlapping (statep:int64,32) (dataptr:int64,64) /\
     nonoverlapping (stackptr:int64,64) (word kk:int64,512) /\
     nonoverlapping (stackptr:int64,64) (dataptr:int64,64) /\
     nonoverlapping (statep:int64,32) (word kk:int64,512) /\
     riprel32_within_bounds kk (pc + 87)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
            read RIP s = word (pc + 29) /\
            read RSP s = stackptr /\
            read RDI s = statep /\
            read RSI s = dataptr /\
            read RDX s = endp /\
            read RAX s = origsp /\
            read (memory :> bytes32 statep) s = (a:int32) /\
            read (memory :> bytes32 (word_add statep (word 4))) s = (b:int32) /\
            read (memory :> bytes32 (word_add statep (word 8))) s = (c:int32) /\
            read (memory :> bytes32 (word_add statep (word 12))) s = (d:int32) /\
            read (memory :> bytes32 (word_add statep (word 16))) s = (e:int32) /\
            read (memory :> bytes32 (word_add statep (word 20))) s = (f:int32) /\
            read (memory :> bytes32 (word_add statep (word 24))) s = (g:int32) /\
            read (memory :> bytes32 (word_add statep (word 28))) s = (h:int32) /\
            read (memory :> bytes32 dataptr) s = word_bytereverse (EL 0 m) /\
            read (memory :> bytes32 (word_add dataptr (word 4))) s = word_bytereverse (EL 1 m) /\
            read (memory :> bytes32 (word_add dataptr (word 8))) s = word_bytereverse (EL 2 m) /\
            read (memory :> bytes32 (word_add dataptr (word 12))) s = word_bytereverse (EL 3 m) /\
            read (memory :> bytes32 (word_add dataptr (word 16))) s = word_bytereverse (EL 4 m) /\
            read (memory :> bytes32 (word_add dataptr (word 20))) s = word_bytereverse (EL 5 m) /\
            read (memory :> bytes32 (word_add dataptr (word 24))) s = word_bytereverse (EL 6 m) /\
            read (memory :> bytes32 (word_add dataptr (word 28))) s = word_bytereverse (EL 7 m) /\
            read (memory :> bytes32 (word_add dataptr (word 32))) s = word_bytereverse (EL 8 m) /\
            read (memory :> bytes32 (word_add dataptr (word 36))) s = word_bytereverse (EL 9 m) /\
            read (memory :> bytes32 (word_add dataptr (word 40))) s = word_bytereverse (EL 10 m) /\
            read (memory :> bytes32 (word_add dataptr (word 44))) s = word_bytereverse (EL 11 m) /\
            read (memory :> bytes32 (word_add dataptr (word 48))) s = word_bytereverse (EL 12 m) /\
            read (memory :> bytes32 (word_add dataptr (word 52))) s = word_bytereverse (EL 13 m) /\
            read (memory :> bytes32 (word_add dataptr (word 56))) s = word_bytereverse (EL 14 m) /\
            read (memory :> bytes32 (word_add dataptr (word 60))) s = word_bytereverse (EL 15 m) /\
            read (memory :> bytelist (word kk,LENGTH K256)) s = K256)
       (\s. read RIP s = word (pc + 4426) /\
            read (memory :> bytes32 statep) s =
                EL 0 (sha256_block m [a;b;c;d;e;f;g;h]) /\
            read (memory :> bytes32 (word_add statep (word 4))) s =
                EL 1 (sha256_block m [a;b;c;d;e;f;g;h]) /\
            read (memory :> bytes32 (word_add statep (word 8))) s =
                EL 2 (sha256_block m [a;b;c;d;e;f;g;h]) /\
            read (memory :> bytes32 (word_add statep (word 12))) s =
                EL 3 (sha256_block m [a;b;c;d;e;f;g;h]) /\
            read (memory :> bytes32 (word_add statep (word 16))) s =
                EL 4 (sha256_block m [a;b;c;d;e;f;g;h]) /\
            read (memory :> bytes32 (word_add statep (word 20))) s =
                EL 5 (sha256_block m [a;b;c;d;e;f;g;h]) /\
            read (memory :> bytes32 (word_add statep (word 24))) s =
                EL 6 (sha256_block m [a;b;c;d;e;f;g;h]) /\
            read (memory :> bytes32 (word_add statep (word 28))) s =
                EL 7 (sha256_block m [a;b;c;d;e;f;g;h]))
       (MAYCHANGE [RIP;RDI;RSI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes32 statep;
                   memory :> bytes32 (word_add statep (word 4));
                   memory :> bytes32 (word_add statep (word 8));
                   memory :> bytes32 (word_add statep (word 12));
                   memory :> bytes32 (word_add statep (word 16));
                   memory :> bytes32 (word_add statep (word 20));
                   memory :> bytes32 (word_add statep (word 24));
                   memory :> bytes32 (word_add statep (word 28))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 64));
                   memory :> bytes64 (word_add stackptr (word 72));
                   memory :> bytes64 (word_add stackptr (word 80));
                   memory :> bytes64 (word_add stackptr (word 88))] ,,
        MAYCHANGE [memory :> bytes32 stackptr;
                   memory :> bytes32 (word_add stackptr (word 4));
                   memory :> bytes32 (word_add stackptr (word 8));
                   memory :> bytes32 (word_add stackptr (word 12));
                   memory :> bytes32 (word_add stackptr (word 16));
                   memory :> bytes32 (word_add stackptr (word 20));
                   memory :> bytes32 (word_add stackptr (word 24));
                   memory :> bytes32 (word_add stackptr (word 28));
                   memory :> bytes32 (word_add stackptr (word 32));
                   memory :> bytes32 (word_add stackptr (word 36));
                   memory :> bytes32 (word_add stackptr (word 40));
                   memory :> bytes32 (word_add stackptr (word 44));
                   memory :> bytes32 (word_add stackptr (word 48));
                   memory :> bytes32 (word_add stackptr (word 52));
                   memory :> bytes32 (word_add stackptr (word 56));
                   memory :> bytes32 (word_add stackptr (word 60))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  CHEAT_TAC);;
