(* ========================================================================= *)
(* Phase 10 — core CORRECT.  Outer multi-block do-while loop wrapped around the  *)
(* single-block body (MINI ; INNER ; TAIL_LP) via ENSURES_WHILE_PUP, prefixed by *)
(* the register-prologue PROL_REG (run once).  Result:                            *)
(*   SHA256_COMPRESS_CORRECT  (core; PC starts after the andq).      *)
(*                                                                                *)
(* Structure (session-034, validated CORE_CORRECT_PROVED on the dev stack):       *)
(*   correct = PROL_REG(once) ⨾ ENSURES_WHILE_PUP num_blocks (pc+78) (pc+4426) inv*)
(*   inv i s = p i s /\ q i s ;  q i = (CF <=> val(dataptr+64i) < val endp).      *)
(*   body leg (PUP SG2) = SHA256_BLOCK_NOHW_BODY_FF (p i -> p(i+1)/\q(i+1),        *)
(*     pc+78->pc+4426), itself MINI⨾INNER⨾TAIL_LP composed inline with the         *)
(*     read-only set (dataq + 64 K-reads + 3 sentinels) threaded through both      *)
(*     seams.  body_leg folds the imp-chain (IMP_IMP) + expands SOME_FLAGS so      *)
(*     BODY_FF's frame matches the scaffold's expanded one.                        *)
(* Reuses the file's committed lemmas SHA256_BLOCK_NOHW_{INNER,MINI,TAIL_LP,       *)
(*   PROL_REG}, SHA256_K256_READS, SHA256_SENTINEL_BYTES, and the toplevel         *)
(*   helpers parts/conjs_of_lam/comp_str/by_comp/is_named/seqop/ens_head_of/        *)
(*   mk_ensures/goal_rodata_var/execup/RECON/SB/EL8_RECONSTRUCT.                    *)
(* ========================================================================= *)

(* ---- local term/util helpers (self-contained; shadow identically-defined  *)
(*      toplevel ones harmlessly) ---- *)
let norm_conv = REWRITE_CONV[WORD_ADD_ASSOC_CONSTS;WORD_ADD_0] THENC
                DEPTH_CONV NUM_ADD_CONV;;
let normt t = try rhs(concl(norm_conv t)) with _ -> t;;
let is_mem c = let cs=comp_str c in String.length cs>=6 && String.sub cs 0 6="memory";;
let is_kread c = is_mem c &&
   (try let _=find_term (fun t->is_const t && fst(dest_const t)="sha256_constants") c
        in true with _->false);;
let is_sentinel c = is_mem c &&
   (try let _=find_term (fun t->is_const t && fst(dest_const t)="bytes8") c
        in true with _->false);;
let at_state sv c = vsubst[sv, `s:x86state`] c;;
let stnames = ["a";"b";"c";"d";"e";"f";"g";"h"];;
let regnames = ["RAX";"RBX";"RCX";"RDX";"R8";"R9";"R10";"R11"];;

(* INNER's PRE conjuncts, kbase:=word kk, flattened — source of K-reads/sentinels.*)
let INNER_i0 = SPECL [`pc:num`;`kk:num`;`word kk:int64`;`stackptr:int64`;
   `dataptr:int64`;`a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;
   `g:int32`;`h:int32`;`m:int32 list`] SHA256_BLOCK_NOHW_INNER;;
let (_,_,iPlam0,_,_) = parts INNER_i0;;
let _,iPc0 = conjs_of_lam iPlam0;;
let kread_terms = map normt (filter is_kread iPc0);;
let sentinel_terms = map normt (filter is_sentinel iPc0);;

let el_hb j ivar =
  vsubst[ivar,`i:num`; mk_small_numeral j,`j:num`]
    `EL j (sha256_hash_blocks (m_fn:num->int32 list) [a;b;c;d;e;f;g;h] i):int32`;;

(* p i s : loop invariant STATE predicate (NO bytes_loaded/RIP — auto-injected). *)
let p_conjs ivar sv =
  let regeq j = mk_eq(parse_term("read "^(el j regnames)^" sQQ"),
                      mk_comb(`word_zx:int32->int64`, el_hb j ivar)) in
  let regeqs = map (fun j -> vsubst[sv,`sQQ:x86state`] (regeq j)) (0--7) in
  let mem_state j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(4*j)^"))" in
    mk_eq(parse_term("read (memory :> bytes32 "^addr^") sQQ"), el_hb j ivar) in
  let memeqs = map (fun j -> vsubst[sv,`sQQ:x86state`] (mem_state j)) (0--7) in
  let rsp  = vsubst[sv,`sQQ:x86state`] (parse_term "read RSP sQQ = stackptr") in
  let rdi  = vsubst[sv,`sQQ:x86state`] (parse_term "read RDI sQQ = statep") in
  let rsi  = vsubst[sv,`sQQ:x86state`; ivar,`i:num`]
               (parse_term "read RSI sQQ = word_add dataptr (word (64*i))") in
  let slot64 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 64))) sQQ = statep") in
  let slot80 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 80))) sQQ = endp") in
  let slot88 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 88))) sQQ = origsp") in
  let dataq = vsubst[sv,`sQQ:x86state`]
       (parse_term
         ("!i' j. i' < num_blocks /\\ j < 16 ==> \
           read (memory :> bytes32 \
             (word_add dataptr (word (64*i' + 4*j)))) sQQ = \
           word_bytereverse (EL j (m_fn i'):int32)")) in
  let kr = map (at_state sv) kread_terms in
  let sn = map (at_state sv) sentinel_terms in
  [rsp; rdi; rsi; slot64; slot80; slot88] @ regeqs @ memeqs @ kr @ sn @ [dataq];;

let q_conj ivar sv =
  vsubst[sv,`sQQ:x86state`; ivar,`i:num`]
    (parse_term
      "(read CF sQQ <=> val (word_add (dataptr:int64) (word (64*i))) < val (endp:int64))");;

let iv_var = `i:num` and sx = `s:x86state`;;
let invariant =
  list_mk_abs([iv_var; sx],
    mk_conj(list_mk_conj (p_conjs iv_var sx), q_conj iv_var sx));;

(* ---- CORRECT statement ---- *)
let correct_pres =
 [ `nonoverlapping (word pc,4465) (statep:int64,32)`;
   `nonoverlapping (word pc,4465) (stackptr:int64,96)`;
   `nonoverlapping (word pc,4465) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (word pc,4465) (word kk:int64,608)`;
   `nonoverlapping (statep:int64,32) (stackptr:int64,96)`;
   `nonoverlapping (statep:int64,32) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (statep:int64,32) (word kk:int64,608)`;
   `nonoverlapping (stackptr:int64,96) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (stackptr:int64,96) (word kk:int64,608)`;
   `0 < num_blocks`;
   `val (dataptr:int64) + 64 * num_blocks < 2 EXP 64`;
   `endp:int64 = word_add dataptr (word (64*num_blocks))`;
   `riprel32_within_bounds kk (pc + 87)` ];;

let correct_PRE =
  let statep_read j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(4*j)^"))" in
    parse_term("read (memory :> bytes32 "^addr^") s = ("^el j stnames^":int32)") in
  let conjs =
    [ `bytes_loaded s (word pc) (sha256_compress_tmc pc kk)`;
      `read RIP s = word (pc + 29)`;
      `read RSP s = stackptr`;
      `read RDI s = statep`;
      `read RSI s = dataptr`;
      `read RDX s = endp`;
      `read RAX s = origsp` ]
    @ (map statep_read (0--7))
    @ [ `read (memory :> bytelist (word kk:int64, LENGTH K256)) s = K256` ;
        parse_term
         "!i' j. i' < num_blocks /\\ j < 16 ==> \
           read (memory :> bytes32 \
             (word_add dataptr (word (64*i' + 4*j)))) s = \
           word_bytereverse (EL j (m_fn i'):int32)" ] in
  mk_abs(`s:x86state`, list_mk_conj conjs);;

let correct_POST =
  let stp j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(4*j)^"))" in
    mk_eq(parse_term("read (memory :> bytes32 "^addr^") s"),
          vsubst[mk_small_numeral j,`j:num`]
            `EL j (sha256_hash_blocks (m_fn:num->int32 list)
                     [a;b;c;d;e;f;g;h] num_blocks):int32`) in
  mk_abs(`s:x86state`,
    list_mk_conj([`read RIP s = word (pc + 4432)`;
                  `read RSP s = stackptr`;
                  `read (memory :> bytes64 (word_add stackptr (word 88))) s =
                       origsp`]
                 @ map stp (0--7)));;

let frame_full =
  `(MAYCHANGE [RIP;RAX;RBX;RCX;RDX;RBP;RDI;RSI;R8;R9;R10;R11;R12;R13;R14;R15] ,,
    MAYCHANGE [memory :> bytes32 statep;
               memory :> bytes32 (word_add statep (word 4));
               memory :> bytes32 (word_add statep (word 8));
               memory :> bytes32 (word_add statep (word 12));
               memory :> bytes32 (word_add statep (word 16));
               memory :> bytes32 (word_add statep (word 20));
               memory :> bytes32 (word_add statep (word 24));
               memory :> bytes32 (word_add statep (word 28))] ,,
    MAYCHANGE [memory :> bytes64 (word_add stackptr (word 64));
               memory :> bytes64 (word_add stackptr (word 72));
               memory :> bytes64 (word_add stackptr (word 80));
               memory :> bytes64 (word_add stackptr (word 88))] ,,
    MAYCHANGE [memory :> bytes32 stackptr;
               memory :> bytes32 (word_add stackptr (word 4));
               memory :> bytes32 (word_add stackptr (word 8));
               memory :> bytes32 (word_add stackptr (word 12));
               memory :> bytes32 (word_add stackptr (word 16));
               memory :> bytes32 (word_add stackptr (word 20));
               memory :> bytes32 (word_add stackptr (word 24));
               memory :> bytes32 (word_add stackptr (word 28));
               memory :> bytes32 (word_add stackptr (word 32));
               memory :> bytes32 (word_add stackptr (word 36));
               memory :> bytes32 (word_add stackptr (word 40));
               memory :> bytes32 (word_add stackptr (word 44));
               memory :> bytes32 (word_add stackptr (word 48));
               memory :> bytes32 (word_add stackptr (word 52));
               memory :> bytes32 (word_add stackptr (word 56));
               memory :> bytes32 (word_add stackptr (word 60))] ,,
    MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`;;

let correct_concl =
  list_mk_forall([`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
                  `dataptr:int64`;`endp:int64`;`origsp:int64`;`num_blocks:num`;
                  `a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;
                  `g:int32`;`h:int32`;`m_fn:num->int32 list`],
    itlist (curry mk_imp) correct_pres
      (mk_ensures `ensures x86` correct_PRE correct_POST frame_full));;

let Q78 = mk_abs(`s:x86state`, list_mk_conj (p_conjs `0` `s:x86state`));;

(* ============================ leg1 (PROL_REG once) ====================== *)
let PROL_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
   `dataptr:int64`;`endp:int64`;`origsp:int64`;`a:int32`;`b:int32`;`c:int32`;
   `d:int32`;`e:int32`;`f:int32`;`g:int32`;`h:int32`] SHA256_BLOCK_NOHW_PROL_REG;;

let match_leg lemma =
  W(fun (asl,w) -> ignore asl;
      let kv = goal_rodata_var w in
      MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kk:num`] lemma)) THEN
      ASM_REWRITE_TAC[]);;
let norm_rule d = CONV_RULE norm_conv d;;
let KDERIVE_ASSUME =
  FIRST_ASSUM(fun th ->
        let c = concl th in
        if is_eq c && (try fst(dest_const(rand c))="K256" with _->false)
        then ASSUME_TAC(norm_rule(MATCH_MP SHA256_K256_READS th)) THEN
             ASSUME_TAC(norm_rule(MATCH_MP SHA256_SENTINEL_BYTES th))
        else NO_TAC);;
let P0_RECON =
  REWRITE_TAC[sha256_hash_blocks] THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REWRITE_TAC[MULT_CLAUSES; WORD_ADD_0; ARITH] THEN
  CONV_TAC(DEPTH_CONV NUM_MULT_CONV) THEN REWRITE_TAC[WORD_ADD_0];;

let leg1 =
  match_leg PROL_i THEN
  MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
   [ W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
     STRIP_TAC THEN ASM_REWRITE_TAC[];
     CONJ_TAC THENL [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC; ALL_TAC] THEN
     W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
     W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
     REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
     KDERIVE_ASSUME THEN
     REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
     REWRITE_TAC[GSYM SEQ_ASSOC] THEN
     PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
     CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
     REWRITE_TAC[ASSIGNS_THM] THEN
     REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
     NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
     ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC) THEN
     P0_RECON THEN ASM_REWRITE_TAC[] ];;

(* ============================ CF legs (back-edge + exit) ================= *)
let CFLT = prove
 (`!(dataptr:int64) i num_blocks.
     i < num_blocks /\ val dataptr + 64 * num_blocks < 2 EXP 64
     ==> val (word_add dataptr (word (64*i))) <
         val (word_add dataptr (word (64*num_blocks)))`,
  REPEAT STRIP_TAC THEN
  REWRITE_TAC[VAL_WORD_ADD; VAL_WORD; DIMINDEX_64] THEN
  SUBGOAL_THEN `(64 * i) MOD 2 EXP 64 = 64 * i /\
                (64 * num_blocks) MOD 2 EXP 64 = 64 * num_blocks`
    (CONJUNCTS_THEN SUBST1_TAC) THENL
   [CONJ_TAC THEN MATCH_MP_TAC MOD_LT THEN ASM_ARITH_TAC; ALL_TAC] THEN
  SUBGOAL_THEN `(val(dataptr:int64) + 64 * i) MOD 2 EXP 64 =
                 val dataptr + 64 * i /\
                (val(dataptr:int64) + 64 * num_blocks) MOD 2 EXP 64 =
                 val dataptr + 64 * num_blocks`
    (CONJUNCTS_THEN SUBST1_TAC) THENL
   [CONJ_TAC THEN MATCH_MP_TAC MOD_LT THEN ASM_ARITH_TAC; ASM_ARITH_TAC]);;

let endp_def = `endp:int64 = word_add dataptr (word (64 * num_blocks))`;;

let leg_back =
  REPEAT STRIP_TAC THEN
  SUBGOAL_THEN `val (word_add (dataptr:int64) (word (64*i))) <
                val (word_add dataptr (word (64*num_blocks)))`
    ASSUME_TAC THENL
   [ MATCH_MP_TAC CFLT THEN ASM_REWRITE_TAC[]; ALL_TAC ] THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--1) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME endp_def]) THEN ASM_REWRITE_TAC[];;

let leg_exit =
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--1) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME endp_def]) THEN
  ASM_REWRITE_TAC[LT_REFL];;

(* ============================ BODY_FF (inline body leg) ================== *)
let HB iv = vsubst[iv,`i:num`]
  `sha256_hash_blocks (m_fn:num->int32 list) [a;b;c;d;e;f;g;h] i`;;
let elhb iv j = mk_comb(mk_comb(`EL:num->int32 list->int32`, mk_small_numeral j), HB iv);;

let iv = `i:num` and ip1 = `i + 1` and sxv = `s:x86state`;;
let dptr_i = `word_add dataptr (word (64*i)):int64`;;

let INNER_i = SPECL [`pc:num`;`kk:num`;`word kk:int64`;`stackptr:int64`;
   dptr_i; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3; elhb iv 4; elhb iv 5;
   elhb iv 6; elhb iv 7; `(m_fn:num->int32 list) i`] SHA256_BLOCK_NOHW_INNER;;
let (_,ihyps,iPlam,iQlam,iC) = parts INNER_i;;
let sI,iPc = conjs_of_lam iPlam;;
let _,iQc = conjs_of_lam iQlam;;
let bighyp_i = hd ihyps;;
let zx_arg comp = rand(rhs_of(by_comp comp iQc));;

let MINI_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`; dptr_i;
   `statep:int64`;`endp:int64`; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3;
   elhb iv 4; elhb iv 5; elhb iv 6; elhb iv 7] SHA256_BLOCK_NOHW_MINI;;
let (_,_,mPlam,mQlam,mC) = parts MINI_i;;
let sM,mPc = conjs_of_lam mPlam;;

let TAILLP_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
   dptr_i;`endp:int64`; zx_arg "RAX"; zx_arg "RBX"; zx_arg "RCX";
   zx_arg "RDX"; zx_arg "R8"; zx_arg "R9"; zx_arg "R10"; zx_arg "R11";
   zx_arg "R14"; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3; elhb iv 4;
   elhb iv 5; elhb iv 6; elhb iv 7] SHA256_BLOCK_NOHW_TAIL_LP;;
let (_,_,tPlam,tQlam,tC) = parts TAILLP_i;;
let sT,tPc = conjs_of_lam tPlam;;
let _,tQc = conjs_of_lam tQlam;;

let pconj_i  = p_conjs iv  sxv;;
let pconj_ip1 = p_conjs ip1 sxv;;
(* read-only / frame-preserved facts that ride every segment frame untouched:    *)
(* the 64 K-reads, 3 sentinels, the quantified dataq, AND slot88=origsp (in no    *)
(* segment's PRE/POST — unlike slot64/80 which ride MINI/TAIL_LP statements).      *)
let ro_i = filter (fun c -> is_kread c || is_sentinel c || not(is_eq c) ||
                            vfree_in `origsp:int64` c) pconj_i;;

let statep_read_i sv j =
  let addr = if j=0 then "statep" else "(word_add statep (word "^string_of_int(4*j)^"))" in
  mk_eq(parse_term("read (memory :> bytes32 "^addr^") sQQ"), elhb iv j)
  |> vsubst[sv,`sQQ:x86state`];;
let slot64v sv = vsubst[sv,`sQQ:x86state`]
   (parse_term "read (memory :> bytes64 (word_add stackptr (word 64))) sQQ = statep");;
let slot80v sv = vsubst[sv,`sQQ:x86state`]
   (parse_term "read (memory :> bytes64 (word_add stackptr (word 80))) sQQ = endp");;

let drop c = is_named "bytes_loaded" c || comp_str c = "RIP";;
let q87_inner = map normt (filter (fun c -> not(drop c)) iPc);;
let q87_extra = (map (statep_read_i sI) (0--7)) @ [slot64v sI; slot80v sI];;
let ro_at sv = map (vsubst[sv,sxv]) ro_i;;
let already c = exists (fun d -> aconv c d) (q87_inner @ q87_extra);;
let q87_ro = filter (fun c -> not(already c)) (ro_at sI);;
let bodyQ87 = mk_abs(sI, list_mk_conj (q87_inner @ q87_extra @ q87_ro));;

let q4355_tl = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c<>"RIP") tPc;;
let already2 c = exists (fun d -> aconv c d) q4355_tl;;
let q4355_ro = filter (fun c -> not(already2 c)) (ro_at sT);;
let bodyQ4355 = mk_abs(sT, list_mk_conj (q4355_tl @ q4355_ro));;

(* BODY_FF statement on frame_full with p(i+1) GROUPED (so the POST conjunct      *)
(* structure equals the PUP body subgoal's `pd /\ rip /\ p(i+1) s /\ q(i+1) s`).  *)
let ff_PRE =
  mk_abs(sxv, list_mk_conj
    (`bytes_loaded s (word pc) (sha256_compress_tmc pc kk)` ::
     `read RIP s = word (pc + 78)` :: pconj_i));;
let ff_POST =
  mk_abs(sxv, list_mk_conj
    [`bytes_loaded s (word pc) (sha256_compress_tmc pc kk)`;
     `read RIP s = word (pc + 4426)`;
     list_mk_conj pconj_ip1;
     q_conj ip1 sxv]);;
let ff_FRAME = frame_full;;
let ff_hyps = correct_pres @ [`i < num_blocks`; `~(i = num_blocks)`];;
let ff_vars =
  [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;`dataptr:int64`;
   `endp:int64`;`origsp:int64`;`num_blocks:num`;`i:num`;`a:int32`;`b:int32`;
   `c:int32`;`d:int32`;`e:int32`;`f:int32`;`g:int32`;`h:int32`;
   `m_fn:num->int32 list`];;
let eh = ens_head_of INNER_i;;
let ff_body0 = itlist (curry mk_imp) ff_hyps (mk_ensures eh ff_PRE ff_POST ff_FRAME);;
let stray_tyvars =
  itlist (fun v acc ->
     let n = fst(dest_var v) in
     if (n="i" || n="num_blocks") && type_of v <> `:num`
     then union (tyvars (type_of v)) acc else acc)
    (frees ff_body0) [];;
let ff_body = inst (map (fun tv -> (`:num`,tv)) stray_tyvars) ff_body0;;
let ff_concl = list_mk_forall(ff_vars, ff_body);;

(* ---- BODY_FF proof tactic (augment PRE with 16 explicit msg reads from dataq, *)
(*      then compose MINI;INNER;TAIL_LP threading the read-only set) ---- *)
let msg_reads_i =
  filter (fun c -> is_mem c &&
     (try let _=find_term (fun t->is_const t &&
             fst(dest_const t)="word_bytereverse") c in true with _->false))
    iPc;;
let msg_template = map normt msg_reads_i;;
let aug_of_prelam plam =
  let sv,body = dest_abs plam in
  let rsi = find (fun c -> try comp_str c = "RSI" with _ -> false) (conjuncts body) in
  let gi = rand(rand(rand(rhs_of rsi))) in
  let msgs = map (fun c -> vsubst[sv,sI; gi,`i:num`] c) msg_template in
  mk_abs(sv, list_mk_conj (conjuncts body @ msgs));;

let sublem_a = ENSURES_SUBLEMMA_TAC execup;;
let INNER_HYP_CLOSER =
  REWRITE_TAC[NONOVERLAPPING_CLAUSES] THEN REPEAT CONJ_TAC THEN
  (NONOVERLAPPING_TAC ORELSE CONV_TAC WORD_REDUCE_CONV ORELSE CONV_TAC WORD_RULE);;
let SEAM_RECON =
  REWRITE_TAC[WORD_ADD_ASSOC_CONSTS; WORD_ADD_0] THEN
  CONV_TAC(DEPTH_CONV NUM_ADD_CONV) THEN ASM_REWRITE_TAC[];;

let mini_leg = match_leg MINI_i THEN sublem_a "s" "s'" THEN SEAM_RECON;;
let inner_leg =
  SUBGOAL_THEN bighyp_i ASSUME_TAC THENL
   [ INNER_HYP_CLOSER;
     match_leg INNER_i THEN sublem_a "s" "s'" THEN SEAM_RECON ];;

let HBSTEP =
  prove(`sha256_hash_blocks (m_fn:num->int32 list) [a;b;c;d;e;f;g;h] (i+1) =
         sha256_block (m_fn i)
           (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i)`,
        REWRITE_TAC[sha256_hash_blocks]);;
let HBLIST =
  prove(`[EL 0 (sha256_hash_blocks (m_fn:num->int32 list) [a;b;c;d;e;f;g;h] i);
          EL 1 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 2 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 3 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 4 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 5 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 6 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 7 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i)] =
         sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i`,
        MATCH_MP_TAC EL8_RECONSTRUCT THEN
        MATCH_MP_TAC LENGTH_SHA256_HASH_BLOCKS THEN
        REWRITE_TAC[LENGTH] THEN ARITH_TAC);;
let SB_GEN =
  prove(`!m hsh j. j < 8
         ==> EL j (sha256_block m hsh) =
             word_add (EL j (sha256_compress_rounds m hsh 64)) (EL j hsh)`,
        REWRITE_TAC[sha256_block] THEN REPEAT GEN_TAC THEN
        CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
        REWRITE_TAC[ARITH_RULE `j < 8 <=> j = 0 \/ j = 1 \/ j = 2 \/ j = 3 \/
                                j = 4 \/ j = 5 \/ j = 6 \/ j = 7`] THEN
        STRIP_TAC THEN ASM_REWRITE_TAC[] THEN
        CONV_TAC(ONCE_DEPTH_CONV EL_CONV) THEN REWRITE_TAC[]);;
let RSI_ADV = prove
 (`word_add (word_add (dataptr:int64) (word (64 * i))) (word 64) =
   word_add dataptr (word (64 * (i + 1)))`,
  SUBST1_TAC(ARITH_RULE `64 * (i + 1) = 64 * i + 64`) THEN
  CONV_TAC WORD_RULE);;
let taillp_reconcile =
  REWRITE_TAC[HBSTEP] THEN SIMP_TAC[SB_GEN; ARITH] THEN
  REWRITE_TAC[HBLIST] THEN
  REWRITE_TAC[RSI_ADV] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[RECON; RSI_ADV; HBLIST]) THEN
  REWRITE_TAC[RECON] THEN ASM_REWRITE_TAC[];;
let taillp_leg =
  match_leg TAILLP_i THEN sublem_a "s" "s'" THEN taillp_reconcile;;

let MSGREAD_ONE =
  W(fun (asl,w) ->
     let elapp = rand(rand w) in
     let jv = rand(rator elapp) in
     let iv2 = rand(rand elapp) in
     FIRST_X_ASSUM(fun th ->
        if is_forall(concl th) then MP_TAC(SPECL [iv2; jv] th) else NO_TAC) THEN
     ANTS_TAC THENL [ASM_ARITH_TAC; ALL_TAC] THEN
     DISCH_THEN(fun dth ->
        let gaddr = rand(rand(rand(rator(lhs w)))) in
        let daddr = rand(rand(rand(rator(lhs(concl dth))))) in
        SUBGOAL_THEN (mk_eq(gaddr, daddr))
          (fun aeq -> REWRITE_TAC[aeq] THEN ACCEPT_TAC dth)) THEN
     CONV_TAC WORD_RULE);;
let DERIVE_MSG_READS = REPEAT CONJ_TAC THEN MSGREAD_ONE;;

let compose_tac =
  ENSURES_SEQUENCE_TAC `pc + 87` bodyQ87 THEN CONJ_TAC THENL
   [ mini_leg;
     ENSURES_SEQUENCE_TAC `pc + 4355` bodyQ4355 THEN CONJ_TAC THENL
      [ inner_leg; taillp_leg ] ];;

let body_ff_tac =
  REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN REPEAT DISCH_TAC THEN
  MATCH_MP_TAC ENSURES_PRECONDITION_THM THEN
  W(fun (asl,w) ->
     let imp = lhand(body(rand w)) in
     let pprime = rator(lhand(snd(dest_forall imp))) in
     EXISTS_TAC (aug_of_prelam pprime)) THEN
  CONJ_TAC THENL
   [ GEN_TAC THEN REWRITE_TAC[] THEN
     DISCH_THEN(STRIP_ASSUME_TAC o CONV_RULE(TOP_DEPTH_CONV BETA_CONV)) THEN
     ASM_REWRITE_TAC[] THEN DERIVE_MSG_READS;
     compose_tac ];;

let SHA256_BLOCK_NOHW_BODY_FF = prove(ff_concl, body_ff_tac);;

(* ============================ assemble core CORRECT ===================== *)
(* body leg: fold BODY_FF's imp-chain (IMP_IMP) + expand SOME_FLAGS so its frame *)
(* matches the scaffold's expanded `[CF;PF;AF;ZF;SF;OF]` (session-034).           *)
let body_leg =
  REPEAT STRIP_TAC THEN
  MATCH_MP_TAC (REWRITE_RULE[SOME_FLAGS; IMP_IMP] SHA256_BLOCK_NOHW_BODY_FF) THEN
  ASM_REWRITE_TAC[] THEN TRY ASM_ARITH_TAC;;

let SHA256_COMPRESS_CORRECT = prove(correct_concl,
  REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN REPEAT STRIP_TAC THEN
  ENSURES_SEQUENCE_TAC `pc + 78` Q78 THEN CONJ_TAC THENL
   [ leg1;
     ENSURES_WHILE_PUP_TAC `num_blocks:num` `pc + 78` `pc + 4426` invariant THEN
     REPEAT CONJ_TAC THENL
      [ ASM_ARITH_TAC;
        (ENSURES_INIT_TAC "s0" THEN ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[]);
        body_leg; leg_back; leg_exit ] ]);;

(* ======================================================================== *)
(* Phase 11 — SysV subroutine CORRECT (NOIBT + IBT).                         *)
(* Wraps the core SHA256_COMPRESS_CORRECT with the prologue/     *)
(* epilogue. The transpiler epilogue is NON-pop (recovers caller-SP from      *)
(* slot88 via `mov 88(%rsp),%rsi`), so we hand-assemble the wrapper using the *)
(* keccak4-style dynamic and-rsp alignment-delta pattern rather than the      *)
(* canned GEN_X86_ADD_RETURN_STACK_TAC.                                       *)
(*                                                                            *)
(* The data<->stack-frame nonoverlapping regions are 215 = 207-byte frame +   *)
(* the 8-byte return slot at entry-SP (cf. keccak4's `0x37f + 8`): the `ret`  *)
(* reads the return address at entry-SP (= stackpointer+207 after the +207    *)
(* offset shift), which sits just OUTSIDE the 207-byte frame, so STATE_UPDATE *)
(* needs RA-slot ⊥ statep to carry the return address across the core BIGSTEP.*)
(* ======================================================================== *)

(* mc = APPEND [endbr64] (tmc (pc+4)), for the IBT lift via ADD_IBT_RULE ~bridge *)
let SHA256_COMPRESS_MC_BRIDGE = prove
 (`!pc kk. sha256_compress_mc pc kk =
     APPEND [word 0xf3:byte; word 0x0f; word 0x1e; word 0xfa]
            (sha256_compress_tmc (pc + 4) kk)`,
  REPEAT GEN_TAC THEN
  REWRITE_TAC[sha256_compress_mc;
              sha256_compress_tmc; APPEND] THEN
  REWRITE_TAC[GSYM INT_OF_NUM_ADD] THEN
  REWRITE_TAC[INT_ARITH `(&pc + &4) + &87 = &pc + &91:int`] THEN
  REWRITE_TAC[]);;

let LEN_K256 = CONV_RULE (RAND_CONV LENGTH_CONV)
                 (AP_TERM `LENGTH:byte list->num` K256_DATA);;

let K_BYTES_FORM = prove
 (`bytes_loaded s (word kk:int64) K256 <=>
   read (memory :> bytes (word kk:int64,608)) s = num_of_bytelist K256`,
  REWRITE_TAC[bytes_loaded; READ_BYTELIST_EQ_BYTES; LEN_K256]);;

let ra_fact = ref TRUTH;;

let SHA256_COMPRESS_NOIBT_SUBROUTINE_CORRECT = prove
 (`!pc kk statep dataptr (num_blocks:num)
    a b c d e f g h (m_fn:num->int32 list) stackpointer returnaddress.
   riprel32_within_bounds kk (pc + 87) /\
   nonoverlapping (word pc,4465) (statep:int64,32) /\
   nonoverlapping (word pc,4465) (word_sub stackpointer (word 207):int64,215) /\
   nonoverlapping (word pc,4465) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (word pc,4465) (word kk:int64,608) /\
   nonoverlapping (statep:int64,32) (word_sub stackpointer (word 207):int64,215) /\
   nonoverlapping (statep:int64,32) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (statep:int64,32) (word kk:int64,608) /\
   nonoverlapping (word_sub stackpointer (word 207):int64,215) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (word_sub stackpointer (word 207):int64,215) (word kk:int64,608) /\
   0 < num_blocks /\
   val (dataptr:int64) + 64 * num_blocks < 2 EXP 64
   ==> ensures x86
        (\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
             read RIP s = word pc /\
             read RSP s = stackpointer /\
             read (memory :> bytes64 stackpointer) s = returnaddress /\
             C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
             read (memory :> bytes32 statep) s = (a:int32) /\
             read (memory :> bytes32 (word_add statep (word 4))) s = (b:int32) /\
             read (memory :> bytes32 (word_add statep (word 8))) s = (c:int32) /\
             read (memory :> bytes32 (word_add statep (word 12))) s = (d:int32) /\
             read (memory :> bytes32 (word_add statep (word 16))) s = (e:int32) /\
             read (memory :> bytes32 (word_add statep (word 20))) s = (f:int32) /\
             read (memory :> bytes32 (word_add statep (word 24))) s = (g:int32) /\
             read (memory :> bytes32 (word_add statep (word 28))) s = (h:int32) /\
             bytes_loaded s (word kk) K256 /\
             (!i' j. i' < num_blocks /\ j < 16
                     ==> read (memory :> bytes32
                           (word_add dataptr (word (64*i' + 4*j)))) s =
                         word_bytereverse (EL j (m_fn i'):int32)))
        (\s. read RIP s = returnaddress /\
             read RSP s = word_add stackpointer (word 8) /\
             read (memory :> bytes32 statep) s =
               EL 0 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 4))) s =
               EL 1 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 8))) s =
               EL 2 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 12))) s =
               EL 3 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 16))) s =
               EL 4 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 20))) s =
               EL 5 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 24))) s =
               EL 6 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 28))) s =
               EL 7 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks))
        (MAYCHANGE [RSP] ,, MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
         MAYCHANGE [memory :> bytes32 statep;
                    memory :> bytes32 (word_add statep (word 4));
                    memory :> bytes32 (word_add statep (word 8));
                    memory :> bytes32 (word_add statep (word 12));
                    memory :> bytes32 (word_add statep (word 16));
                    memory :> bytes32 (word_add statep (word 20));
                    memory :> bytes32 (word_add statep (word 24));
                    memory :> bytes32 (word_add statep (word 28))] ,,
         MAYCHANGE [memory :> bytes (word_sub stackpointer (word 207),207)])`,
  REWRITE_TAC[MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI; C_ARGUMENTS;
              fst SHA256_COMPRESS_EXEC] THEN
  REPLICATE_TAC 14 GEN_TAC THEN
  WORD_FORALL_OFFSET_TAC 207 THEN
  REWRITE_TAC[K_BYTES_FORM] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_PRESERVED_TAC "rbx_init" `RBX` THEN
  ENSURES_PRESERVED_TAC "rbp_init" `RBP` THEN
  ENSURES_PRESERVED_TAC "r12_init" `R12` THEN
  ENSURES_PRESERVED_TAC "r13_init" `R13` THEN
  ENSURES_PRESERVED_TAC "r14_init" `R14` THEN
  ENSURES_PRESERVED_TAC "r15_init" `R15` THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--11) THEN
  (* capture the s11 return-address fact into a ref (runs at proof time) *)
  W(fun (asl,w) ->
     let isra (_,th) =
       let c = concl th in
       (try let _ = find_term (fun t -> try fst(dest_var t)="returnaddress"
                                        with _->false) c in is_eq c
        with _->false) in
     ra_fact := snd (List.find isra asl); ALL_TAC) THEN
  ABBREV_TAC
   `delta =
    val(word_sub (word 63)
                 (word_and (word_add stackpointer (word 63)) (word 63)):int64)` THEN
  SUBGOAL_THEN `delta <= 63` ASSUME_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `word_and (word_add stackpointer (word 63)) (word 18446744073709551552):int64 =
    word_add stackpointer (word delta)`
  SUBST_ALL_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `4 * val (word_shl (word num_blocks:int64) 4) = 64 * num_blocks`
  ASSUME_TAC THENL
   [REWRITE_TAC[VAL_WORD_SHL; VAL_WORD; DIMINDEX_64] THEN
    REWRITE_TAC[ARITH_RULE `2 EXP 4 = 16`] THEN
    SUBGOAL_THEN `num_blocks MOD 2 EXP 64 = num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 64 * n < 2 EXP 64 ==> n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    SUBGOAL_THEN `(16 * num_blocks) MOD 2 EXP 64 = 16 * num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 64 * n < 2 EXP 64 ==> 16 * n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    ARITH_TAC; ALL_TAC] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME
    `4 * val (word_shl (word num_blocks:int64) 4) = 64 * num_blocks`]) THEN
  SUBGOAL_THEN
   `read (memory :> bytelist (word kk:int64,LENGTH K256)) s11 = K256`
  ASSUME_TAC THENL
   [REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K256] THEN ASM_REWRITE_TAC[]; ALL_TAC] THEN
  MP_TAC(REWRITE_RULE[IMP_IMP] (SPECL
   [`pc:num`; `kk:num`; `word_add stackpointer (word delta):int64`;
    `statep:int64`; `dataptr:int64`;
    `word_add dataptr (word (64*num_blocks)):int64`;
    `word_add stackpointer (word 207):int64`; `num_blocks:num`;
    `a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;`g:int32`;`h:int32`;
    `m_fn:num->int32 list`]
   SHA256_COMPRESS_CORRECT)) THEN
  ANTS_TAC THENL
   [REPEAT CONJ_TAC THEN
    (NONOVERLAPPING_TAC ORELSE ASM_REWRITE_TAC[]); ALL_TAC] THEN
  REWRITE_TAC[SOME_FLAGS] THEN
  X86_BIGSTEP_TAC SHA256_COMPRESS_EXEC "s12" THEN
  ABBREV_TAC `asp:int64 = word_add stackpointer (word delta)` THEN
  (* BLOCKER C: re-derive the return-address fact at s12 across the core frame.
     The deref of ra_fact is DEFERRED to proof time via W(...) (an eager
     `ASSUME_TAC(!ra_fact)` would bake in TRUTH). With the 215-widened hyps,
     STATE_UPDATE_RULE can prove RA-slot ⊥ statep so the fact carries. *)
  SUBGOAL_THEN
   `read (memory :> bytes64 (word_add stackpointer (word 207))) s12 = returnaddress`
  ASSUME_TAC THENL
   [W(fun (asl,w) -> ASSUME_TAC(!ra_fact)) THEN
    FIRST_X_ASSUM(MP_TAC o check (maychange_term o concl)) THEN
    REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
    REWRITE_TAC[GSYM SEQ_ASSOC] THEN
    PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
    CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
    REWRITE_TAC[ASSIGNS_THM] THEN
    REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
    ASSUMPTION_STATE_UPDATE_TAC THEN
    DISCH_THEN(K ALL_TAC) THEN
    ASM_REWRITE_TAC[]; ALL_TAC] THEN
  X86_STEPS_TAC SHA256_COMPRESS_EXEC (13--21) THEN
  (* undo the asp abbreviation in the asms so CONTAINED_TAC in the frame
     subsumption can relate the asp-keyed writes to stackpointer (delta<=63). *)
  RULE_ASSUM_TAC(REWRITE_RULE[SYM(ASSUME
     `word_add stackpointer (word delta):int64 = asp`)]) THEN
  ENSURES_FINAL_STATE_TAC THEN
  REPEAT CONJ_TAC THEN
  TRY MONOTONE_MAYCHANGE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  TRY(CONV_TAC WORD_RULE));;

let SHA256_COMPRESS_SUBROUTINE_CORRECT = prove
 (`!pc kk statep dataptr (num_blocks:num)
    a b c d e f g h (m_fn:num->int32 list) stackpointer returnaddress.
   riprel32_within_bounds kk (pc + 91) /\
   nonoverlapping (word pc,4469) (statep:int64,32) /\
   nonoverlapping (word pc,4469) (word_sub stackpointer (word 207):int64,215) /\
   nonoverlapping (word pc,4469) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (word pc,4469) (word kk:int64,608) /\
   nonoverlapping (statep:int64,32) (word_sub stackpointer (word 207):int64,215) /\
   nonoverlapping (statep:int64,32) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (statep:int64,32) (word kk:int64,608) /\
   nonoverlapping (word_sub stackpointer (word 207):int64,215) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (word_sub stackpointer (word 207):int64,215) (word kk:int64,608) /\
   0 < num_blocks /\
   val (dataptr:int64) + 64 * num_blocks < 2 EXP 64
   ==> ensures x86
        (\s. bytes_loaded s (word pc) (sha256_compress_mc pc kk) /\
             read RIP s = word pc /\
             read RSP s = stackpointer /\
             read (memory :> bytes64 stackpointer) s = returnaddress /\
             C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
             read (memory :> bytes32 statep) s = (a:int32) /\
             read (memory :> bytes32 (word_add statep (word 4))) s = (b:int32) /\
             read (memory :> bytes32 (word_add statep (word 8))) s = (c:int32) /\
             read (memory :> bytes32 (word_add statep (word 12))) s = (d:int32) /\
             read (memory :> bytes32 (word_add statep (word 16))) s = (e:int32) /\
             read (memory :> bytes32 (word_add statep (word 20))) s = (f:int32) /\
             read (memory :> bytes32 (word_add statep (word 24))) s = (g:int32) /\
             read (memory :> bytes32 (word_add statep (word 28))) s = (h:int32) /\
             bytes_loaded s (word kk) K256 /\
             (!i' j. i' < num_blocks /\ j < 16
                     ==> read (memory :> bytes32
                           (word_add dataptr (word (64*i' + 4*j)))) s =
                         word_bytereverse (EL j (m_fn i'):int32)))
        (\s. read RIP s = returnaddress /\
             read RSP s = word_add stackpointer (word 8) /\
             read (memory :> bytes32 statep) s =
               EL 0 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 4))) s =
               EL 1 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 8))) s =
               EL 2 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 12))) s =
               EL 3 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 16))) s =
               EL 4 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 20))) s =
               EL 5 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 24))) s =
               EL 6 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 28))) s =
               EL 7 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks))
        (MAYCHANGE [RSP] ,, MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
         MAYCHANGE [memory :> bytes32 statep;
                    memory :> bytes32 (word_add statep (word 4));
                    memory :> bytes32 (word_add statep (word 8));
                    memory :> bytes32 (word_add statep (word 12));
                    memory :> bytes32 (word_add statep (word 16));
                    memory :> bytes32 (word_add statep (word 20));
                    memory :> bytes32 (word_add statep (word 24));
                    memory :> bytes32 (word_add statep (word 28))] ,,
         MAYCHANGE [memory :> bytes (word_sub stackpointer (word 207),207)])`,
  MATCH_ACCEPT_TAC(ADD_IBT_RULE
    ~bridge:(Some SHA256_COMPRESS_MC_BRIDGE)
    SHA256_COMPRESS_NOIBT_SUBROUTINE_CORRECT));;


