let sha256_compress_windows_tmc =
  define_trimmed "sha256_compress_windows_tmc"
                 sha256_compress_windows_mc;;

let SHA256_WIN_EXEC = X86_MK_EXEC_RULE sha256_compress_windows_tmc;;

(* ======================================================================== *)
(* Phase 12 — Windows subroutine CORRECT: shared infrastructure.             *)
(*                                                                            *)
(* The Windows .obj is the INLINE-SHIM model: its trimmed machine code is     *)
(*   windows_tmc pc kk = shim(11) ++ COMMON(4464) ++ [pop rsi; pop rdi; ret]  *)
(* where shim(11) = push rdi; push rsi; mov rcx->rdi; mov rdx->rsi; mov r8->rdx*)
(* and COMMON is byte-identical to BUTLAST(sysv_tmc) modulo the riprel LEA-    *)
(* K256 displacement, which shifts by the 11-byte shim ((&pc+11)+87 = &pc+98).*)
(* The SysV tmc = COMMON ++ [ret]; the Windows image lacks the SysV trailing   *)
(* `ret` (it has `pop rsi` there), so ONLY BUTLAST(sysv_tmc) is a subprogram   *)
(* of windows_tmc. The canned WINDOWS_X86_WRAP_STACK_TAC and                   *)
(* BYTES_LOADED_SUBPROGRAM_RULE do not apply (they need concrete byte lists;   *)
(* our reloc-mc carries the symbolic riprel atom), so we hand-roll the wrapper.*)
(* ======================================================================== *)

(* ---- Windows machine code (mc/tmc/EXEC), from the Windows .obj. ---- *)
(* (defined in the windefs prefix: sha256_compress_windows_mc /  *)
(*  _windows_tmc / SHA256_WIN_EXEC, constant K256W.)                          *)

(* ---- The 11-byte ABI shim prefix and the 3-byte non-pop epilogue tail. --- *)
let WIN_SHIM11 = `[word 0x57; word 0x56; word 0x48; word 0x89; word 0xcf;
   word 0x48; word 0x89; word 0xd6; word 0x4c; word 0x89; word 0xc2]:byte list`;;
let WIN_TAIL3  = `[word 94; word 95; word 195]:byte list`;;

(* ---- WIN_DECOMP: windows_tmc = shim ++ BUTLAST(sysv_tmc @ pc+11) ++ tail. - *)
let SHA256_WIN_RIPREL_ALIGN = INT_ARITH `(&pc + &11) + &87:int = &pc + &98`;;
let SHA256_WIN_DECOMP =
  let appf = `APPEND:byte list->byte list->byte list` in
  let butl = `BUTLAST (sha256_compress_tmc (pc+11) kk)` in
  let rhs_tm = mk_comb(mk_comb(appf, WIN_SHIM11),
                mk_comb(mk_comb(appf, butl), WIN_TAIL3)) in
  prove
   (mk_eq(`sha256_compress_windows_tmc pc kk`, rhs_tm),
    REWRITE_TAC[sha256_compress_windows_tmc;
                sha256_compress_tmc] THEN
    REWRITE_TAC[BUTLAST_CLAUSES; APPEND] THEN
    REWRITE_TAC[GSYM INT_OF_NUM_ADD] THEN
    REWRITE_TAC[SHA256_WIN_RIPREL_ALIGN] THEN REWRITE_TAC[]);;

(* ---- WIN_BODY_BRIDGE: the windows->sysv-body bytes_loaded bridge. -------- *)
let SHA256_WIN_BODY_BRIDGE = prove
 (`bytes_loaded s (word pc) (sha256_compress_windows_tmc pc kk)
   ==> bytes_loaded s (word (pc + 11))
          (BUTLAST (sha256_compress_tmc (pc + 11) kk))`,
  REWRITE_TAC[SHA256_WIN_DECOMP; bytes_loaded_append; LENGTH] THEN
  CONV_TAC NUM_REDUCE_CONV THEN
  REWRITE_TAC[GSYM WORD_ADD; WORD_ADD_0] THEN
  REWRITE_TAC[ARITH_RULE `pc + 11 = 11 + pc`] THEN
  STRIP_TAC THEN ASM_REWRITE_TAC[]);;

(* ---- bl_tmc: the BUTLAST core program + its EXEC (decode rows [0,4464)). - *)
(* X86_MK_EXEC on BUTLAST of the reloc tmc fails via AP_TERM (X86_TRIM_EXEC),  *)
(* so we name the reduced BUTLAST list as its own constant and MK_EXEC that.   *)
let sha256_compress_bl_tmc = new_definition
 `sha256_compress_bl_tmc pc kk =
    BUTLAST (sha256_compress_tmc pc kk)`;;

let SHA256_BL_TMC_RED =
  REWRITE_RULE[sha256_compress_tmc; BUTLAST_CLAUSES]
    (SPEC_ALL sha256_compress_bl_tmc);;

let SHA256_BL_EXEC = X86_MK_EXEC_RULE SHA256_BL_TMC_RED;;

(* ---- WINDOWS_MC_BRIDGE: windows_mc = [endbr] ++ windows_tmc(pc+4), for IBT. *)
(* The windows mc trims the 4-byte endbr; the riprel offset in the windows mc  *)
(* is pc+102 (=98+4) vs pc+98 in the tmc, realigned by (&pc+4)+98 = &pc+102.   *)
let SHA256_COMPRESS_WINDOWS_MC_BRIDGE = prove
 (`!pc kk. sha256_compress_windows_mc pc kk =
     APPEND [word 0xf3:byte; word 0x0f; word 0x1e; word 0xfa]
            (sha256_compress_windows_tmc (pc + 4) kk)`,
  REPEAT GEN_TAC THEN
  REWRITE_TAC[sha256_compress_windows_mc;
              sha256_compress_windows_tmc; APPEND] THEN
  REWRITE_TAC[GSYM INT_OF_NUM_ADD] THEN
  REWRITE_TAC[INT_ARITH `(&pc + &4) + &98 = &pc + &102:int`] THEN
  REWRITE_TAC[]);;

(* ======================================================================== *)
(* Phase 12 — the bl_tmc proof chain.                                        *)
(*                                                                            *)
(* The Windows wrapper MPs a CORE proved over `sha256_compress_  *)
(* bl_tmc` (= BUTLAST sysv_tmc), NOT the full sysv_tmc: the Windows image      *)
(* lacks the SysV trailing `ret` byte, so only BUTLAST(sysv_tmc) is a          *)
(* subprogram of windows_tmc (at offset 11).  The committed sysv-core CANNOT   *)
(* be weakened to a bl PRE — that is the UNSOUND direction (X86_CORE_PROMOTE   *)
(* only does bl-core => full-core), so the entire INNER cone must be re-stated *)
(* over bl_tmc.  Because bl_tmc = BUTLAST sysv_tmc DECODES IDENTICALLY for all *)
(* rows in [0,4464) (everything below the final `ret`), the re-statement is    *)
(* purely mechanical: each bl-lemma's statement is the committed one with      *)
(* sha256_compress_tmc -> ..._bl_tmc and 4465 -> 4464, and its    *)
(* PROOF is the committed tactic with SHA256_COMPRESS_EXEC ->     *)
(* SHA256_BL_EXEC.  We derive the bl-statement by term surgery on the          *)
(* committed `concl` (bl_of_stmt) rather than re-typing the large terms.       *)
(* ======================================================================== *)

(* statement surgery: full sysv_tmc -> bl_tmc, length 4465 -> 4464. *)
let bl_of_stmt tm =
  subst [`4464`,`4465`]
   (subst [`sha256_compress_bl_tmc`,
           `sha256_compress_tmc`] tm);;

(* ---- stepped leaves over bl_tmc (genuinely-leaf: no composition) ---- *)
(* Each reuses its committed tactic verbatim with SHA256_BL_EXEC.        *)

let SHA256_BLOCK_NOHW_LOOPEDGE_CONT_BL = prove
