    REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
    REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
                SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
                SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
    REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    ALL_TAC] THEN
  ABBREV_TAC `rr29:int32 list = (sha256_round rr28 k29 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 v15) v10) (word_add (sha_msg_sigma_0 v2) v1))) v12) (word_add (sha_msg_sigma_0 v4) v3))) v14) (word_add (sha_msg_sigma_0 v6) v5))) (word_add (word_add (sha_msg_sigma_1 v14) v9) (word_add (sha_msg_sigma_0 v1) v0))) (word_add (sha_msg_sigma_0 v8) v7))) (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 v14) v9) (word_add (sha_msg_sigma_0 v1) v0))) v11) (word_add (sha_msg_sigma_0 v3) v2))) (word_add (sha_msg_sigma_0 v10) v9))) (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 v14) v9) (word_add (sha_msg_sigma_0 v1) v0))) v11) (word_add (sha_msg_sigma_0 v3) v2))) v13) (word_add (sha_msg_sigma_0 v5) v4))) (word_add (sha_msg_sigma_0 v12) v11))) (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 (word_add (word_add (sha_msg_sigma_1 v14) v9) (word_add (sha_msg_sigma_0 v1) v0))) v11) (word_add (sha_msg_sigma_0 v3) v2))) v13) (word_add (sha_msg_sigma_0 v5) v4))) v15) (word_add (sha_msg_sigma_0 v7) v6))) (word_add (sha_msg_sigma_0 v14) v13)))` THEN
  (* final segment: round 30, pc+4044 .. pc+4205 *)
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_BL_EXEC (1--47) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA256_WORD_ZX_3264; SHA256_WORD_ZX_3232; SHA256_WORD_ZX_6464] THEN
  REWRITE_TAC[SHA256_SIGMA1_BRIDGE; SHA256_SIGMA0_BRIDGE;
              SHA256_CHOOSE_BRIDGE; SHA256_MAJ_BRIDGE;
              SHA256_MSG_SIGMA0_BRIDGE; SHA256_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha256_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ======================================================================== *)
(* Phase 12 STEP 2 (session-042): the bl ABS layer over bl_tmc.              *)
(* bl-aware goal_rodata_var (matches _bl_tmc) + execup (SHA256_BL_EXEC)       *)
(* SHADOW the earlier _tmc toplevel versions; everything below uses the bl    *)
(* forms.  HEAD16_ABS_BL = bl_of_stmt(HEAD16_ABS) MP-ing HEAD16_BL; the five  *)
(* MK_*_ABS_BL generators are the committed generators with leaf refs ->_BL   *)
(* and the no_rbp 4465->4464; ITER_ABS_{0,1,EXIT_2}_BL are the 3 concretes.   *)
(* ======================================================================== *)
let goal_rodata_var w =
  let blob = find_term (fun t ->
      (try fst(dest_const(fst(strip_comb t)))="sha256_compress_bl_tmc"
       with _ -> false)) w in
  last (snd (strip_comb blob));;
let execup = MATCH_MP bytes_loaded_update (fst SHA256_BL_EXEC);;

(* ---- HEAD16_ABS_BL: explicit bl statement, MP the BL leaf. ---- *)
let SHA256_BLOCK_NOHW_HEAD16_ABS_BL = prove
 (bl_of_stmt (concl SHA256_BLOCK_NOHW_HEAD16_ABS),
  REPEAT GEN_TAC THEN STRIP_TAC THEN
  MP_TAC(SPECL
   [`pc:num`; `kdat:num`; `kbase:int64`; `stackptr:int64`; `dataptr:int64`;
    `a:int32`; `b:int32`; `c:int32`; `d:int32`;
    `e:int32`; `f:int32`; `g:int32`; `h:int32`;
    `word_bytereverse (EL 0 m):int32`; `word_bytereverse (EL 1 m):int32`;
    `word_bytereverse (EL 2 m):int32`; `word_bytereverse (EL 3 m):int32`;
    `word_bytereverse (EL 4 m):int32`; `word_bytereverse (EL 5 m):int32`;
    `word_bytereverse (EL 6 m):int32`; `word_bytereverse (EL 7 m):int32`;
    `word_bytereverse (EL 8 m):int32`; `word_bytereverse (EL 9 m):int32`;
    `word_bytereverse (EL 10 m):int32`; `word_bytereverse (EL 11 m):int32`;
    `word_bytereverse (EL 12 m):int32`; `word_bytereverse (EL 13 m):int32`;
    `word_bytereverse (EL 14 m):int32`; `word_bytereverse (EL 15 m):int32`;
    `EL 0 sha256_constants:int32`; `EL 1 sha256_constants:int32`;
    `EL 2 sha256_constants:int32`; `EL 3 sha256_constants:int32`;
    `EL 4 sha256_constants:int32`; `EL 5 sha256_constants:int32`;
    `EL 6 sha256_constants:int32`; `EL 7 sha256_constants:int32`;
    `EL 8 sha256_constants:int32`; `EL 9 sha256_constants:int32`;
    `EL 10 sha256_constants:int32`; `EL 11 sha256_constants:int32`;
    `EL 12 sha256_constants:int32`; `EL 13 sha256_constants:int32`;
    `EL 14 sha256_constants:int32`; `EL 15 sha256_constants:int32`]
   SHA256_BLOCK_NOHW_HEAD16_BL) THEN
  ASM_REWRITE_TAC[] THEN
  (* collapse word_bytereverse(word_bytereverse x) = x then fold nest *)
  REWRITE_TAC[WORD_BYTEREVERSE_BYTEREVERSE; GSYM HEAD16_FOLD]);;

(* ---- bl generators (leaf refs ->_BL; execup/goal_rodata_var shadowed; 4465->4464). *)
let MK_BODY15_ABS_BL i =
  let rb = 16*i and wb = 16+16*i in
  let schedM = abs_build_schedM rb (wb+14) in
  let foldeq = prove
   (mk_eq(abs_cr_tm (wb+15),
          rhs(concl((COMPRESS_ROUNDS_DOWNTO wb THENC
                     REWRITE_CONV(map (fun t -> schedM.(t)) (wb--(wb+14))))
                    (abs_cr_tm (wb+15))))),
    CONV_TAC(LAND_CONV(COMPRESS_ROUNDS_DOWNTO wb THENC
                       REWRITE_CONV(map (fun t -> schedM.(t)) (wb--(wb+14))))) THEN
    REFL_TAC) in
  let sinwb = abs_cr_tm wb in
  let sinwb_len = prove
   (mk_imp(`LENGTH (sin:int32 list) = 8`,
           mk_eq(mk_list(map (fun j -> abs_el_cr j wb) (0--7),`:int32`), sinwb)),
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA256_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  let inst_args =
    [`pc:num`; `kdat:num`; `kbase:int64`; `stackptr:int64`] @
    (map (fun j -> abs_el_cr j wb) (0--7)) @
    (map (fun j -> abs_instM (rb+j)) (0--15)) @
    (map (fun t -> abs_el_k (wb+t)) (0--14)) in
  let body15_inst = SPECL inst_args SHA256_BLOCK_NOHW_BODY15_BL in
  let th0 = DISCH `LENGTH (sin:int32 list) = 8` body15_inst in
  let raw = GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sinwb_len; GSYM foldeq] (UNDISCH th0))) in
  REWRITE_RULE (map (fun t -> GSYM schedM.(t)) ((rb+16)--(wb+14))) raw;;

let MK_ROUND31S_ABS_BL i =
  let rb = 16*i and wb = 16+16*i in
  let ol = abs_one_level (rb+31) in
  let foldeq = (COMPRESS_ROUNDS_DOWNTO (wb+15)) (abs_cr_tm (wb+16)) in
  let sinwbp15 = abs_cr_tm (wb+15) in
  let sinwbp15_len = prove
   (mk_imp(`LENGTH (sin:int32 list) = 8`,
           mk_eq(mk_list(map (fun j -> abs_el_cr j (wb+15)) (0--7),`:int32`), sinwbp15)),
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA256_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  let inst_args =
    [`pc:num`; `kdat:num`; `kb:int64`; `stackptr:int64`] @
    (map (fun j -> abs_el_cr j (wb+15)) (0--7)) @
    [ abs_instM (rb+16); abs_instM (rb+24); abs_instM (rb+29); abs_instM (rb+15);
      abs_el_k (wb+15); `v1:int32`; `v14:int32` ] in
  let r31s_inst = SPECL inst_args SHA256_BLOCK_NOHW_ROUND31_S_BL in
  let th0 = DISCH `LENGTH (sin:int32 list) = 8` r31s_inst in
  GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sinwbp15_len; GSYM ol; GSYM foldeq]
    (UNDISCH th0)));;

let MK_BR_S_ABS_BL i =
  let bI = MK_BODY15_ABS_BL i and rI = MK_ROUND31S_ABS_BL i in
  let (bvars,bhyps,pBlam,qBlam,cB) = parts bI in
  let (rvars,rhypsB,pR,qR,cR)  = parts rI in
  ignore rhypsB;
  let sB, pBc = conjs_of_lam pBlam in
  let _, qBc  = conjs_of_lam qBlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let rv = vbn rvars in
  (* seam instantiation: ABS lemmas pre-align a..h; only kb/v1/v14 are free. *)
  let rbp_b  = rhs_of(by_comp "RBP" qBc) in                 (* kbase+108 *)
  let slot4  = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 4))" qBc) in
  let slot56 = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 56))" qBc) in
  let inst = [ rbp_b, rv"kb"; slot4, rv"v1"; slot56, rv"v14" ] in
  let pR_i = vsubst inst pR and qR_i = vsubst inst qR and cR_i = vsubst inst cR in
  let _, pR_i_c = conjs_of_lam pR_i in
  let _, qR_i_c = conjs_of_lam qR_i in
  (* B15-post ring slots NOT in ROUND31_S frame (everything but slot60): survive *)
  let surviving_slots = filter (fun off -> off <> 60)
                          [0;4;8;12;16;20;24;28;32;36;40;44;48;52;56] in
  let body_slot_conj off = by_comp
      (if off = 0 then "memory :> bytes32 stackptr"
       else "memory :> bytes32 (word_add stackptr (word "^string_of_int off^"))") qBc in
  let carried_slot_conjs = map body_slot_conj surviving_slots in
  (* carried K read at kbase+108 = EL (31+16i) consts (k31), which B15 post lacks. *)
  let k31val = abs_el_k (16+16*i+15) in   (* EL (31+16i) sha256_constants *)
  let kread108 = mk_eq(
     mk_comb(mk_comb(`read:(x86state,int32)component->x86state->int32`,
                     `memory :> bytes32 (word_add (kbase:int64) (word 108))`),
             sB), k31val) in
  let pre_lam  = mk_abs(sB, list_mk_conj (pBc @ [kread108])) in
  let frame = mk_comb(mk_comb(seqop,cB),cR_i) in
  let hyps_B = list_mk_conj bhyps in
  let no_extra = `nonoverlapping (stackptr:int64,64) (word_add (kbase:int64) (word 108),4)` in
  let hyps = mk_conj(hyps_B, no_extra) in
  let eh = ens_head_of bI in
  let post_lam = mk_abs(sB, list_mk_conj (qR_i_c @ carried_slot_conjs)) in
  (* LENGTH sin = 8 must front the composed concl (both legs need it).           *)
  let lensin = `LENGTH (sin:int32 list) = 8` in
  let comp_concl =
    list_mk_forall(bvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  (* seamQ = ROUND31_S inst-pre (minus bytes_loaded+RIP) + surviving ring slots.  *)
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pR_i_c in
  let extra_seam_slots = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) carried_slot_conjs in
  let seamQ = mk_abs(sB, list_mk_conj (seamQ_conjs @ extra_seam_slots)) in
  let pc_seam = `pc + 4205` in
  (* committed lemmas, specialised at the seam (keep BOTH antecedents            *)
  (* LENGTH sin=8 ==> nonoverlap ==> ensures; ASM_REWRITE_TAC discharges both     *)
  (* from the outer assumptions, as in the concrete case for the single hyp).     *)
  let body_self = SPECL bvars bI in
  let round31_seam =
    SPECL [ `kdat:num`; `pc:num`; rbp_b; slot4; slot56; `sin:int32 list`;
            `m:int32 list`; `stackptr:int64` ] rI in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg body_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg round31_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

let MK_ITER_ABS_BL i brI =
  let (brvars,brhyps,pBRlam,qBRlam,cBR) = parts brI in
  let (cvars,chypsC,pC,qC,cC) = parts SHA256_BLOCK_NOHW_LOOPEDGE_CONT_BL in
  ignore chypsC;
  let sBR, pBRc = conjs_of_lam pBRlam in
  let _, qBRc = conjs_of_lam qBRlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let cv = vbn cvars in
  let rbp_val_v = rhs_of(by_comp "RBP" qBRc) in
  let rax_in_v  = rand(rhs_of(by_comp "RAX" qBRc)) in
  let r14_in_v  = rand(rhs_of(by_comp "R14" qBRc)) in
  let r1_v      = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 4))" qBRc) in
  let r14v_v    = rhs_of(by_comp "memory :> bytes32 (word_add stackptr (word 56))" qBRc) in
  let sb_v = `sb:byte` in
  let cinst =
   [ `kdat:num`, cv"kk"; rbp_val_v, cv"rbp_val"; r1_v, cv"r1"; r14v_v, cv"r14v";
     rax_in_v, cv"rax_in"; r14_in_v, cv"r14_in"; sb_v, cv"sb" ] in
  let pC_i = vsubst cinst pC and qC_i = vsubst cinst qC and cC_i = vsubst cinst cC in
  let _, pC_i_c = conjs_of_lam pC_i in
  let _, qC_i_c = conjs_of_lam qC_i in
  let is_bytes8 c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes8") c in true with _->false in
  let sent_read_C = find is_bytes8 pC_i_c in
  let sent_state = rand(fst(dest_eq sent_read_C)) in
  let sent_read = subst [sBR, sent_state] sent_read_C in
  let pre_lam = mk_abs(sBR, list_mk_conj (pBRc @ [sent_read])) in
  let cont_post_comps = map comp_str qC_i_c in
  let overwritten = ["RIP";"RAX";"R12";"R13";"R15"] in
  let surviving = filter (fun c ->
       not(mem (comp_str c) cont_post_comps) && not(mem (comp_str c) overwritten)) qBRc in
  let post_lam = mk_abs(sBR, list_mk_conj (qC_i_c @ surviving)) in
  let frame = mk_comb(mk_comb(seqop,cBR),cC_i) in
  let hyps_BR = list_mk_conj brhyps in
  let no_rbp = vsubst [rbp_val_v,`RBPV:int64`] `nonoverlapping (word pc,4464) (RBPV:int64,4)` in
  let sb_ne = mk_neg(mk_eq(sb_v,`word 0:byte`)) in
  (* sentinel nonoverlap: (stackptr,64) vs (rbp_val+3, 1) *)
  let no_sent = vsubst [rbp_val_v,`RBPV:int64`]
      `nonoverlapping (stackptr:int64,64) (word_add (RBPV:int64) (word 3),1)` in
  let hyps = list_mk_conj [hyps_BR; no_rbp; sb_ne; no_sent] in
  let eh = ens_head_of brI in
  let lensin = `LENGTH (sin:int32 list) = 8` in
  let comp_concl =
    list_mk_forall(brvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pC_i_c in
  let extra_seam = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) surviving in
  let seamQ = mk_abs(sBR, list_mk_conj (seamQ_conjs @ extra_seam)) in
  let pc_seam = `pc + 4345` in
  let brs_self = SPECL brvars brI in
  let cont_seam =
    SPECL [ `pc:num`; `kdat:num`; `stackptr:int64`; rbp_val_v; r1_v; r14v_v;
            rax_in_v; r14_in_v; sb_v ] SHA256_BLOCK_NOHW_LOOPEDGE_CONT_BL in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg brs_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg cont_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

let MK_ITER_ABS_EXIT_BL i brI =
  let (brvars,brhyps,pBRlam,qBRlam,cBR) = parts brI in
  let (cvars,chypsE,pE,qE,cE) = parts SHA256_BLOCK_NOHW_LOOPEDGE_EXIT_BL in
  ignore chypsE;
  let sBR, pBRc = conjs_of_lam pBRlam in
  let _, qBRc = conjs_of_lam qBRlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let cv = vbn cvars in
  let rbp_val_v = rhs_of(by_comp "RBP" qBRc) in
  let rax_in_v  = rand(rhs_of(by_comp "RAX" qBRc)) in
  let r14_in_v  = rand(rhs_of(by_comp "R14" qBRc)) in
  let einst =
   [ `kdat:num`, cv"kk"; rbp_val_v, cv"rbp_val";
     rax_in_v, cv"rax_in"; r14_in_v, cv"r14_in" ] in
  let pE_i = vsubst einst pE and qE_i = vsubst einst qE and cE_i = vsubst einst cE in
  let _, pE_i_c = conjs_of_lam pE_i in
  let _, qE_i_c = conjs_of_lam qE_i in
  (* sentinel-byte read at rbp_val+3 = word 0 (EXIT condition). *)
  let is_bytes8 c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes8") c in true with _->false in
  let sent_read_E = find is_bytes8 pE_i_c in
  let sent_state = rand(fst(dest_eq sent_read_E)) in
  let sent_read = subst [sBR, sent_state] sent_read_E in
  let pre_lam = mk_abs(sBR, list_mk_conj (pBRc @ [sent_read])) in
  (* EXIT frame is only [RIP]+flags+events; everything else of BR_S post survives *)
  let exit_post_comps = map comp_str qE_i_c in
  let overwritten = ["RIP"] in
  let surviving = filter (fun c ->
       not(mem (comp_str c) exit_post_comps) && not(mem (comp_str c) overwritten)) qBRc in
  let post_lam = mk_abs(sBR, list_mk_conj (qE_i_c @ surviving)) in
  let frame = mk_comb(mk_comb(seqop,cBR),cE_i) in
  let hyps_BR = list_mk_conj brhyps in
  let no_rbp = vsubst [rbp_val_v,`RBPV:int64`] `nonoverlapping (word pc,4464) (RBPV:int64,4)` in
  let no_sent = vsubst [rbp_val_v,`RBPV:int64`]
      `nonoverlapping (stackptr:int64,64) (word_add (RBPV:int64) (word 3),1)` in
  let hyps = list_mk_conj [hyps_BR; no_rbp; no_sent] in
  let eh = ens_head_of brI in
  let lensin = `LENGTH (sin:int32 list) = 8` in
  let comp_concl =
    list_mk_forall(brvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pE_i_c in
  let extra_seam = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) surviving in
  let seamQ = mk_abs(sBR, list_mk_conj (seamQ_conjs @ extra_seam)) in
  let pc_seam = `pc + 4345` in
  let brs_self = SPECL brvars brI in
  let exit_seam =
    SPECL [ `pc:num`; `kdat:num`; `stackptr:int64`; rbp_val_v;
            rax_in_v; r14_in_v ] SHA256_BLOCK_NOHW_LOOPEDGE_EXIT_BL in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg brs_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg exit_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

(* ---- the three concrete bl iteration lemmas. ---- *)
let SHA256_BLOCK_NOHW_ITER_ABS_0_BL = MK_ITER_ABS_BL 0 (MK_BR_S_ABS_BL 0);;
let SHA256_BLOCK_NOHW_ITER_ABS_1_BL = MK_ITER_ABS_BL 1 (MK_BR_S_ABS_BL 1);;
let SHA256_BLOCK_NOHW_ITER_ABS_EXIT_2_BL = MK_ITER_ABS_EXIT_BL 2 (MK_BR_S_ABS_BL 2);;

(* ======================================================================== *)
(* Phase 12 STEP 3a (session-042): bl-INNER over bl_tmc.                     *)
(* The committed INNER body with the 4 ABS refs ->_BL; compose_step bakes    *)
(* execup/goal_rodata_var (now the bl-aware shadows in scope above).         *)
(* HEAD16_ABS_BL ; ITER_ABS_0_BL[K+128] ; ITER_ABS_1_BL[K+256] ;             *)
(* ITER_ABS_EXIT_2_BL[K+384] => ensures pc+87 -> pc+4355 over bl_tmc.        *)
(* ======================================================================== *)
let SHA256_BLOCK_NOHW_INNER_BL =
  let len8 = LENGTH_CONV `LENGTH ([a;b;c;d;e;f;g;h]:int32 list)` in
  (* per-iteration ITER lemmas, instantiated for the chain (kbase +128/iter,    *)
  (* sin:=[a;..;h] so the working state threads as cr m [a..h] (16i) directly,   *)
  (* sentinel byte 0x27/0x19 for the two continue iterations; LENGTH collapsed). *)
  let it0i = REWRITE_RULE[len8] (INST [`word 0x27:byte`,`sb:byte`]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 128)`;
              `[a;b;c;d;e;f;g;h]:int32 list`;`m:int32 list`;`stackptr:int64`]
             SHA256_BLOCK_NOHW_ITER_ABS_0_BL)) in
  let it1i = REWRITE_RULE[len8] (INST [`word 0x19:byte`,`sb:byte`]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 256)`;
              `[a;b;c;d;e;f;g;h]:int32 list`;`m:int32 list`;`stackptr:int64`]
             SHA256_BLOCK_NOHW_ITER_ABS_1_BL)) in
  let it2i = REWRITE_RULE[len8]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 384)`;
              `[a;b;c;d;e;f;g;h]:int32 list`;`m:int32 list`;`stackptr:int64`]
             SHA256_BLOCK_NOHW_ITER_ABS_EXIT_2_BL) in
  (* leg-B trimmed SUBLEM (canned ENSURES_SUBLEMMA_TAC body minus the leg-1      *)
  (* branch, which auto-closes when seamQ = the appended lemma's PRE exactly).   *)
  let sublem_b_tac =
    MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
     [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC;
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
      REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
      REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
      REWRITE_TAC[GSYM SEQ_ASSOC] THEN
      PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
      CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
      REWRITE_TAC[ASSIGNS_THM] THEN
      REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
      NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
      ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC)] in
  (* compose prevThm ; itI at the pc+1786 seam (see header).                     *)
  let compose_step prevThm itI legA_reconcile =
    let (pvars,phyps,pPlam,pQlam,pC) = parts prevThm in
    let (_,ihyps,iPlam,iQlam,iC) = parts itI in
    let sP, pPc = conjs_of_lam pPlam in
    let _,  pQc = conjs_of_lam pQlam in
    let sI, iPc0 = conjs_of_lam iPlam in
    let iPc = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") iPc0 in
    let pcomps = map comp_str pQc in
    let carried_I = filter (fun c -> not(mem (comp_str c) pcomps)) iPc in
    let carried_P = map (vsubst [sP, sI]) carried_I in
    let pre_lam = mk_abs(sP, list_mk_conj (pPc @ carried_P)) in
    let post_lam = iQlam in
    let frame = mk_comb(mk_comb(seqop,pC),iC) in
    let hyps = list_mk_conj (phyps @ ihyps) in
    let eh = ens_head_of prevThm in
    let comp_concl = list_mk_forall(pvars, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame)) in
    let seamQ = mk_abs(sI, list_mk_conj iPc) in
    let pc_seam = `pc + 1786` in
    let prev_self = SPECL pvars prevThm in
    let match_leg lemma =
      W(fun (asl,w) -> ignore asl;
          let kv = goal_rodata_var w in
          MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
          ASM_REWRITE_TAC[]) in
    let sublem_a = ENSURES_SUBLEMMA_TAC execup in
    let legA = MP_TAC (REWRITE_RULE[SOME_FLAGS] prev_self) THEN ASM_REWRITE_TAC[] in
    prove
     (comp_concl,
      REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN STRIP_TAC THEN
      ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
      [ legA THEN sublem_a "s" "s'" THEN legA_reconcile;
        match_leg itI THEN sublem_b_tac THEN ASM_REWRITE_TAC[] ]) in
  let SCHED_LT16_RULES = map (fun j -> SCHED_LT16_CONV (abs_instM j)) (0--15) in
  let c0 = compose_step SHA256_BLOCK_NOHW_HEAD16_ABS_BL it0i
             (REWRITE_TAC SCHED_LT16_RULES THEN ASM_REWRITE_TAC[]) in
  let c1 = compose_step c0 it1i
             (ASM_REWRITE_TAC[] THEN REWRITE_TAC (cr_rot_rules 31) THEN
              REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE) in
  let c2 = compose_step c1 it2i
             (ASM_REWRITE_TAC[] THEN REWRITE_TAC (cr_rot_rules 47) THEN
              REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE) in
  c2;;

(* ======================================================================== *)
(* Phase 12 STEP 3b (session-042): bl-BODY_FF + bl-CORE over bl_tmc.         *)
(* The committed Phase-10 core CORRECT block re-run with                     *)
(*   SHA256_COMPRESS_EXEC -> SHA256_BL_EXEC ;                    *)
(*   SHA256_BLOCK_NOHW_{INNER,MINI,TAIL_LP,PROL_REG,BODY_FF} -> _BL ;         *)
(*   sha256_compress_tmc -> _bl_tmc ; 4465 -> 4464.              *)
(* The block-local match_leg/sublem_a use the bl-aware goal_rodata_var/execup *)
(* shadows in scope from STEP 2.  Result SHA256_COMPRESS_BL_     *)
(* CORRECT: the bl-core, pc+29 -> pc+4432 over bl_tmc, the Windows-wrapper    *)
(* MP target.  Proved on warm server (S042_STEP3B_BLCORE_PASS, bl_tmc OK).    *)
(* ======================================================================== *)
let norm_conv = REWRITE_CONV[WORD_ADD_ASSOC_CONSTS;WORD_ADD_0] THENC
                DEPTH_CONV NUM_ADD_CONV;;
let normt t = try rhs(concl(norm_conv t)) with _ -> t;;
let is_mem c = let cs=comp_str c in String.length cs>=6 && String.sub cs 0 6="memory";;
let is_kread c = is_mem c &&
   (try let _=find_term (fun t->is_const t && fst(dest_const t)="sha256_constants") c
        in true with _->false);;
let is_sentinel c = is_mem c &&
   (try let _=find_term (fun t->is_const t && fst(dest_const t)="bytes8") c
        in true with _->false);;
let at_state sv c = vsubst[sv, `s:x86state`] c;;
let stnames = ["a";"b";"c";"d";"e";"f";"g";"h"];;
let regnames = ["RAX";"RBX";"RCX";"RDX";"R8";"R9";"R10";"R11"];;

(* INNER's PRE conjuncts, kbase:=word kk, flattened — source of K-reads/sentinels.*)
let INNER_i0 = SPECL [`pc:num`;`kk:num`;`word kk:int64`;`stackptr:int64`;
   `dataptr:int64`;`a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;
   `g:int32`;`h:int32`;`m:int32 list`] SHA256_BLOCK_NOHW_INNER_BL;;
let (_,_,iPlam0,_,_) = parts INNER_i0;;
let _,iPc0 = conjs_of_lam iPlam0;;
let kread_terms = map normt (filter is_kread iPc0);;
let sentinel_terms = map normt (filter is_sentinel iPc0);;

let el_hb j ivar =
  vsubst[ivar,`i:num`; mk_small_numeral j,`j:num`]
    `EL j (sha256_hash_blocks (m_fn:num->int32 list) [a;b;c;d;e;f;g;h] i):int32`;;

(* p i s : loop invariant STATE predicate (NO bytes_loaded/RIP — auto-injected). *)
let p_conjs ivar sv =
  let regeq j = mk_eq(parse_term("read "^(el j regnames)^" sQQ"),
                      mk_comb(`word_zx:int32->int64`, el_hb j ivar)) in
  let regeqs = map (fun j -> vsubst[sv,`sQQ:x86state`] (regeq j)) (0--7) in
  let mem_state j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(4*j)^"))" in
    mk_eq(parse_term("read (memory :> bytes32 "^addr^") sQQ"), el_hb j ivar) in
  let memeqs = map (fun j -> vsubst[sv,`sQQ:x86state`] (mem_state j)) (0--7) in
  let rsp  = vsubst[sv,`sQQ:x86state`] (parse_term "read RSP sQQ = stackptr") in
  let rdi  = vsubst[sv,`sQQ:x86state`] (parse_term "read RDI sQQ = statep") in
  let rsi  = vsubst[sv,`sQQ:x86state`; ivar,`i:num`]
               (parse_term "read RSI sQQ = word_add dataptr (word (64*i))") in
  let slot64 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 64))) sQQ = statep") in
  let slot80 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 80))) sQQ = endp") in
  let slot88 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 88))) sQQ = origsp") in
  let dataq = vsubst[sv,`sQQ:x86state`]
       (parse_term
         ("!i' j. i' < num_blocks /\\ j < 16 ==> \
           read (memory :> bytes32 \
             (word_add dataptr (word (64*i' + 4*j)))) sQQ = \
           word_bytereverse (EL j (m_fn i'):int32)")) in
  let kr = map (at_state sv) kread_terms in
  let sn = map (at_state sv) sentinel_terms in
  [rsp; rdi; rsi; slot64; slot80; slot88] @ regeqs @ memeqs @ kr @ sn @ [dataq];;

let q_conj ivar sv =
  vsubst[sv,`sQQ:x86state`; ivar,`i:num`]
    (parse_term
      "(read CF sQQ <=> val (word_add (dataptr:int64) (word (64*i))) < val (endp:int64))");;

let iv_var = `i:num` and sx = `s:x86state`;;
let invariant =
  list_mk_abs([iv_var; sx],
    mk_conj(list_mk_conj (p_conjs iv_var sx), q_conj iv_var sx));;

(* ---- CORRECT statement ---- *)
let correct_pres =
 [ `nonoverlapping (word pc,4464) (statep:int64,32)`;
   `nonoverlapping (word pc,4464) (stackptr:int64,96)`;
   `nonoverlapping (word pc,4464) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (word pc,4464) (word kk:int64,608)`;
   `nonoverlapping (statep:int64,32) (stackptr:int64,96)`;
   `nonoverlapping (statep:int64,32) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (statep:int64,32) (word kk:int64,608)`;
   `nonoverlapping (stackptr:int64,96) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (stackptr:int64,96) (word kk:int64,608)`;
   `0 < num_blocks`;
   `val (dataptr:int64) + 64 * num_blocks < 2 EXP 64`;
   `endp:int64 = word_add dataptr (word (64*num_blocks))`;
   `riprel32_within_bounds kk (pc + 87)` ];;

let correct_PRE =
  let statep_read j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(4*j)^"))" in
    parse_term("read (memory :> bytes32 "^addr^") s = ("^el j stnames^":int32)") in
  let conjs =
    [ `bytes_loaded s (word pc) (sha256_compress_bl_tmc pc kk)`;
      `read RIP s = word (pc + 29)`;
      `read RSP s = stackptr`;
      `read RDI s = statep`;
      `read RSI s = dataptr`;
      `read RDX s = endp`;
      `read RAX s = origsp` ]
    @ (map statep_read (0--7))
    @ [ `read (memory :> bytelist (word kk:int64, LENGTH K256)) s = K256` ;
        parse_term
         "!i' j. i' < num_blocks /\\ j < 16 ==> \
           read (memory :> bytes32 \
             (word_add dataptr (word (64*i' + 4*j)))) s = \
           word_bytereverse (EL j (m_fn i'):int32)" ] in
  mk_abs(`s:x86state`, list_mk_conj conjs);;

let correct_POST =
  let stp j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(4*j)^"))" in
    mk_eq(parse_term("read (memory :> bytes32 "^addr^") s"),
          vsubst[mk_small_numeral j,`j:num`]
            `EL j (sha256_hash_blocks (m_fn:num->int32 list)
                     [a;b;c;d;e;f;g;h] num_blocks):int32`) in
  mk_abs(`s:x86state`,
    list_mk_conj([`read RIP s = word (pc + 4432)`;
                  `read RSP s = stackptr`;
                  `read (memory :> bytes64 (word_add stackptr (word 88))) s =
                       origsp`]
                 @ map stp (0--7)));;

let frame_full =
  `(MAYCHANGE [RIP;RAX;RBX;RCX;RDX;RBP;RDI;RSI;R8;R9;R10;R11;R12;R13;R14;R15] ,,
    MAYCHANGE [memory :> bytes32 statep;
               memory :> bytes32 (word_add statep (word 4));
               memory :> bytes32 (word_add statep (word 8));
               memory :> bytes32 (word_add statep (word 12));
               memory :> bytes32 (word_add statep (word 16));
               memory :> bytes32 (word_add statep (word 20));
               memory :> bytes32 (word_add statep (word 24));
               memory :> bytes32 (word_add statep (word 28))] ,,
    MAYCHANGE [memory :> bytes64 (word_add stackptr (word 64));
               memory :> bytes64 (word_add stackptr (word 72));
               memory :> bytes64 (word_add stackptr (word 80));
               memory :> bytes64 (word_add stackptr (word 88))] ,,
    MAYCHANGE [memory :> bytes32 stackptr;
               memory :> bytes32 (word_add stackptr (word 4));
               memory :> bytes32 (word_add stackptr (word 8));
               memory :> bytes32 (word_add stackptr (word 12));
               memory :> bytes32 (word_add stackptr (word 16));
               memory :> bytes32 (word_add stackptr (word 20));
               memory :> bytes32 (word_add stackptr (word 24));
               memory :> bytes32 (word_add stackptr (word 28));
               memory :> bytes32 (word_add stackptr (word 32));
               memory :> bytes32 (word_add stackptr (word 36));
               memory :> bytes32 (word_add stackptr (word 40));
               memory :> bytes32 (word_add stackptr (word 44));
               memory :> bytes32 (word_add stackptr (word 48));
               memory :> bytes32 (word_add stackptr (word 52));
               memory :> bytes32 (word_add stackptr (word 56));
               memory :> bytes32 (word_add stackptr (word 60))] ,,
    MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`;;

let correct_concl =
  list_mk_forall([`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
                  `dataptr:int64`;`endp:int64`;`origsp:int64`;`num_blocks:num`;
                  `a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;
                  `g:int32`;`h:int32`;`m_fn:num->int32 list`],
    itlist (curry mk_imp) correct_pres
      (mk_ensures `ensures x86` correct_PRE correct_POST frame_full));;

let Q78 = mk_abs(`s:x86state`, list_mk_conj (p_conjs `0` `s:x86state`));;

(* ============================ leg1 (PROL_REG once) ====================== *)
let PROL_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
   `dataptr:int64`;`endp:int64`;`origsp:int64`;`a:int32`;`b:int32`;`c:int32`;
   `d:int32`;`e:int32`;`f:int32`;`g:int32`;`h:int32`] SHA256_BLOCK_NOHW_PROL_REG_BL;;

let match_leg lemma =
  W(fun (asl,w) -> ignore asl;
      let kv = goal_rodata_var w in
      MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kk:num`] lemma)) THEN
      ASM_REWRITE_TAC[]);;
let norm_rule d = CONV_RULE norm_conv d;;
let KDERIVE_ASSUME =
  FIRST_ASSUM(fun th ->
        let c = concl th in
        if is_eq c && (try fst(dest_const(rand c))="K256" with _->false)
        then ASSUME_TAC(norm_rule(MATCH_MP SHA256_K256_READS th)) THEN
             ASSUME_TAC(norm_rule(MATCH_MP SHA256_SENTINEL_BYTES th))
        else NO_TAC);;
let P0_RECON =
  REWRITE_TAC[sha256_hash_blocks] THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REWRITE_TAC[MULT_CLAUSES; WORD_ADD_0; ARITH] THEN
  CONV_TAC(DEPTH_CONV NUM_MULT_CONV) THEN REWRITE_TAC[WORD_ADD_0];;

let leg1 =
  match_leg PROL_i THEN
  MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
   [ W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
     STRIP_TAC THEN ASM_REWRITE_TAC[];
     CONJ_TAC THENL [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC; ALL_TAC] THEN
     W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
     W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
     REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
     KDERIVE_ASSUME THEN
     REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
     REWRITE_TAC[GSYM SEQ_ASSOC] THEN
     PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
     CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
     REWRITE_TAC[ASSIGNS_THM] THEN
     REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
     NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
     ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC) THEN
     P0_RECON THEN ASM_REWRITE_TAC[] ];;

(* ============================ CF legs (back-edge + exit) ================= *)
let CFLT = prove
 (`!(dataptr:int64) i num_blocks.
     i < num_blocks /\ val dataptr + 64 * num_blocks < 2 EXP 64
     ==> val (word_add dataptr (word (64*i))) <
         val (word_add dataptr (word (64*num_blocks)))`,
  REPEAT STRIP_TAC THEN
  REWRITE_TAC[VAL_WORD_ADD; VAL_WORD; DIMINDEX_64] THEN
  SUBGOAL_THEN `(64 * i) MOD 2 EXP 64 = 64 * i /\
                (64 * num_blocks) MOD 2 EXP 64 = 64 * num_blocks`
    (CONJUNCTS_THEN SUBST1_TAC) THENL
   [CONJ_TAC THEN MATCH_MP_TAC MOD_LT THEN ASM_ARITH_TAC; ALL_TAC] THEN
  SUBGOAL_THEN `(val(dataptr:int64) + 64 * i) MOD 2 EXP 64 =
                 val dataptr + 64 * i /\
                (val(dataptr:int64) + 64 * num_blocks) MOD 2 EXP 64 =
                 val dataptr + 64 * num_blocks`
    (CONJUNCTS_THEN SUBST1_TAC) THENL
   [CONJ_TAC THEN MATCH_MP_TAC MOD_LT THEN ASM_ARITH_TAC; ASM_ARITH_TAC]);;

let endp_def = `endp:int64 = word_add dataptr (word (64 * num_blocks))`;;

let leg_back =
  REPEAT STRIP_TAC THEN
  SUBGOAL_THEN `val (word_add (dataptr:int64) (word (64*i))) <
                val (word_add dataptr (word (64*num_blocks)))`
    ASSUME_TAC THENL
   [ MATCH_MP_TAC CFLT THEN ASM_REWRITE_TAC[]; ALL_TAC ] THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_BL_EXEC (1--1) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME endp_def]) THEN ASM_REWRITE_TAC[];;

let leg_exit =
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_BL_EXEC (1--1) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME endp_def]) THEN
  ASM_REWRITE_TAC[LT_REFL];;

(* ============================ BODY_FF (inline body leg) ================== *)
let HB iv = vsubst[iv,`i:num`]
  `sha256_hash_blocks (m_fn:num->int32 list) [a;b;c;d;e;f;g;h] i`;;
let elhb iv j = mk_comb(mk_comb(`EL:num->int32 list->int32`, mk_small_numeral j), HB iv);;

let iv = `i:num` and ip1 = `i + 1` and sxv = `s:x86state`;;
let dptr_i = `word_add dataptr (word (64*i)):int64`;;

let INNER_i = SPECL [`pc:num`;`kk:num`;`word kk:int64`;`stackptr:int64`;
   dptr_i; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3; elhb iv 4; elhb iv 5;
   elhb iv 6; elhb iv 7; `(m_fn:num->int32 list) i`] SHA256_BLOCK_NOHW_INNER_BL;;
let (_,ihyps,iPlam,iQlam,iC) = parts INNER_i;;
let sI,iPc = conjs_of_lam iPlam;;
let _,iQc = conjs_of_lam iQlam;;
let bighyp_i = hd ihyps;;
let zx_arg comp = rand(rhs_of(by_comp comp iQc));;

let MINI_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`; dptr_i;
   `statep:int64`;`endp:int64`; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3;
   elhb iv 4; elhb iv 5; elhb iv 6; elhb iv 7] SHA256_BLOCK_NOHW_MINI_BL;;
let (_,_,mPlam,mQlam,mC) = parts MINI_i;;
let sM,mPc = conjs_of_lam mPlam;;

let TAILLP_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
   dptr_i;`endp:int64`; zx_arg "RAX"; zx_arg "RBX"; zx_arg "RCX";
   zx_arg "RDX"; zx_arg "R8"; zx_arg "R9"; zx_arg "R10"; zx_arg "R11";
   zx_arg "R14"; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3; elhb iv 4;
   elhb iv 5; elhb iv 6; elhb iv 7] SHA256_BLOCK_NOHW_TAIL_LP_BL;;
let (_,_,tPlam,tQlam,tC) = parts TAILLP_i;;
let sT,tPc = conjs_of_lam tPlam;;
let _,tQc = conjs_of_lam tQlam;;

let pconj_i  = p_conjs iv  sxv;;
let pconj_ip1 = p_conjs ip1 sxv;;
(* read-only / frame-preserved facts that ride every segment frame untouched:    *)
(* the 64 K-reads, 3 sentinels, the quantified dataq, AND slot88=origsp (in no    *)
(* segment's PRE/POST — unlike slot64/80 which ride MINI/TAIL_LP statements).      *)
let ro_i = filter (fun c -> is_kread c || is_sentinel c || not(is_eq c) ||
                            vfree_in `origsp:int64` c) pconj_i;;

let statep_read_i sv j =
  let addr = if j=0 then "statep" else "(word_add statep (word "^string_of_int(4*j)^"))" in
  mk_eq(parse_term("read (memory :> bytes32 "^addr^") sQQ"), elhb iv j)
  |> vsubst[sv,`sQQ:x86state`];;
let slot64v sv = vsubst[sv,`sQQ:x86state`]
   (parse_term "read (memory :> bytes64 (word_add stackptr (word 64))) sQQ = statep");;
let slot80v sv = vsubst[sv,`sQQ:x86state`]
   (parse_term "read (memory :> bytes64 (word_add stackptr (word 80))) sQQ = endp");;

let drop c = is_named "bytes_loaded" c || comp_str c = "RIP";;
let q87_inner = map normt (filter (fun c -> not(drop c)) iPc);;
let q87_extra = (map (statep_read_i sI) (0--7)) @ [slot64v sI; slot80v sI];;
let ro_at sv = map (vsubst[sv,sxv]) ro_i;;
let already c = exists (fun d -> aconv c d) (q87_inner @ q87_extra);;
let q87_ro = filter (fun c -> not(already c)) (ro_at sI);;
let bodyQ87 = mk_abs(sI, list_mk_conj (q87_inner @ q87_extra @ q87_ro));;

let q4355_tl = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c<>"RIP") tPc;;
let already2 c = exists (fun d -> aconv c d) q4355_tl;;
let q4355_ro = filter (fun c -> not(already2 c)) (ro_at sT);;
let bodyQ4355 = mk_abs(sT, list_mk_conj (q4355_tl @ q4355_ro));;

(* BODY_FF statement on frame_full with p(i+1) GROUPED (so the POST conjunct      *)
(* structure equals the PUP body subgoal's `pd /\ rip /\ p(i+1) s /\ q(i+1) s`).  *)
let ff_PRE =
  mk_abs(sxv, list_mk_conj
    (`bytes_loaded s (word pc) (sha256_compress_bl_tmc pc kk)` ::
     `read RIP s = word (pc + 78)` :: pconj_i));;
let ff_POST =
  mk_abs(sxv, list_mk_conj
    [`bytes_loaded s (word pc) (sha256_compress_bl_tmc pc kk)`;
     `read RIP s = word (pc + 4426)`;
     list_mk_conj pconj_ip1;
     q_conj ip1 sxv]);;
let ff_FRAME = frame_full;;
let ff_hyps = correct_pres @ [`i < num_blocks`; `~(i = num_blocks)`];;
let ff_vars =
  [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;`dataptr:int64`;
   `endp:int64`;`origsp:int64`;`num_blocks:num`;`i:num`;`a:int32`;`b:int32`;
   `c:int32`;`d:int32`;`e:int32`;`f:int32`;`g:int32`;`h:int32`;
   `m_fn:num->int32 list`];;
let eh = ens_head_of INNER_i;;
let ff_body0 = itlist (curry mk_imp) ff_hyps (mk_ensures eh ff_PRE ff_POST ff_FRAME);;
let stray_tyvars =
  itlist (fun v acc ->
     let n = fst(dest_var v) in
     if (n="i" || n="num_blocks") && type_of v <> `:num`
     then union (tyvars (type_of v)) acc else acc)
    (frees ff_body0) [];;
let ff_body = inst (map (fun tv -> (`:num`,tv)) stray_tyvars) ff_body0;;
let ff_concl = list_mk_forall(ff_vars, ff_body);;

(* ---- BODY_FF proof tactic (augment PRE with 16 explicit msg reads from dataq, *)
(*      then compose MINI;INNER;TAIL_LP threading the read-only set) ---- *)
let msg_reads_i =
  filter (fun c -> is_mem c &&
     (try let _=find_term (fun t->is_const t &&
             fst(dest_const t)="word_bytereverse") c in true with _->false))
    iPc;;
let msg_template = map normt msg_reads_i;;
let aug_of_prelam plam =
  let sv,body = dest_abs plam in
  let rsi = find (fun c -> try comp_str c = "RSI" with _ -> false) (conjuncts body) in
  let gi = rand(rand(rand(rhs_of rsi))) in
  let msgs = map (fun c -> vsubst[sv,sI; gi,`i:num`] c) msg_template in
  mk_abs(sv, list_mk_conj (conjuncts body @ msgs));;

let sublem_a = ENSURES_SUBLEMMA_TAC execup;;
let INNER_HYP_CLOSER =
  REWRITE_TAC[NONOVERLAPPING_CLAUSES] THEN REPEAT CONJ_TAC THEN
  (NONOVERLAPPING_TAC ORELSE CONV_TAC WORD_REDUCE_CONV ORELSE CONV_TAC WORD_RULE);;
let SEAM_RECON =
  REWRITE_TAC[WORD_ADD_ASSOC_CONSTS; WORD_ADD_0] THEN
  CONV_TAC(DEPTH_CONV NUM_ADD_CONV) THEN ASM_REWRITE_TAC[];;

let mini_leg = match_leg MINI_i THEN sublem_a "s" "s'" THEN SEAM_RECON;;
let inner_leg =
  SUBGOAL_THEN bighyp_i ASSUME_TAC THENL
   [ INNER_HYP_CLOSER;
     match_leg INNER_i THEN sublem_a "s" "s'" THEN SEAM_RECON ];;

let HBSTEP =
  prove(`sha256_hash_blocks (m_fn:num->int32 list) [a;b;c;d;e;f;g;h] (i+1) =
         sha256_block (m_fn i)
           (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i)`,
        REWRITE_TAC[sha256_hash_blocks]);;
let HBLIST =
  prove(`[EL 0 (sha256_hash_blocks (m_fn:num->int32 list) [a;b;c;d;e;f;g;h] i);
          EL 1 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 2 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 3 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 4 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 5 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 6 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 7 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i)] =
         sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] i`,
        MATCH_MP_TAC EL8_RECONSTRUCT THEN
        MATCH_MP_TAC LENGTH_SHA256_HASH_BLOCKS THEN
        REWRITE_TAC[LENGTH] THEN ARITH_TAC);;
let SB_GEN =
  prove(`!m hsh j. j < 8
         ==> EL j (sha256_block m hsh) =
             word_add (EL j (sha256_compress_rounds m hsh 64)) (EL j hsh)`,
        REWRITE_TAC[sha256_block] THEN REPEAT GEN_TAC THEN
        CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
        REWRITE_TAC[ARITH_RULE `j < 8 <=> j = 0 \/ j = 1 \/ j = 2 \/ j = 3 \/
                                j = 4 \/ j = 5 \/ j = 6 \/ j = 7`] THEN
        STRIP_TAC THEN ASM_REWRITE_TAC[] THEN
        CONV_TAC(ONCE_DEPTH_CONV EL_CONV) THEN REWRITE_TAC[]);;
let RSI_ADV = prove
 (`word_add (word_add (dataptr:int64) (word (64 * i))) (word 64) =
   word_add dataptr (word (64 * (i + 1)))`,
  SUBST1_TAC(ARITH_RULE `64 * (i + 1) = 64 * i + 64`) THEN
  CONV_TAC WORD_RULE);;
let taillp_reconcile =
  REWRITE_TAC[HBSTEP] THEN SIMP_TAC[SB_GEN; ARITH] THEN
  REWRITE_TAC[HBLIST] THEN
  REWRITE_TAC[RSI_ADV] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[RECON; RSI_ADV; HBLIST]) THEN
  REWRITE_TAC[RECON] THEN ASM_REWRITE_TAC[];;
let taillp_leg =
  match_leg TAILLP_i THEN sublem_a "s" "s'" THEN taillp_reconcile;;

let MSGREAD_ONE =
  W(fun (asl,w) ->
     let elapp = rand(rand w) in
     let jv = rand(rator elapp) in
     let iv2 = rand(rand elapp) in
     FIRST_X_ASSUM(fun th ->
        if is_forall(concl th) then MP_TAC(SPECL [iv2; jv] th) else NO_TAC) THEN
     ANTS_TAC THENL [ASM_ARITH_TAC; ALL_TAC] THEN
     DISCH_THEN(fun dth ->
        let gaddr = rand(rand(rand(rator(lhs w)))) in
        let daddr = rand(rand(rand(rator(lhs(concl dth))))) in
        SUBGOAL_THEN (mk_eq(gaddr, daddr))
          (fun aeq -> REWRITE_TAC[aeq] THEN ACCEPT_TAC dth)) THEN
     CONV_TAC WORD_RULE);;
let DERIVE_MSG_READS = REPEAT CONJ_TAC THEN MSGREAD_ONE;;

let compose_tac =
  ENSURES_SEQUENCE_TAC `pc + 87` bodyQ87 THEN CONJ_TAC THENL
   [ mini_leg;
     ENSURES_SEQUENCE_TAC `pc + 4355` bodyQ4355 THEN CONJ_TAC THENL
      [ inner_leg; taillp_leg ] ];;

let body_ff_tac =
  REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN REPEAT DISCH_TAC THEN
  MATCH_MP_TAC ENSURES_PRECONDITION_THM THEN
  W(fun (asl,w) ->
     let imp = lhand(body(rand w)) in
     let pprime = rator(lhand(snd(dest_forall imp))) in
     EXISTS_TAC (aug_of_prelam pprime)) THEN
  CONJ_TAC THENL
   [ GEN_TAC THEN REWRITE_TAC[] THEN
     DISCH_THEN(STRIP_ASSUME_TAC o CONV_RULE(TOP_DEPTH_CONV BETA_CONV)) THEN
     ASM_REWRITE_TAC[] THEN DERIVE_MSG_READS;
     compose_tac ];;

let SHA256_BLOCK_NOHW_BODY_FF_BL = prove(ff_concl, body_ff_tac);;

(* ============================ assemble core CORRECT ===================== *)
(* body leg: fold BODY_FF's imp-chain (IMP_IMP) + expand SOME_FLAGS so its frame *)
(* matches the scaffold's expanded `[CF;PF;AF;ZF;SF;OF]` (session-034).           *)
let body_leg =
  REPEAT STRIP_TAC THEN
  MATCH_MP_TAC (REWRITE_RULE[SOME_FLAGS; IMP_IMP] SHA256_BLOCK_NOHW_BODY_FF_BL) THEN
  ASM_REWRITE_TAC[] THEN TRY ASM_ARITH_TAC;;

let SHA256_COMPRESS_BL_CORRECT = prove(correct_concl,
  REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN REPEAT STRIP_TAC THEN
  ENSURES_SEQUENCE_TAC `pc + 78` Q78 THEN CONJ_TAC THENL
   [ leg1;
     ENSURES_WHILE_PUP_TAC `num_blocks:num` `pc + 78` `pc + 4426` invariant THEN
     REPEAT CONJ_TAC THENL
      [ ASM_ARITH_TAC;
        (ENSURES_INIT_TAC "s0" THEN ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[]);
        body_leg; leg_back; leg_exit ] ]);;

(* ===================================================================== *)
(* Phase 12 — Windows subroutine CORRECT wrappers (the last 2 of 4).      *)
(* The Windows .obj is the inline-shim image: 16-instr prologue (endbr +  *)
(* 2 pushes rdi/rsi + 3 ABI-arg moves + SysV prologue) wrapping the SysV  *)
(* body at offset 11, with a non-pop epilogue (mov-restores + pop rsi/rdi *)
(* + ret).  We MP the bl_tmc-core SHA256_COMPRESS_BL_CORRECT *)
(* (over BUTLAST sysv_tmc, at pc:=pc+11) through the windows prologue +   *)
(* epilogue, keccak4-style: dynamic and-rsp alignment delta (ABBREV,      *)
(* BITBLAST), but with the +71 offset (2 extra windows pushes vs SysV +63)*)
(* and the FOUR data<->frame nonoverlap hyps widened to 239 (=231 frame + *)
(* 8-byte ret slot) so the return-address fact carries across the core    *)
(* BIGSTEP.  The bl-core's (pc+11)+N offsets are reduced to pc+40/pc+4443/ *)
(* pc+98 before the MP so its PRE/POST RIP + riprel match the stepped     *)
(* windows state; X86_BIGSTEP_TAC steps with the WINDOWS exec (the program *)
(* in memory) while the MP target is the bl-core.                         *)

let ra_fact_w = ref TRUTH;;

let SHA256_COMPRESS_NOIBT_WINDOWS_SUBROUTINE_CORRECT = prove
 (`!pc kk statep dataptr (num_blocks:num)
    a b c d e f g h (m_fn:num->int32 list) stackpointer returnaddress.
   riprel32_within_bounds kk (pc + 98) /\
   nonoverlapping (word pc,4478) (statep:int64,32) /\
   nonoverlapping (word pc,4478) (word_sub stackpointer (word 231):int64,239) /\
   nonoverlapping (word pc,4478) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (word pc,4478) (word kk:int64,608) /\
   nonoverlapping (statep:int64,32) (word_sub stackpointer (word 231):int64,239) /\
   nonoverlapping (statep:int64,32) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (statep:int64,32) (word kk:int64,608) /\
   nonoverlapping (word_sub stackpointer (word 231):int64,239) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (word_sub stackpointer (word 231):int64,239) (word kk:int64,608) /\
   0 < num_blocks /\
   val (dataptr:int64) + 64 * num_blocks < 2 EXP 64
   ==> ensures x86
        (\s. bytes_loaded s (word pc) (sha256_compress_windows_tmc pc kk) /\
             read RIP s = word pc /\
             read RSP s = stackpointer /\
             read (memory :> bytes64 stackpointer) s = returnaddress /\
             WINDOWS_C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
             read (memory :> bytes32 statep) s = (a:int32) /\
             read (memory :> bytes32 (word_add statep (word 4))) s = (b:int32) /\
             read (memory :> bytes32 (word_add statep (word 8))) s = (c:int32) /\
             read (memory :> bytes32 (word_add statep (word 12))) s = (d:int32) /\
             read (memory :> bytes32 (word_add statep (word 16))) s = (e:int32) /\
             read (memory :> bytes32 (word_add statep (word 20))) s = (f:int32) /\
             read (memory :> bytes32 (word_add statep (word 24))) s = (g:int32) /\
             read (memory :> bytes32 (word_add statep (word 28))) s = (h:int32) /\
             bytes_loaded s (word kk) K256 /\
             (!i' j. i' < num_blocks /\ j < 16
                     ==> read (memory :> bytes32
                           (word_add dataptr (word (64*i' + 4*j)))) s =
                         word_bytereverse (EL j (m_fn i'):int32)))
        (\s. read RIP s = returnaddress /\
             read RSP s = word_add stackpointer (word 8) /\
             read (memory :> bytes32 statep) s =
               EL 0 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 4))) s =
               EL 1 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 8))) s =
               EL 2 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 12))) s =
               EL 3 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 16))) s =
               EL 4 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 20))) s =
               EL 5 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 24))) s =
               EL 6 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 28))) s =
               EL 7 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks))
        (MAYCHANGE [RSP] ,, WINDOWS_MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
         MAYCHANGE [memory :> bytes32 statep;
                    memory :> bytes32 (word_add statep (word 4));
                    memory :> bytes32 (word_add statep (word 8));
                    memory :> bytes32 (word_add statep (word 12));
                    memory :> bytes32 (word_add statep (word 16));
                    memory :> bytes32 (word_add statep (word 20));
                    memory :> bytes32 (word_add statep (word 24));
                    memory :> bytes32 (word_add statep (word 28))] ,,
         MAYCHANGE [memory :> bytes (word_sub stackpointer (word 231),231)])`,
  REWRITE_TAC[WINDOWS_MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI; WINDOWS_C_ARGUMENTS;
              fst SHA256_WIN_EXEC] THEN
  REPLICATE_TAC 14 GEN_TAC THEN
  WORD_FORALL_OFFSET_TAC 231 THEN
  REWRITE_TAC[K_BYTES_FORM] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_PRESERVED_TAC "rdi_init" `RDI` THEN
  ENSURES_PRESERVED_TAC "rsi_init" `RSI` THEN
  ENSURES_PRESERVED_TAC "rbx_init" `RBX` THEN
  ENSURES_PRESERVED_TAC "rbp_init" `RBP` THEN
  ENSURES_PRESERVED_TAC "r12_init" `R12` THEN
  ENSURES_PRESERVED_TAC "r13_init" `R13` THEN
  ENSURES_PRESERVED_TAC "r14_init" `R14` THEN
  ENSURES_PRESERVED_TAC "r15_init" `R15` THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA256_WIN_EXEC (1--16) THEN
  (* capture RA fact at s16 (prologue end, pre-BIGSTEP). Deferred deref later. *)
  W(fun (asl,w) ->
     let isra (_,th) =
       let c = concl th in
       (try let _ = find_term (fun t -> try fst(dest_var t)="returnaddress"
                                        with _->false) c in is_eq c
        with _->false) in
     ra_fact_w := snd (List.find isra asl); ALL_TAC) THEN
  (* DELTA — s039 word-subtraction form with 63->71 (BITBLAST-friendly). *)
  ABBREV_TAC
   `delta =
    val(word_sub (word 71)
                 (word_and (word_add stackpointer (word 71)) (word 63)):int64)` THEN
  SUBGOAL_THEN `delta <= 71` ASSUME_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `word_and (word_add stackpointer (word 71)) (word 18446744073709551552):int64 =
    word_add stackpointer (word delta)`
  SUBST_ALL_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `4 * val (word_shl (word num_blocks:int64) 4) = 64 * num_blocks`
  ASSUME_TAC THENL
   [REWRITE_TAC[VAL_WORD_SHL; VAL_WORD; DIMINDEX_64] THEN
    REWRITE_TAC[ARITH_RULE `2 EXP 4 = 16`] THEN
    SUBGOAL_THEN `num_blocks MOD 2 EXP 64 = num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 64 * n < 2 EXP 64 ==> n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    SUBGOAL_THEN `(16 * num_blocks) MOD 2 EXP 64 = 16 * num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 64 * n < 2 EXP 64 ==> 16 * n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    ARITH_TAC; ALL_TAC] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME
    `4 * val (word_shl (word num_blocks:int64) 4) = 64 * num_blocks`]) THEN
  (* re-derive the bl-core's bytelist K demand at s16. *)
  SUBGOAL_THEN
   `read (memory :> bytelist (word kk:int64,LENGTH K256)) s16 = K256`
  ASSUME_TAC THENL
   [REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K256] THEN ASM_REWRITE_TAC[]; ALL_TAC] THEN
  (* bridge windows_tmc bytes_loaded -> bl_tmc bytes_loaded at pc+11 (for the MP). *)
  SUBGOAL_THEN
   `bytes_loaded s16 (word (pc + 11))
       (sha256_compress_bl_tmc (pc + 11) kk)`
  ASSUME_TAC THENL
   [REWRITE_TAC[sha256_compress_bl_tmc] THEN
    MATCH_MP_TAC SHA256_WIN_BODY_BRIDGE THEN ASM_REWRITE_TAC[]; ALL_TAC] THEN
  (* Reduce the (pc+11)+N offsets in the MP'd bl-core so its PRE/POST RIP +
     riprel hyp are syntactically `pc+40`/`pc+4443`/`pc+98` and match the stepped
     state. WITHOUT this the PRE conjunct `read RIP = word((pc+11)+29)` does NOT
     match the stepped `word(pc+40)`, the BIGSTEP P-side leaves a residual goal,
     and the downstream SUBGOAL_THEN...THENL sees 2x goals -> seqapply mismatch. *)
  MP_TAC(REWRITE_RULE[ARITH_RULE `(pc + 11) + 29 = pc + 40`;
                      ARITH_RULE `(pc + 11) + 4432 = pc + 4443`;
                      ARITH_RULE `(pc + 11) + 87 = pc + 98`; IMP_IMP] (SPECL
   [`pc + 11`; `kk:num`; `word_add stackpointer (word delta):int64`;
    `statep:int64`; `dataptr:int64`;
    `word_add dataptr (word (64*num_blocks)):int64`;
    `word_add stackpointer (word 215):int64`; `num_blocks:num`;
    `a:int32`;`b:int32`;`c:int32`;`d:int32`;`e:int32`;`f:int32`;`g:int32`;`h:int32`;
    `m_fn:num->int32 list`]
   SHA256_COMPRESS_BL_CORRECT)) THEN
  ANTS_TAC THENL
   [REPEAT CONJ_TAC THEN
    (NONOVERLAPPING_TAC ORELSE ASM_REWRITE_TAC[]); ALL_TAC] THEN
  REWRITE_TAC[SOME_FLAGS] THEN
  (* BIGSTEP stepping-exec MUST be the WINDOWS exec (the program loaded in
     memory whose bytes_loaded NONSELFMODIFYING_STATE_UPDATE_TAC maintains),
     NOT the bl-core exec — keccak4 uses windows_tmc_EXEC here. The bl-core is
     the MP'd `ensures` target; the BIGSTEP exec is for stepping. *)
  X86_BIGSTEP_TAC SHA256_WIN_EXEC "s17" THEN
  ABBREV_TAC `asp:int64 = word_add stackpointer (word delta)` THEN
  (* re-derive RA at s17 (deferred deref of ra_fact_w). ret slot = stackpointer+231.
     With the 239 hyp, RA-slot _|_ statep is provable so ASSUMPTION_STATE_UPDATE_TAC
     carries the RA fact across the bl-core frame. *)
  SUBGOAL_THEN
   `read (memory :> bytes64 (word_add stackpointer (word 231))) s17 = returnaddress`
  ASSUME_TAC THENL
   [W(fun (asl,w) -> ASSUME_TAC(!ra_fact_w)) THEN
    FIRST_X_ASSUM(MP_TAC o check (maychange_term o concl)) THEN
    REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
    REWRITE_TAC[GSYM SEQ_ASSOC] THEN
    PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
    CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
    REWRITE_TAC[ASSIGNS_THM] THEN
    REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
    ASSUMPTION_STATE_UPDATE_TAC THEN
    DISCH_THEN(K ALL_TAC) THEN
    ASM_REWRITE_TAC[]; ALL_TAC] THEN
  X86_STEPS_TAC SHA256_WIN_EXEC (18--28) THEN
  RULE_ASSUM_TAC(REWRITE_RULE[SYM(ASSUME
     `word_add stackpointer (word delta):int64 = asp`)]) THEN
  ENSURES_FINAL_STATE_TAC THEN
  REPEAT CONJ_TAC THEN
  TRY MONOTONE_MAYCHANGE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  TRY(CONV_TAC WORD_RULE));;

let SHA256_COMPRESS_WINDOWS_SUBROUTINE_CORRECT = prove
 (`!pc kk statep dataptr (num_blocks:num)
    a b c d e f g h (m_fn:num->int32 list) stackpointer returnaddress.
   riprel32_within_bounds kk (pc + 102) /\
   nonoverlapping (word pc,4482) (statep:int64,32) /\
   nonoverlapping (word pc,4482) (word_sub stackpointer (word 231):int64,239) /\
   nonoverlapping (word pc,4482) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (word pc,4482) (word kk:int64,608) /\
   nonoverlapping (statep:int64,32) (word_sub stackpointer (word 231):int64,239) /\
   nonoverlapping (statep:int64,32) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (statep:int64,32) (word kk:int64,608) /\
   nonoverlapping (word_sub stackpointer (word 231):int64,239) (dataptr:int64,64*num_blocks) /\
   nonoverlapping (word_sub stackpointer (word 231):int64,239) (word kk:int64,608) /\
   0 < num_blocks /\
   val (dataptr:int64) + 64 * num_blocks < 2 EXP 64
   ==> ensures x86
        (\s. bytes_loaded s (word pc) (sha256_compress_windows_mc pc kk) /\
             read RIP s = word pc /\
             read RSP s = stackpointer /\
             read (memory :> bytes64 stackpointer) s = returnaddress /\
             WINDOWS_C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
             read (memory :> bytes32 statep) s = (a:int32) /\
             read (memory :> bytes32 (word_add statep (word 4))) s = (b:int32) /\
             read (memory :> bytes32 (word_add statep (word 8))) s = (c:int32) /\
             read (memory :> bytes32 (word_add statep (word 12))) s = (d:int32) /\
             read (memory :> bytes32 (word_add statep (word 16))) s = (e:int32) /\
             read (memory :> bytes32 (word_add statep (word 20))) s = (f:int32) /\
             read (memory :> bytes32 (word_add statep (word 24))) s = (g:int32) /\
             read (memory :> bytes32 (word_add statep (word 28))) s = (h:int32) /\
             bytes_loaded s (word kk) K256 /\
             (!i' j. i' < num_blocks /\ j < 16
                     ==> read (memory :> bytes32
                           (word_add dataptr (word (64*i' + 4*j)))) s =
                         word_bytereverse (EL j (m_fn i'):int32)))
        (\s. read RIP s = returnaddress /\
             read RSP s = word_add stackpointer (word 8) /\
             read (memory :> bytes32 statep) s =
               EL 0 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 4))) s =
               EL 1 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 8))) s =
               EL 2 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 12))) s =
               EL 3 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 16))) s =
               EL 4 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 20))) s =
               EL 5 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 24))) s =
               EL 6 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes32 (word_add statep (word 28))) s =
               EL 7 (sha256_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks))
        (MAYCHANGE [RSP] ,, WINDOWS_MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
         MAYCHANGE [memory :> bytes32 statep;
                    memory :> bytes32 (word_add statep (word 4));
                    memory :> bytes32 (word_add statep (word 8));
                    memory :> bytes32 (word_add statep (word 12));
                    memory :> bytes32 (word_add statep (word 16));
                    memory :> bytes32 (word_add statep (word 20));
                    memory :> bytes32 (word_add statep (word 24));
                    memory :> bytes32 (word_add statep (word 28))] ,,
         MAYCHANGE [memory :> bytes (word_sub stackpointer (word 231),231)])`,
  MATCH_ACCEPT_TAC(ADD_IBT_RULE
    ~bridge:(Some SHA256_COMPRESS_WINDOWS_MC_BRIDGE)
    SHA256_COMPRESS_NOIBT_WINDOWS_SUBROUTINE_CORRECT));;

(* ========================================================================= *)
(* Phase 13 — core SAFE (constant-time + memory safety).                     *)
(*                                                                           *)
(* Mirrors the core CORRECT (entry pc+29, exit pc+4432, explicit register    *)
(* reads — the prologue has already transformed the SysV C args by pc+29, so *)
(* the core has NO C_ARGUMENTS; mk_safety_spec cannot be used on it). The     *)
(* event trace depends only on PUBLIC data (dataptr statep num_blocks kk pc   *)
(* stackpointer): SHA-256 is data-oblivious — the inner-loop trip count is    *)
(* rodata-determined (the K256 sentinel bytes), not input-dependent.         *)
(*   read-set  = [statep,32; dataptr,64*num_blocks; stackptr,96; word kk,608] *)
(*   write-set = [statep,32; stackptr,96]                                     *)
(* word kk,608 is the K256 rodata region (RIP-relative, ~readonly_objects).   *)
(* ========================================================================= *)

(* Self-contained SAFE builders (do NOT reuse the shadowed L11411 correct_pres/  *)
(* frame_full, which are over bl_tmc/4464 — the Windows MP target).  The core    *)
(* SAFE is over the PRIMARY core (tmc + 4465 + EXEC), so we restate them here     *)
(* with the full 4465 length.  ONE stack-pointer variable `stackpointer`         *)
(* throughout (the safety machinery — mk_safety_spec, DISCHARGE_MEMACCESS_-       *)
(* INBOUNDS_TAC's CONTAINED_TAC — keys on that literal name, and the post's       *)
(* memaccess_inbounds bounds it as [stackpointer,96]; a distinct free `stackptr`  *)
(* would escape the forall and block the inbounds discharge).                     *)
let safe_pres =
 [ `nonoverlapping (word pc,4465) (statep:int64,32)`;
   `nonoverlapping (word pc,4465) (stackpointer:int64,96)`;
   `nonoverlapping (word pc,4465) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (word pc,4465) (word kk:int64,608)`;
   `nonoverlapping (statep:int64,32) (stackpointer:int64,96)`;
   `nonoverlapping (statep:int64,32) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (statep:int64,32) (word kk:int64,608)`;
   `nonoverlapping (stackpointer:int64,96) (dataptr:int64,64*num_blocks)`;
   `nonoverlapping (stackpointer:int64,96) (word kk:int64,608)`;
   `0 < num_blocks`;
   `val (dataptr:int64) + 64 * num_blocks < 2 EXP 64`;
   `endp:int64 = word_add dataptr (word (64*num_blocks))`;
   `riprel32_within_bounds kk (pc + 87)` ];;

let safe_frame =
  `(MAYCHANGE [RIP;RAX;RBX;RCX;RDX;RBP;RDI;RSI;R8;R9;R10;R11;R12;R13;R14;R15] ,,
    MAYCHANGE [memory :> bytes32 statep;
               memory :> bytes32 (word_add statep (word 4));
               memory :> bytes32 (word_add statep (word 8));
               memory :> bytes32 (word_add statep (word 12));
               memory :> bytes32 (word_add statep (word 16));
               memory :> bytes32 (word_add statep (word 20));
               memory :> bytes32 (word_add statep (word 24));
               memory :> bytes32 (word_add statep (word 28))] ,,
    MAYCHANGE [memory :> bytes64 (word_add stackpointer (word 64));
               memory :> bytes64 (word_add stackpointer (word 72));
               memory :> bytes64 (word_add stackpointer (word 80));
               memory :> bytes64 (word_add stackpointer (word 88))] ,,
    MAYCHANGE [memory :> bytes32 stackpointer;
               memory :> bytes32 (word_add stackpointer (word 4));
               memory :> bytes32 (word_add stackpointer (word 8));
               memory :> bytes32 (word_add stackpointer (word 12));
               memory :> bytes32 (word_add stackpointer (word 16));
               memory :> bytes32 (word_add stackpointer (word 20));
               memory :> bytes32 (word_add stackpointer (word 24));
               memory :> bytes32 (word_add stackpointer (word 28));
               memory :> bytes32 (word_add stackpointer (word 32));
               memory :> bytes32 (word_add stackpointer (word 36));
               memory :> bytes32 (word_add stackpointer (word 40));
               memory :> bytes32 (word_add stackpointer (word 44));
               memory :> bytes32 (word_add stackpointer (word 48));
               memory :> bytes32 (word_add stackpointer (word 52));
               memory :> bytes32 (word_add stackpointer (word 56));
               memory :> bytes32 (word_add stackpointer (word 60))] ,,
    MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`;;

let core_safe_concl =
  let pre =
   `\s. bytes_loaded s (word pc) (sha256_compress_tmc pc kk) /\
        read RIP s = word (pc + 29) /\
        read (memory :> bytelist (word kk:int64, LENGTH K256)) s = K256 /\
        read RSP s = stackpointer /\
        read RDI s = statep /\
        read RSI s = dataptr /\
        read RDX s = endp /\
        read RAX s = origsp /\
        read events s = e` in
  let post =
   `\s. read RIP s = word (pc + 4432) /\
        read RSP s = stackpointer /\
        read (memory :> bytes64 (word_add stackpointer (word 88))) s = origsp /\
        (exists e2.
           read events s = APPEND e2 e /\
           e2 = f_events dataptr statep num_blocks kk pc stackpointer /\
           memaccess_inbounds e2
             [statep:int64,32; dataptr:int64,64*num_blocks;
              stackpointer:int64,96; word kk:int64,608]
             [statep:int64,32; stackpointer:int64,96])` in
  mk_exists(`f_events:int64->int64->num->num->num->int64->(uarch_event)list`,
    list_mk_forall(
      [`e:(uarch_event)list`;`pc:num`;`kk:num`;`stackpointer:int64`;
       `statep:int64`;`dataptr:int64`;`endp:int64`;`origsp:int64`;
       `num_blocks:num`],
      itlist (curry mk_imp) safe_pres
        (list_mk_comb(`ensures x86`, [pre; post; safe_frame]))));;

(* The concrete f_events skeleton: epilogue ++ (loop iterated num_blocks) ++      *)
(* prologue (validated session-045; matches ENSURES_EVENTS_WHILE_UP2's expected   *)
(* APPEND epil (APPEND (ENUMERATEL n loop) prol) shape).                          *)
let safe_f_events_shape =
  `\(dataptr:int64) (statep:int64) (num_blocks:num) (kk:num) (pc:num)
      (stackpointer:int64).
    APPEND
      (f_ev_epil dataptr statep num_blocks kk pc stackpointer)
      (APPEND
        (ENUMERATEL num_blocks (\i.
          f_ev_loop dataptr statep num_blocks kk pc stackpointer i))
        (f_ev_prol dataptr statep num_blocks kk pc stackpointer))
  :(uarch_event)list`;;

(* loop invariant: PUBLIC regs/slots + the rodata read.  pc1=pc+78 (loop top),   *)
(* pc2=pc+4432 (the jb FALL-THROUGH; the UP2 body leg steps the jb itself, so the *)
(* exit leg is 0-step and needs no CF).  The rodata read is carried in the        *)
(* FRAME-CARRYING `bytes`+`num_of_bytelist` form (the `bytelist` aggregate does    *)
(* NOT survive stepping — session-047 / cf. session-036) so the body leg can       *)
(* re-derive the 3 sentinel bytes every iteration to resolve the inner back-edges. *)
let safe_loop_inv =
  `\i s. read RSP s = stackpointer /\
         read RSI s = word_add dataptr (word (64*i)) /\
         read (memory :> bytes64 (word_add stackpointer (word 64))) s = statep /\
         read (memory :> bytes64 (word_add stackpointer (word 80))) s = endp /\
         read (memory :> bytes64 (word_add stackpointer (word 88))) s = origsp /\
         read (memory :> bytes (word kk:int64,608)) s = num_of_bytelist K256`;;

(* Biconditional CF bridge for the folded outer jb: the tail's `cmp endp,rsi;jb`  *)
(* leaves the conditional PC `if val(dataptr+64*(i+1)) < val endp then ..`; this    *)
(* turns that pointer inequality into the UP2 index test `i+1 < num_blocks`.        *)
let CFLT_IFF = prove
 (`!(dataptr:int64) i num_blocks.
     i < num_blocks /\ val dataptr + 64 * num_blocks < 2 EXP 64
     ==> (val (word_add dataptr (word (64*(i+1)))) <
          val (word_add dataptr (word (64*num_blocks))) <=> i + 1 < num_blocks)`,
  REPEAT STRIP_TAC THEN
  REWRITE_TAC[VAL_WORD_ADD; VAL_WORD; DIMINDEX_64] THEN
  SUBGOAL_THEN `(64 * (i+1)) MOD 2 EXP 64 = 64 * (i+1) /\
                (64 * num_blocks) MOD 2 EXP 64 = 64 * num_blocks`
    (CONJUNCTS_THEN SUBST1_TAC) THENL
   [CONJ_TAC THEN MATCH_MP_TAC MOD_LT THEN ASM_ARITH_TAC; ALL_TAC] THEN
  SUBGOAL_THEN `(val(dataptr:int64) + 64 * (i+1)) MOD 2 EXP 64 =
                 val dataptr + 64 * (i+1) /\
                (val(dataptr:int64) + 64 * num_blocks) MOD 2 EXP 64 =
                 val dataptr + 64 * num_blocks`
    (CONJUNCTS_THEN SUBST1_TAC) THENL
   [CONJ_TAC THEN MATCH_MP_TAC MOD_LT THEN ASM_ARITH_TAC; ASM_ARITH_TAC]);;

let SHA256_COMPRESS_SAFE = prove(core_safe_concl,
  CONCRETIZE_F_EVENTS_TAC safe_f_events_shape THEN
  REPEAT META_EXISTS_TAC THEN STRIP_TAC THEN
  REPEAT GEN_TAC THEN
  REWRITE_TAC[NONOVERLAPPING_CLAUSES; SOME_FLAGS] THEN REPEAT STRIP_TAC THEN
  ENSURES_EVENTS_WHILE_UP2_TAC `num_blocks:num` `pc + 78` `pc + 4432`
    safe_loop_inv THEN
  REPEAT CONJ_TAC THENL [
    (* arith: ~(num_blocks = 0) *)
    ASM_ARITH_TAC;
    (* init: prologue pc+29 -> pc+78 (13 instrs) -> loopinv 0.  Convert the PRE
       bytelist read into the frame-carrying bytes form FIRST (so loopinv-0's
       rodata conjunct closes after stepping), reduce 64*0, then peel the RSI
       loop-inv conjunct so DISCHARGE sees a bare `exists e2`. *)
    ENSURES_INIT_TAC "s0" THEN
    SUBGOAL_THEN `read (memory :> bytes (word kk:int64,608)) s0 = num_of_bytelist K256`
      ASSUME_TAC THENL
     [ UNDISCH_TAC `read (memory :> bytelist (word kk:int64,LENGTH K256)) s0 = K256` THEN
       REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K256] THEN STRIP_TAC THEN
       ASM_REWRITE_TAC[]; ALL_TAC ] THEN
    X86_STEPS_TAC SHA256_COMPRESS_EXEC (1--13) THEN
    ENSURES_FINAL_STATE_TAC THEN
    REWRITE_TAC[MULT_CLAUSES; WORD_ADD_0; ADD_CLAUSES] THEN ASM_REWRITE_TAC[] THEN
    (* loopinv-0 now carries TWO non-events conjuncts that may not auto-close
       (RSI by WORD_RULE; slot88=origsp by ASM_REWRITE — the prologue's
       `mov %rax,88(%rsp)` with rax=origsp writes it); peel each, stopping at the
       `exists e2` events conjunct for the safety discharge. *)
    REPEAT (CONJ_TAC THENL
     [ (CONV_TAC WORD_RULE ORELSE ASM_REWRITE_TAC[]); ALL_TAC ]) THEN
    DISCHARGE_SAFETY_PROPERTY_TAC;
    (* body: pc+78 -> (jb) pc+78/pc+4432, ONE full block as a single continuous
       C8 segment of N=2798 instrs (head 515 [pc+78->1766] + 3 inner iters x754
       [the inner jne back-edge to pc+1766 resolves CONCRETELY from the sentinel
       cmpb, so the segment follows all 3 iterations] + tail-incl-jb 21).  Events-
       only stepping stays FLAT (no spec terms), so no per-round cuts are needed.
       Closers (cf. CORRECT TAIL_LP/leg_back): convert the carried bytes-rodata
       back to the bytelist form, derive the 3 sentinel bytes, fold RBP at pc+87,
       C8-step, then bridge the symbolic CF -> i+1<num_blocks (CFLT_IFF + endp_def)
       for the conditional PC, RSI_ADV for the +64 advance, DISCHARGE for events. *)
    REPEAT STRIP_TAC THEN
    ENSURES_INIT_TAC "s0" THEN STRIP_EXISTS_ASSUM_TAC THEN
    SUBGOAL_THEN `read (memory :> bytelist (word kk:int64,LENGTH K256)) s0 = K256`
      ASSUME_TAC THENL
     [ ASM_REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K256]; ALL_TAC ] THEN
    FIRST_ASSUM(fun th ->
      let c = concl th in
      if is_eq c && (try fst(dest_const(rand c))="K256" with _->false) &&
         (try let _=find_term (fun t->is_const t && fst(dest_const t)="bytelist")
                (lhand c) in true with _->false)
      then ASSUME_TAC(MATCH_MP SHA256_SENTINEL_BYTES th) else NO_TAC) THEN
    X86_STEPS_C8_TAC SHA256_COMPRESS_EXEC (1--2) THEN
    UNDISCH_TAC
     `read RBP s2 =
        word (val (word (pc + 87):(64)word) +
              val (word_sx (iword (&kk - (&pc + &87)):int32):(64)word):num)` THEN
    IMP_REWRITE_TAC[RIP_REL_ADDR_FOLD] THEN ASM_REWRITE_TAC[] THEN DISCH_TAC THEN
    X86_STEPS_C8_TAC SHA256_COMPRESS_EXEC (3--2798) THEN
    ENSURES_FINAL_STATE_TAC THEN
    (* the tail's `cmp endp,rsi; jb` leaves the conditional PC keyed on the pointer
       inequality val(dataptr+64*(i+1)) < val endp; substitute endp then turn that
       inequality into the UP2 index test i+1<num_blocks. *)
    SUBGOAL_THEN `val (word_add (dataptr:int64) (word (64*(i+1)))) <
                  val (word_add dataptr (word (64*num_blocks))) <=>
                  i + 1 < num_blocks`
      ASSUME_TAC THENL
     [ MATCH_MP_TAC CFLT_IFF THEN ASM_REWRITE_TAC[]; ALL_TAC ] THEN
    RULE_ASSUM_TAC(REWRITE_RULE
      [ASSUME `endp:int64 = word_add dataptr (word (64*num_blocks))`]) THEN
    ASM_REWRITE_TAC[RSI_ADV] THEN
    (* peel each non-events conjunct (RSI via RSI_ADV; the conditional PC by
       rewriting the goal's pointer-ineq with the CF-bridge fact then pushing
       `word` through the if with GSYM COND_RAND), leaving exactly `exists e2`
       for the safety discharge. *)
    REPEAT(CONJ_TAC THENL
     [ TRY(REWRITE_TAC[RSI_ADV]) THEN
       (REFL_TAC ORELSE CONV_TAC WORD_RULE ORELSE
        (FIRST_X_ASSUM(fun th ->
           if is_iff(concl th) then REWRITE_TAC[th] else NO_TAC) THEN
         REWRITE_TAC[GSYM COND_RAND]) ORELSE
        ASM_REWRITE_TAC[]);
       ALL_TAC ]) THEN
    DISCHARGE_SAFETY_PROPERTY_TAC;
    (* exit: loopinv num_blocks @ pc+4432 -> postcond @ pc+4432 (0-step).
       STRIP_EXISTS_ASSUM_TAC exposes the carried events trace so the epilogue
       f_ev_epil unifies to []. *)
    ENSURES_INIT_TAC "s0" THEN STRIP_EXISTS_ASSUM_TAC THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    DISCHARGE_SAFETY_PROPERTY_TAC ]);;

(* ========================================================================= *)
(* Phase 14 — bl_tmc core SAFE (the Windows-wrapper MP target).              *)
(*                                                                           *)
(* The Windows image loads only bl_tmc = BUTLAST sysv_tmc (the SysV `ret`    *)
(* byte is dropped — session-040), so the Windows SAFE wrappers MP a SAFE    *)
(* theorem over bl_tmc, NOT the primary tmc core SAFE (weakening tmc->bl_tmc *)
(* is unsound).  This is the SAFE analogue of SHA256_COMPRESS_  *)
(* BL_CORRECT (L11801): the committed core-SAFE statement re-stated over     *)
(* bl_tmc (4465->4464) via term surgery, proved by the SAME tactic with      *)
(* SHA256_COMPRESS_EXEC -> SHA256_BL_EXEC (bl_tmc decodes        *)
(* identically to tmc for rows [0,4464), so the C8 body-leg replay holds      *)
(* verbatim).  Validated end-to-end on the SAFE dev prefix (S053_BLSAFE_      *)
(* REAL_PROVED, real 2798-instr body leg, cheat-free).                       *)
let bl_core_safe_concl =
  subst [`sha256_compress_bl_tmc`,
         `sha256_compress_tmc`;
         `4464`,`4465`] core_safe_concl;;

let SHA256_COMPRESS_BL_SAFE = prove(bl_core_safe_concl,
  CONCRETIZE_F_EVENTS_TAC safe_f_events_shape THEN
  REPEAT META_EXISTS_TAC THEN STRIP_TAC THEN
  REPEAT GEN_TAC THEN
  REWRITE_TAC[NONOVERLAPPING_CLAUSES; SOME_FLAGS] THEN REPEAT STRIP_TAC THEN
  ENSURES_EVENTS_WHILE_UP2_TAC `num_blocks:num` `pc + 78` `pc + 4432`
    safe_loop_inv THEN
  REPEAT CONJ_TAC THENL [
    ASM_ARITH_TAC;
    (* init: prologue pc+29 -> pc+78 (13 instrs) over bl_tmc *)
    ENSURES_INIT_TAC "s0" THEN
    SUBGOAL_THEN `read (memory :> bytes (word kk:int64,608)) s0 = num_of_bytelist K256`
      ASSUME_TAC THENL
     [ UNDISCH_TAC `read (memory :> bytelist (word kk:int64,LENGTH K256)) s0 = K256` THEN
       REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K256] THEN STRIP_TAC THEN
       ASM_REWRITE_TAC[]; ALL_TAC ] THEN
    X86_STEPS_TAC SHA256_BL_EXEC (1--13) THEN
    ENSURES_FINAL_STATE_TAC THEN
    REWRITE_TAC[MULT_CLAUSES; WORD_ADD_0; ADD_CLAUSES] THEN ASM_REWRITE_TAC[] THEN
    REPEAT (CONJ_TAC THENL
     [ (CONV_TAC WORD_RULE ORELSE ASM_REWRITE_TAC[]); ALL_TAC ]) THEN
    DISCHARGE_SAFETY_PROPERTY_TAC;
    (* body: ONE continuous C8 segment N=2798 over bl_tmc *)
    REPEAT STRIP_TAC THEN
    ENSURES_INIT_TAC "s0" THEN STRIP_EXISTS_ASSUM_TAC THEN
    SUBGOAL_THEN `read (memory :> bytelist (word kk:int64,LENGTH K256)) s0 = K256`
      ASSUME_TAC THENL
     [ ASM_REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K256]; ALL_TAC ] THEN
    FIRST_ASSUM(fun th ->
      let c = concl th in
      if is_eq c && (try fst(dest_const(rand c))="K256" with _->false) &&
         (try let _=find_term (fun t->is_const t && fst(dest_const t)="bytelist")
                (lhand c) in true with _->false)
      then ASSUME_TAC(MATCH_MP SHA256_SENTINEL_BYTES th) else NO_TAC) THEN
    X86_STEPS_C8_TAC SHA256_BL_EXEC (1--2) THEN
    UNDISCH_TAC
     `read RBP s2 =
        word (val (word (pc + 87):(64)word) +
              val (word_sx (iword (&kk - (&pc + &87)):int32):(64)word):num)` THEN
    IMP_REWRITE_TAC[RIP_REL_ADDR_FOLD] THEN ASM_REWRITE_TAC[] THEN DISCH_TAC THEN
    X86_STEPS_C8_TAC SHA256_BL_EXEC (3--2798) THEN
    ENSURES_FINAL_STATE_TAC THEN
    SUBGOAL_THEN `val (word_add (dataptr:int64) (word (64*(i+1)))) <
                  val (word_add dataptr (word (64*num_blocks))) <=>
                  i + 1 < num_blocks`
      ASSUME_TAC THENL
     [ MATCH_MP_TAC CFLT_IFF THEN ASM_REWRITE_TAC[]; ALL_TAC ] THEN
    RULE_ASSUM_TAC(REWRITE_RULE
      [ASSUME `endp:int64 = word_add dataptr (word (64*num_blocks))`]) THEN
    ASM_REWRITE_TAC[RSI_ADV] THEN
    REPEAT(CONJ_TAC THENL
     [ TRY(REWRITE_TAC[RSI_ADV]) THEN
       (REFL_TAC ORELSE CONV_TAC WORD_RULE ORELSE
        (FIRST_X_ASSUM(fun th ->
           if is_iff(concl th) then REWRITE_TAC[th] else NO_TAC) THEN
         REWRITE_TAC[GSYM COND_RAND]) ORELSE
        ASM_REWRITE_TAC[]);
       ALL_TAC ]) THEN
    DISCHARGE_SAFETY_PROPERTY_TAC;
    (* exit: 0-step *)
    ENSURES_INIT_TAC "s0" THEN STRIP_EXISTS_ASSUM_TAC THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    DISCHARGE_SAFETY_PROPERTY_TAC ]);;

(* ========================================================================= *)
(* Phase 14 — SysV NOIBT subroutine SAFE.                                    *)
(*                                                                           *)
(* Wraps the core SAFE (SHA256_COMPRESS_SAFE) with the dynamic- *)
(* alignment prologue (`and rsp,-64`) + non-pop epilogue.  The wrapper       *)
(* targets the SAFE-spec stack frame of 215 bytes (= the 207-byte local      *)
(* frame + the 8-byte return-address slot the prologue's `and` exposes at    *)
(* sp+207..215): the READ inbounds set covers the RA read, and 215 >= the    *)
(* true 207-byte write region so the WRITE bound is a sound over-            *)
(* approximation.  ASSUME_CALLEE_SAFETY_TAC instantiates the core SAFE with  *)
(* origsp := word_add stackpointer (word 207), reconciling its slot88=origsp *)
(* POST against the wrapper's RA slot (the non-pop epilogue recovers the     *)
(* caller SP from slot88).  The spec is the mk_safety_spec output captured    *)
(* with the 215-frame SUBROUTINE_CORRECT statement (session-050/052); fed as  *)
(* a literal because mk_safety_spec needs subroutine_signatures, not loaded   *)
(* in this file.  Two fixes baked in (session-051): (1) the dataptr units      *)
(* rewrite val(word num_blocks:int64)*64 = 64*num_blocks before the inbounds  *)
(* discharge; (2) the 6 ENSURES_PRESERVED_TAC callee-saved intros so          *)
(* ENSURES_FINAL_STATE_TAC auto-closes the MAYCHANGE frame branch.            *)
(* ========================================================================= *)

let sysv_safe_spec_215 = `
   exists f_events.
    forall e pc kk statep dataptr num_blocks stackpointer returnaddress.
        riprel32_within_bounds kk (pc + 87) /\
        nonoverlapping (word pc,4465) (statep:int64,32) /\
        nonoverlapping (word pc,4465) (word_sub stackpointer (word 207):int64,215) /\
        nonoverlapping (word pc,4465) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (word pc,4465) (word kk:int64,608) /\
        nonoverlapping (statep:int64,32) (word_sub stackpointer (word 207):int64,215) /\
        nonoverlapping (statep:int64,32) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (statep:int64,32) (word kk:int64,608) /\
        nonoverlapping (word_sub stackpointer (word 207):int64,215) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (word_sub stackpointer (word 207):int64,215) (word kk:int64,608) /\
        0 < num_blocks /\
        val (dataptr:int64) + 64 * num_blocks < 2 EXP 64
        ==> ensures x86
            (\s. bytes_loaded s (word pc)
                   (sha256_compress_tmc pc kk) /\
                 read RIP s = word pc /\
                 bytes_loaded s (word kk) K256 /\
                 read RSP s = stackpointer /\
                 read (memory :> bytes64 stackpointer) s = returnaddress /\
                 C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
                 read events s = e)
            (\s. read RIP s = returnaddress /\
                 (exists e2.
                      read events s = APPEND e2 e /\
                      e2 = f_events dataptr statep num_blocks kk pc
                             (word_sub stackpointer (word 207)) returnaddress /\
                      memaccess_inbounds e2
                        [statep:int64,32; dataptr:int64,val (word num_blocks:int64) * 64;
                         word_sub stackpointer (word 207):int64,215; word kk:int64,608]
                        [statep:int64,32; word_sub stackpointer (word 207):int64,215]))
            (MAYCHANGE [RSP] ,,
             MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
             MAYCHANGE
             [memory :> bytes32 statep;
              memory :> bytes32 (word_add statep (word 4));
              memory :> bytes32 (word_add statep (word 8));
              memory :> bytes32 (word_add statep (word 12));
              memory :> bytes32 (word_add statep (word 16));
              memory :> bytes32 (word_add statep (word 20));
              memory :> bytes32 (word_add statep (word 24));
              memory :> bytes32 (word_add statep (word 28))] ,,
             MAYCHANGE [memory :> bytes (word_sub stackpointer (word 207),215)])`;;

let e_s11 = ref `e:(uarch_event)list`;;

let WRAPPER_PREFIX_P =
  REWRITE_TAC[fst SHA256_COMPRESS_EXEC] THEN
  REWRITE_TAC[MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI] THEN
  ASSUME_CALLEE_SAFETY_TAC SHA256_COMPRESS_SAFE "HCORE" THEN
  META_EXISTS_TAC THEN
  REWRITE_TAC[C_ARGUMENTS] THEN
  REPLICATE_TAC 6 GEN_TAC THEN
  WORD_FORALL_OFFSET_TAC 207 THEN
  REWRITE_TAC[K_BYTES_FORM] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_PRESERVED_TAC "rbx_init" `RBX` THEN
  ENSURES_PRESERVED_TAC "rbp_init" `RBP` THEN
  ENSURES_PRESERVED_TAC "r12_init" `R12` THEN
  ENSURES_PRESERVED_TAC "r13_init" `R13` THEN
  ENSURES_PRESERVED_TAC "r14_init" `R14` THEN
  ENSURES_PRESERVED_TAC "r15_init" `R15` THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_C8_TAC SHA256_COMPRESS_EXEC (1--11) THEN
  ABBREV_TAC
   `delta =
    val(word_sub (word 63)
                 (word_and (word_add stackpointer (word 63)) (word 63)):int64)` THEN
  SUBGOAL_THEN `delta <= 63` ASSUME_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `word_and (word_add stackpointer (word 63)) (word 18446744073709551552):int64 =
    word_add stackpointer (word delta)`
  SUBST_ALL_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `4 * val (word_shl (word num_blocks:int64) 4) = 64 * num_blocks`
  ASSUME_TAC THENL
   [REWRITE_TAC[VAL_WORD_SHL; VAL_WORD; DIMINDEX_64] THEN
    REWRITE_TAC[ARITH_RULE `2 EXP 4 = 16`] THEN
    SUBGOAL_THEN `num_blocks MOD 2 EXP 64 = num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 64 * n < 2 EXP 64 ==> n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    SUBGOAL_THEN `(16 * num_blocks) MOD 2 EXP 64 = 16 * num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 64 * n < 2 EXP 64 ==> 16 * n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    ARITH_TAC; ALL_TAC] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME
    `4 * val (word_shl (word num_blocks:int64) 4) = 64 * num_blocks`]) THEN
  W(fun (asl,w) ->
     let _,th = find (fun (_,th) ->
        let c = concl th in
        is_eq c && string_of_term(lhand c) = "read events s11") asl in
     e_s11 := rhs(concl th); ALL_TAC);;

let MP_CORE_SAFE =
  SUBGOAL_THEN
   `read (memory :> bytelist (word kk:int64,LENGTH K256)) s11 = K256`
  ASSUME_TAC THENL
   [REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K256] THEN ASM_REWRITE_TAC[]; ALL_TAC] THEN
  W(fun (asl,w) ->
    let _,hcore = find (fun (nm,_) -> nm="HCORE") asl in
    let specth = SPECL
      [ !e_s11; `pc:num`; `kk:num`;
        `word_add stackpointer (word delta):int64`;
        `statep:int64`; `dataptr:int64`;
        `word_add dataptr (word (64*num_blocks)):int64`;
        `word_add stackpointer (word 207):int64`;
        `num_blocks:num` ] hcore in
    MP_TAC (REWRITE_RULE[IMP_IMP] specth)) THEN
  ANTS_TAC THENL
   [REPEAT CONJ_TAC THEN
    (NONOVERLAPPING_TAC ORELSE ASM_REWRITE_TAC[]); ALL_TAC] THEN
  REWRITE_TAC[SOME_FLAGS] THEN
  X86_BIGSTEP_TAC SHA256_COMPRESS_EXEC "s12";;

let SHA256_COMPRESS_NOIBT_SUBROUTINE_SAFE = prove
 (sysv_safe_spec_215,
  WRAPPER_PREFIX_P THEN MP_CORE_SAFE THEN
  ABBREV_TAC `asp:int64 = word_add stackpointer (word delta)` THEN
  X86_STEPS_C8_TAC SHA256_COMPRESS_EXEC (13--21) THEN
  RULE_ASSUM_TAC(REWRITE_RULE[SYM(ASSUME
     `word_add stackpointer (word delta):int64 = asp`)]) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  SAFE_META_EXISTS_TAC allowed_vars_e THEN
  CONJ_TAC THENL [ EXISTS_E2_TAC allowed_vars_e; ALL_TAC ] THEN
  CONJ_TAC THENL [
    (* f_events conjunct: re-fold delta before unifying the metavar trace *)
    W(fun (asl,w) ->
       let _,dth = find (fun (_,th) ->
         let c = concl th in is_eq c && rhs c = `delta:num`) asl in
       REWRITE_TAC[SYM dth]) THEN FULL_UNIFY_F_EVENTS_TAC;
    (* inbounds conjunct: dataptr units fix, then discharge *)
    SUBGOAL_THEN `val (word num_blocks:int64) = num_blocks` ASSUME_TAC THENL
     [ MATCH_MP_TAC VAL_WORD_EQ THEN REWRITE_TAC[DIMINDEX_64] THEN
       MP_TAC(ASSUME `val (dataptr:int64) + 64 * num_blocks < 2 EXP 64`) THEN
       ARITH_TAC;
       ALL_TAC] THEN
    SUBGOAL_THEN `val (word num_blocks:int64) * 64 = 64 * num_blocks`
      (fun th -> REWRITE_TAC[th]) THENL
     [ ASM_REWRITE_TAC[] THEN ARITH_TAC; ALL_TAC] THEN
    DISCHARGE_MEMACCESS_INBOUNDS_TAC ]);;

(* SysV IBT subroutine SAFE: the +4 endbr64-prefixed `mc` form (pc+91, 4469),  *)
(* lifted from the NOIBT SAFE via ADD_IBT_RULE ~bridge:MC_BRIDGE.               *)
let SHA256_COMPRESS_SUBROUTINE_SAFE = prove(`
   exists f_events.
    forall e pc kk statep dataptr num_blocks stackpointer returnaddress.
        riprel32_within_bounds kk (pc + 91) /\
        nonoverlapping (word pc,4469) (statep:int64,32) /\
        nonoverlapping (word pc,4469) (word_sub stackpointer (word 207):int64,215) /\
        nonoverlapping (word pc,4469) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (word pc,4469) (word kk:int64,608) /\
        nonoverlapping (statep:int64,32) (word_sub stackpointer (word 207):int64,215) /\
        nonoverlapping (statep:int64,32) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (statep:int64,32) (word kk:int64,608) /\
        nonoverlapping (word_sub stackpointer (word 207):int64,215) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (word_sub stackpointer (word 207):int64,215) (word kk:int64,608) /\
        0 < num_blocks /\
        val (dataptr:int64) + 64 * num_blocks < 2 EXP 64
        ==> ensures x86
            (\s. bytes_loaded s (word pc)
                   (sha256_compress_mc pc kk) /\
                 read RIP s = word pc /\
                 bytes_loaded s (word kk) K256 /\
                 read RSP s = stackpointer /\
                 read (memory :> bytes64 stackpointer) s = returnaddress /\
                 C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
                 read events s = e)
            (\s. read RIP s = returnaddress /\
                 (exists e2.
                      read events s = APPEND e2 e /\
                      e2 = f_events dataptr statep num_blocks kk pc
                             (word_sub stackpointer (word 207)) returnaddress /\
                      memaccess_inbounds e2
                        [statep:int64,32; dataptr:int64,val (word num_blocks:int64) * 64;
                         word_sub stackpointer (word 207):int64,215; word kk:int64,608]
                        [statep:int64,32; word_sub stackpointer (word 207):int64,215]))
            (MAYCHANGE [RSP] ,,
             MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
             MAYCHANGE
             [memory :> bytes32 statep;
              memory :> bytes32 (word_add statep (word 4));
              memory :> bytes32 (word_add statep (word 8));
              memory :> bytes32 (word_add statep (word 12));
              memory :> bytes32 (word_add statep (word 16));
              memory :> bytes32 (word_add statep (word 20));
              memory :> bytes32 (word_add statep (word 24));
              memory :> bytes32 (word_add statep (word 28))] ,,
             MAYCHANGE [memory :> bytes (word_sub stackpointer (word 207),215)])`,
  MATCH_ACCEPT_TAC(ADD_IBT_RULE
    ~bridge:(Some SHA256_COMPRESS_MC_BRIDGE)
    SHA256_COMPRESS_NOIBT_SUBROUTINE_SAFE));;

(* ========================================================================= *)
(* Phase 14 — Windows subroutine SAFE wrappers (the last 2 of 4).            *)
(*                                                                           *)
(* Mirror the Windows CORRECT wrapper (L11829) but MP the bl-core SAFE       *)
(* SHA256_COMPRESS_BL_SAFE (the Windows image loads only        *)
(* bl_tmc = BUTLAST sysv_tmc — the SysV `ret` byte is dropped, session-040 — *)
(* so the SAFE wrapper MPs a bl_tmc SAFE, not the primary tmc core SAFE).    *)
(* Structure: 16-instr Windows prologue (endbr + 2 pushes rdi/rsi + 3 ABI    *)
(* moves + SysV prologue) X86_STEPS_C8 (1--16); capture RA + event trace at  *)
(* s16; dynamic-alignment delta keyed +71 (2 extra Windows pushes vs SysV    *)
(* +63), BITBLAST; bridge windows_tmc->bl_tmc bytes_loaded at pc+11 via      *)
(* SHA256_WIN_BODY_BRIDGE; MP the bl-core SAFE's 9 foralls with origsp :=     *)
(* sp+215 (the non-pop epilogue recovers caller-SP from slot88) and the      *)
(* (pc+11)+N offsets reduced to pc+40/pc+4443/pc+98; BIGSTEP with the WINDOWS *)
(* exec; re-derive RA at the ret slot sp+231; non-pop epilogue X86_STEPS_C8  *)
(* (18--28); then the SAFE discharge tail (SAFE_META_EXISTS / EXISTS_E2 /     *)
(* FULL_UNIFY_F_EVENTS / DISCHARGE_MEMACCESS_INBOUNDS).  The frame is 231/239 *)
(* (231-byte local frame + 8-byte RA slot the `and` exposes at sp+231..239,   *)
(* so the data<->frame nonoverlap hyps are widened to 239 to carry the RA     *)
(* fact across the bl-core BIGSTEP).  As with the SysV SAFE wrapper, the      *)
(* spec is the mk_safety_spec output for the 239-frame Windows SUBROUTINE_    *)
(* CORRECT (fed as a literal: mk_safety_spec needs subroutine_signatures,     *)
(* not loaded here).  The :int64 on `word num_blocks` in the POST inbounds    *)
(* READ entry is EXPLICIT (session-053: the pretty-printer hides it, leaving  *)
(* a type metavar that blocks DISCHARGE_MEMACCESS_INBOUNDS_TAC).             *)
(* ========================================================================= *)

let win_safe_spec_239 = `
   exists f_events.
    forall e pc kk statep dataptr num_blocks stackpointer returnaddress.
        riprel32_within_bounds kk (pc + 98) /\
        nonoverlapping (word pc,4478) (statep:int64,32) /\
        nonoverlapping (word pc,4478) (word_sub stackpointer (word 231):int64,239) /\
        nonoverlapping (word pc,4478) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (word pc,4478) (word kk:int64,608) /\
        nonoverlapping (statep:int64,32) (word_sub stackpointer (word 231):int64,239) /\
        nonoverlapping (statep:int64,32) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (statep:int64,32) (word kk:int64,608) /\
        nonoverlapping (word_sub stackpointer (word 231):int64,239) (dataptr:int64,64 * num_blocks) /\
        nonoverlapping (word_sub stackpointer (word 231):int64,239) (word kk:int64,608) /\
        0 < num_blocks /\
        val (dataptr:int64) + 64 * num_blocks < 2 EXP 64
        ==> ensures x86
            (\s. bytes_loaded s (word pc)
                   (sha256_compress_windows_tmc pc kk) /\
                 read RIP s = word pc /\
                 bytes_loaded s (word kk) K256 /\
                 read RSP s = stackpointer /\
                 read (memory :> bytes64 stackpointer) s = returnaddress /\
                 WINDOWS_C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
                 read events s = e)
            (\s. read RIP s = returnaddress /\
                 (exists e2.
                      read events s = APPEND e2 e /\
                      e2 = f_events dataptr statep num_blocks kk pc
                             (word_sub stackpointer (word 231)) returnaddress /\
                      memaccess_inbounds e2
                        [statep:int64,32; dataptr:int64,val (word num_blocks:int64) * 64;
                         word_sub stackpointer (word 231):int64,239; word kk:int64,608]
                        [statep:int64,32; word_sub stackpointer (word 231):int64,239]))
            (MAYCHANGE [RSP] ,,
             WINDOWS_MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
             MAYCHANGE
             [memory :> bytes32 statep;
              memory :> bytes32 (word_add statep (word 4));
              memory :> bytes32 (word_add statep (word 8));
              memory :> bytes32 (word_add statep (word 12));
              memory :> bytes32 (word_add statep (word 16));
              memory :> bytes32 (word_add statep (word 20));
              memory :> bytes32 (word_add statep (word 24));
              memory :> bytes32 (word_add statep (word 28))] ,,
             MAYCHANGE [memory :> bytes (word_sub stackpointer (word 231),231)])`;;

(* refs for the captured event trace + RA fact (Windows SAFE wrapper) *)
let e_s16 = ref `e:(uarch_event)list`;;
let ra_fact_ws = ref TRUTH;;

let SHA256_COMPRESS_NOIBT_WINDOWS_SUBROUTINE_SAFE = prove
 (win_safe_spec_239,
  REWRITE_TAC[fst SHA256_WIN_EXEC] THEN
  REWRITE_TAC[WINDOWS_MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI] THEN
  ASSUME_CALLEE_SAFETY_TAC SHA256_COMPRESS_BL_SAFE "HCORE" THEN
  META_EXISTS_TAC THEN
  REWRITE_TAC[WINDOWS_C_ARGUMENTS] THEN
  REPLICATE_TAC 6 GEN_TAC THEN
  WORD_FORALL_OFFSET_TAC 231 THEN
  REWRITE_TAC[K_BYTES_FORM] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_PRESERVED_TAC "rdi_init" `RDI` THEN
  ENSURES_PRESERVED_TAC "rsi_init" `RSI` THEN
  ENSURES_PRESERVED_TAC "rbx_init" `RBX` THEN
  ENSURES_PRESERVED_TAC "rbp_init" `RBP` THEN
  ENSURES_PRESERVED_TAC "r12_init" `R12` THEN
  ENSURES_PRESERVED_TAC "r13_init" `R13` THEN
  ENSURES_PRESERVED_TAC "r14_init" `R14` THEN
  ENSURES_PRESERVED_TAC "r15_init" `R15` THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_C8_TAC SHA256_WIN_EXEC (1--16) THEN
  (* capture RA fact at s16 (prologue end, pre-BIGSTEP). Deferred deref later. *)
  W(fun (asl,w) ->
     let isra (_,th) =
       let c = concl th in
       (try let _ = find_term (fun t -> try fst(dest_var t)="returnaddress"
                                        with _->false) c in is_eq c
        with _->false) in
     ra_fact_ws := snd (List.find isra asl); ALL_TAC) THEN
  (* DELTA — Windows +71 word-subtraction form (BITBLAST-friendly). *)
  ABBREV_TAC
   `delta =
    val(word_sub (word 71)
                 (word_and (word_add stackpointer (word 71)) (word 63)):int64)` THEN
  SUBGOAL_THEN `delta <= 71` ASSUME_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `word_and (word_add stackpointer (word 71)) (word 18446744073709551552):int64 =
    word_add stackpointer (word delta)`
  SUBST_ALL_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `4 * val (word_shl (word num_blocks:int64) 4) = 64 * num_blocks`
  ASSUME_TAC THENL
   [REWRITE_TAC[VAL_WORD_SHL; VAL_WORD; DIMINDEX_64] THEN
    REWRITE_TAC[ARITH_RULE `2 EXP 4 = 16`] THEN
    SUBGOAL_THEN `num_blocks MOD 2 EXP 64 = num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 64 * n < 2 EXP 64 ==> n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    SUBGOAL_THEN `(16 * num_blocks) MOD 2 EXP 64 = 16 * num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 64 * n < 2 EXP 64 ==> 16 * n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    ARITH_TAC; ALL_TAC] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME
    `4 * val (word_shl (word num_blocks:int64) 4) = 64 * num_blocks`]) THEN
  (* capture the event trace at s16 (prologue end, pre-BIGSTEP). *)
  W(fun (asl,w) ->
     let _,th = find (fun (_,th) ->
        let c = concl th in
        is_eq c && string_of_term(lhand c) = "read events s16") asl in
     e_s16 := rhs(concl th); ALL_TAC) THEN
  (* re-derive the bl-core's bytelist K demand at s16. *)
  SUBGOAL_THEN
   `read (memory :> bytelist (word kk:int64,LENGTH K256)) s16 = K256`
  ASSUME_TAC THENL
   [REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K256] THEN ASM_REWRITE_TAC[]; ALL_TAC] THEN
  (* bridge windows_tmc bytes_loaded -> bl_tmc bytes_loaded at pc+11 (for the MP). *)
  SUBGOAL_THEN
   `bytes_loaded s16 (word (pc + 11))
       (sha256_compress_bl_tmc (pc + 11) kk)`
  ASSUME_TAC THENL
   [REWRITE_TAC[sha256_compress_bl_tmc] THEN
    MATCH_MP_TAC SHA256_WIN_BODY_BRIDGE THEN ASM_REWRITE_TAC[]; ALL_TAC] THEN
  (* MP the bl-core SAFE, reducing the (pc+11)+N offsets.  SPECL its 9 foralls
     [e; pc; kk; sp; statep; dataptr; endp; origsp; num_blocks] with the
     captured trace e_s16, the dynamic delta SP, and origsp := sp+215. *)
  W(fun (asl,w) ->
    let _,hcore = find (fun (nm,_) -> nm="HCORE") asl in
    let specth = SPECL
      [ !e_s16; `pc + 11`; `kk:num`;
        `word_add stackpointer (word delta):int64`;
        `statep:int64`; `dataptr:int64`;
        `word_add dataptr (word (64*num_blocks)):int64`;
        `word_add stackpointer (word 215):int64`;
        `num_blocks:num` ] hcore in
    MP_TAC (REWRITE_RULE[ARITH_RULE `(pc + 11) + 29 = pc + 40`;
                         ARITH_RULE `(pc + 11) + 4432 = pc + 4443`;
                         ARITH_RULE `(pc + 11) + 87 = pc + 98`; IMP_IMP] specth)) THEN
  ANTS_TAC THENL
   [REPEAT CONJ_TAC THEN
    (NONOVERLAPPING_TAC ORELSE ASM_REWRITE_TAC[]); ALL_TAC] THEN
  REWRITE_TAC[SOME_FLAGS] THEN
  X86_BIGSTEP_TAC SHA256_WIN_EXEC "s17" THEN
  ABBREV_TAC `asp:int64 = word_add stackpointer (word delta)` THEN
  (* re-derive RA at s17 (ret slot = stackpointer+231). With the 239 hyp the
     RA-slot _|_ statep is provable, so ASSUMPTION_STATE_UPDATE_TAC carries
     the RA fact across the bl-core frame. *)
  SUBGOAL_THEN
   `read (memory :> bytes64 (word_add stackpointer (word 231))) s17 = returnaddress`
  ASSUME_TAC THENL
   [W(fun (asl,w) -> ASSUME_TAC(!ra_fact_ws)) THEN
    FIRST_X_ASSUM(MP_TAC o check (maychange_term o concl)) THEN
    REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
    REWRITE_TAC[GSYM SEQ_ASSOC] THEN
    PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
    CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
    REWRITE_TAC[ASSIGNS_THM] THEN
    REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
    ASSUMPTION_STATE_UPDATE_TAC THEN
    DISCH_THEN(K ALL_TAC) THEN
    ASM_REWRITE_TAC[]; ALL_TAC] THEN
  X86_STEPS_C8_TAC SHA256_WIN_EXEC (18--28) THEN
  RULE_ASSUM_TAC(REWRITE_RULE[SYM(ASSUME
     `word_add stackpointer (word delta):int64 = asp`)]) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  SAFE_META_EXISTS_TAC allowed_vars_e THEN
  CONJ_TAC THENL [ EXISTS_E2_TAC allowed_vars_e; ALL_TAC ] THEN
  CONJ_TAC THENL [
    (* f_events conjunct: re-fold delta before unifying the metavar trace *)
    W(fun (asl,w) ->
       let _,dth = find (fun (_,th) ->
         let c = concl th in is_eq c && rhs c = `delta:num`) asl in
       REWRITE_TAC[SYM dth]) THEN FULL_UNIFY_F_EVENTS_TAC;
    (* inbounds conjunct: dataptr units fix, then discharge *)
    SUBGOAL_THEN `val (word num_blocks:int64) = num_blocks` ASSUME_TAC THENL
     [ MATCH_MP_TAC VAL_WORD_EQ THEN REWRITE_TAC[DIMINDEX_64] THEN
       MP_TAC(ASSUME `val (dataptr:int64) + 64 * num_blocks < 2 EXP 64`) THEN
       ARITH_TAC;
       ALL_TAC] THEN
    SUBGOAL_THEN `val (word num_blocks:int64) * 64 = 64 * num_blocks`
      (fun th -> REWRITE_TAC[th]) THENL
     [ ASM_REWRITE_TAC[] THEN ARITH_TAC; ALL_TAC] THEN
    DISCHARGE_MEMACCESS_INBOUNDS_TAC ]);;

(* Windows IBT subroutine SAFE: the +4 endbr64-prefixed windows_mc form        *)
(* (pc+102, 4482), lifted from the NOIBT SAFE via ADD_IBT_RULE                  *)
(* ~bridge:WINDOWS_MC_BRIDGE.  The spec is the NOIBT spec with the three        *)
(* IBT deltas: windows_tmc->windows_mc, 4478->4482, riprel pc+98->pc+102.       *)
let win_safe_ibt_spec_239 =
  subst [`sha256_compress_windows_mc`,
         `sha256_compress_windows_tmc`;
         `4482`,`4478`;
         `102`,`98`] win_safe_spec_239;;

let SHA256_COMPRESS_WINDOWS_SUBROUTINE_SAFE = prove
 (win_safe_ibt_spec_239,
  MATCH_ACCEPT_TAC(ADD_IBT_RULE
    ~bridge:(Some SHA256_COMPRESS_WINDOWS_MC_BRIDGE)
    SHA256_COMPRESS_NOIBT_WINDOWS_SUBROUTINE_SAFE));;
